-- Poems batch 123
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f958ab78-391c-4b65-b7b9-e4b4a19227aa','秋雨','陸游','宋','宋诗','song-poetry','','[]','雨聲疏復密，窗影暗還明。',48,'全唐诗/poet.song.133000.json','["雨聲疏復密，窗影暗還明。", "赤米香炊飯，青蔬淡煮羹。", "閑中長棋格，病後減詩情。", "惟有桑麻事，鄰翁與細評。"]'),
('e7279070-016b-4ede-b091-1884377e93e2','雨後凉甚','陸游','宋','宋诗','song-poetry','','[]','並海寬閑野，清秋摇落天。',48,'全唐诗/poet.song.133000.json','["並海寬閑野，清秋摇落天。", "微凉供美睡，穩字入新聯。", "陋屋蕭蕭雨，修筒細細泉。", "晚窗生酒興，洗酌一陶然。"]'),
('372de889-624c-440b-9917-3c870c67fbf5','屏迹二首  其一','陸游','宋','宋诗','song-poetry','','[]','屏迹亂山中，觀身槁木同。',48,'全唐诗/poet.song.133000.json','["屏迹亂山中，觀身槁木同。", "桑麻安舊業，薪水付村童。", "不散嬰兒樸，常存太古風。", "一錢無用處，那復計囊空。"]'),
('01b7a67b-2357-4000-a9a5-c588c7a6769c','屏迹二首  其二','陸游','宋','宋诗','song-poetry','','[]','飯熟起開鉢，困來徐倒床。',48,'全唐诗/poet.song.133000.json','["飯熟起開鉢，困來徐倒床。", "無狂安取聖，有短始知長。", "養道褐懷玉，露才錐出囊。", "聊須喚兒稚，細細話耕桑。"]'),
('ae6b5896-ca7c-4f88-b759-5b6313c058a8','書事四首  其一','陸游','宋','宋诗','song-poetry','','[]','聞道輿圖次第還，黄河依舊抱潼關。',32,'全唐诗/poet.song.134000.json','["聞道輿圖次第還，黄河依舊抱潼關。", "會當小駐平戎帳，饒益南亭看華山。"]'),
('adde8866-1596-40a5-983a-ef32aae6a84e','書事四首  其二','陸游','宋','宋诗','song-poetry','','[]','關中父老望王師，想見壺漿滿路時。',32,'全唐诗/poet.song.134000.json','["關中父老望王師，想見壺漿滿路時。", "寂寞西溪衰草裏，斷碑猶有少陵詩。"]'),
('601cf8aa-8fee-42d4-a0b1-a62f451dc11f','書事四首  其三','陸游','宋','宋诗','song-poetry','','[]','鴨綠桑乾盡漢天，傳烽自合過祁連。',32,'全唐诗/poet.song.134000.json','["鴨綠桑乾盡漢天，傳烽自合過祁連。", "功名在子何殊我，惟恨無人快著鞭。"]'),
('03b461c3-261f-4a26-8e7f-e2020d2be682','書事四首  其四','陸游','宋','宋诗','song-poetry','','[]','九天清蹕響春雷，百萬貔貅扈駕回。',32,'全唐诗/poet.song.134000.json','["九天清蹕響春雷，百萬貔貅扈駕回。", "不獨雨師先灑道，汴流滾滾入淮來。"]'),
('a61a8ffc-ce49-40e1-b903-30db3eaba4ff','雨後','陸游','宋','宋诗','song-poetry','','[]','雨後凉生病體輕，閑拖拄杖出門行。',32,'全唐诗/poet.song.134000.json','["雨後凉生病體輕，閑拖拄杖出門行。", "槐花落盡桐陰薄，時有殘蟬一兩聲。"]'),
('d938079e-a4f0-4f65-9203-62724311d1f5','幽居','陸游','宋','宋诗','song-poetry','','[]','早歲猶奇怪，中年痛掃除。',48,'全唐诗/poet.song.134000.json','["早歲猶奇怪，中年痛掃除。", "華堂棋陸廢，名馬宴遊疏。", "散帙身忘倦，畦蔬手自鉏。", "寥寥千載後，誰此訪幽居。"]'),
('3c3e1b4d-1036-4b8c-8c82-ec6d8ac44af4','書事','陸游','宋','宋诗','song-poetry','','[]','北征談笑取關河，盟府何人策戰多。',64,'全唐诗/poet.song.134000.json','["北征談笑取關河，盟府何人策戰多。", "掃盡烟塵歸鐵馬，剪空荆棘出銅駝。", "史臣歷紀平戎策，壯士遥傳入塞歌。", "自笑書生無寸效，十年枉是枕琱戈。"]'),
('c91c0c24-a3dc-41f1-b75c-904f51366003','秋夜感遇十首以孤村一犬吠殘月幾人行爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','月生東山口，宿鳥驚相呼。',48,'全唐诗/poet.song.134000.json','["月生東山口，宿鳥驚相呼。", "我起立蒼茫，怳在白玉壺。", "饑鶻掠危巢，大魚躍平湖。", "作意賦新詩，佳夕不可孤。"]'),
('3b52f8c4-ca3d-4642-b926-ee4277d02beb','秋夜感遇十首以孤村一犬吠殘月幾人行爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','今日天氣佳，駕言適山村。',48,'全唐诗/poet.song.134000.json','["今日天氣佳，駕言適山村。", "種枳作短籬，疊石成高垣。", "牲酒賽秋社，簫鼓迎新婚。", "所願在仕者，努力蘇元元。"]'),
('b1c482ba-b2a3-4c56-85c7-a69f26f38788','秋夜感遇十首以孤村一犬吠殘月幾人行爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','長康有三絕，吾獨得其一。',48,'全唐诗/poet.song.134000.json','["長康有三絕，吾獨得其一。", "寓世八十年，一癡萬事畢。", "世間所謂黠，正類褌中虱。", "燂湯會有時，爲計誰得失。"]'),
('da6a3c26-47b4-4f65-b055-d0dac1eca52b','秋夜感遇十首以孤村一犬吠殘月幾人行爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','我夢遊異境，烏帽跨小蹇。',48,'全唐诗/poet.song.134000.json','["我夢遊異境，烏帽跨小蹇。", "桑麻夾阡陌，山川曠何遠。", "俗有太古風，蕭散到雞犬。", "鐘鳴忽驚覺，所造恨猶淺。"]'),
('f56100ae-f949-47f1-95ff-96ffbcf8bb27','秋夜感遇十首以孤村一犬吠殘月幾人行爲韵  其五','陸游','宋','宋诗','song-poetry','','[]','竭作朝筑陂，獨勞暮鉏菜。',48,'全唐诗/poet.song.134000.json','["竭作朝筑陂，獨勞暮鉏菜。", "草烟欄犢卧，船響籬犬吠。", "殘年迫耄及，農事不敢廢。", "兒曹强學餘，努力事舂磑。"]'),
('862d6b7b-43fa-4c2f-bf81-233771bddf12','秋夜感遇十首以孤村一犬吠殘月幾人行爲韵  其六','陸游','宋','宋诗','song-poetry','','[]','頒曆如昨日，俯仰芳歲殘。',48,'全唐诗/poet.song.134000.json','["頒曆如昨日，俯仰芳歲殘。", "蜩蚻方鳴秋，碪杵已戒寒。", "書生賦予薄，何適不艱難。", "粱肉固所美，食淡心始安。"]'),
('15bcd0cb-3ae7-4baf-91ea-dd19944d644d','秋夜感遇十首以孤村一犬吠殘月幾人行爲韵  其七','陸游','宋','宋诗','song-poetry','','[]','前年蒙趣召，渡江當六月。',48,'全唐诗/poet.song.134000.json','["前年蒙趣召，渡江當六月。", "顧慚衰病軀，觸熱朝行闕。", "君恩雖屢下，恐懼乞骸骨。", "飄然返柴荆，所愧已黔突。"]'),
('9b72f0ee-f077-4761-a439-6fe67cea6310','秋夜感遇十首以孤村一犬吠殘月幾人行爲韵  其八','陸游','宋','宋诗','song-poetry','','[]','畏首復畏尾，吾身其餘幾。',48,'全唐诗/poet.song.134000.json','["畏首復畏尾，吾身其餘幾。", "雖云食不足，健决豈不偉。", "蓬窗對親舊，情話來亹亹。", "何以永今朝，沽酒刺圈豨。"]'),
('c957ab19-3b5b-47ff-958c-49d2d76beced','秋夜感遇十首以孤村一犬吠殘月幾人行爲韵  其九','陸游','宋','宋诗','song-poetry','','[]','昔遇高皇帝，同朝多偉人。',48,'全唐诗/poet.song.134000.json','["昔遇高皇帝，同朝多偉人。", "哀哉逝不留，焄蒿返蒼旻。", "存者纔一二，相望不得親。", "秋風聞雁過，老泪霑衣巾。"]'),
('4768424c-c0e2-4cb4-8608-ea7d4b5dbe77','秋夜感遇十首以孤村一犬吠殘月幾人行爲韵  其一○','陸游','宋','宋诗','song-poetry','','[]','唐虞治巍巍，洙泗道益明。',48,'全唐诗/poet.song.134000.json','["唐虞治巍巍，洙泗道益明。", "豈知秦漢後，佛老起縱橫。", "詩書雖僅存，韶頀無遺聲。", "書生幸有聞，未死猶力行。"]'),
('ad7f82f5-e06b-49c3-bb64-7cfce81cdc81','草書歌','陸游','宋','宋诗','song-poetry','','[]','吾廬宛在水中沚，車馬喧囂那到耳。',128,'全唐诗/poet.song.134000.json','["吾廬宛在水中沚，車馬喧囂那到耳。", "一堂翛然卧虛曠，蟬聲未斷蟲聲起。", "有時寓意筆硯間，跌宕奔騰作詼詭。", "徂徠松盡玉池墨，雲夢澤乾蟾滴水。", "心空萬象提寸毫，睥睨醉僧窺長史。", "聯翩昏鴉斜著壁，鬰屈瘦蛟蟠入紙。", "神馳意造起雷雨，坐覺乾坤真一洗。", "小兒勸我當自珍，勿爲門生書棐几。"]'),
('fa9b3489-8c5b-4c74-93de-1db425fb4cc7','自儆','陸游','宋','宋诗','song-poetry','','[]','牛解謹藏刀，羊亡密補牢。',48,'全唐诗/poet.song.134000.json','["牛解謹藏刀，羊亡密補牢。", "達人憂祿厚，奇禍出名高。", "所要懷全壁，寧當耻縕袍。", "世間俱癬疥，何事苦爬搔。"]'),
('7bc7837a-f0b9-4a1f-a4fa-7a4e4c7ef21c','新秋二首  其一','陸游','宋','宋诗','song-poetry','','[]','遠浦平郊弄夕霏，曲籬幽徑鎖秋暉。',64,'全唐诗/poet.song.134000.json','["遠浦平郊弄夕霏，曲籬幽徑鎖秋暉。", "馴麞巧占蒼苔卧，驚鵲斜穿密篠飛。", "浴罷小軒成美睡，雨餘老火斂餘威。", "未言風月供詩思，汗幘塵衣且解圍。"]'),
('b9f7c13b-163d-4ce6-8e35-494cacd3c623','新秋二首  其二','陸游','宋','宋诗','song-poetry','','[]','蟬聲滿院送流年，又見秋風到海邊。',64,'全唐诗/poet.song.134000.json','["蟬聲滿院送流年，又見秋風到海邊。", "舊友死來頻入夢，新詩愁絕少成篇。", "步頭野水雙飛鷺，林外人家一點烟。", "顧影自驚如許瘦，囊空無藥起沉綿。"]'),
('2fe558f7-ca9c-454a-89d3-205b7c428574','憫俗','陸游','宋','宋诗','song-poetry','','[]','蚩蚩之氓不自覺，顧笑吾曹安淡薄。',96,'全唐诗/poet.song.134000.json','["蚩蚩之氓不自覺，顧笑吾曹安淡薄。", "携女數千行問法，腰錢鉅萬仍騎鶴。", "豈知此事不兩得，芻豢何可參毒藥。", "野狐出林作百態，擊下髑髏渠自怍。", "老氏五千本清靜，揚雄太玄惟寂寞。", "但能於此尊所聞，萬卷丹經盡糟粕。"]'),
('11592a47-aab4-47c5-ba93-38c1474f77e5','塊坐齋中有感','陸游','宋','宋诗','song-poetry','','[]','敗席凝塵懶拂除，况能作意去庭蕪。',64,'全唐诗/poet.song.134000.json','["敗席凝塵懶拂除，况能作意去庭蕪。", "讀書眼力衰難强，對酒心情薄欲無。", "野寺鍾魚思下擔，山郵鞍馱憶登途。", "頹然坐睡誰驚覺，寂寞西窗日又晡。"]'),
('370140d7-d5f5-4f31-adf1-477ada192700','新凉示子遹時子遹將有臨安之行','陸游','宋','宋诗','song-poetry','','[]','竹簟紗幮事已非，秋清初換熟縑衣。',64,'全唐诗/poet.song.134000.json','["竹簟紗幮事已非，秋清初換熟縑衣。", "鵲驚山月栖還起，螢避溪風墮又飛。", "老眼漸昏書懶讀，壯心雖在事多違。", "夜窗剩欲挑燈語，日倚柴門望汝歸。"]'),
('43bf6b61-a33b-46e3-9e36-96e4c683271b','秋雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','毒熱秋未衰，吾廬况淺迫。',48,'全唐诗/poet.song.134000.json','["毒熱秋未衰，吾廬况淺迫。", "雖云日一浴，流汗沾衣幘。", "蕭蕭三日雨，出此炮烙厄。", "瀟湘應更佳，恨我無六翮。"]'),
('903f8556-a929-477d-a6b7-c786e9733564','秋雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','吾廬多美蔭，最茂楸與梧。',48,'全唐诗/poet.song.134000.json','["吾廬多美蔭，最茂楸與梧。", "百鳥集其間，下上更鳴呼。", "秋風忽動地，摇落日日疏。", "何如澗底松，終歲無榮枯。"]'),
('3440eb09-9f60-4514-b0bc-0b8aa0146da1','講學','陸游','宋','宋诗','song-poetry','','[]','遷善以美身，講學以盡性。',48,'全唐诗/poet.song.134000.json','["遷善以美身，講學以盡性。", "能爲可行爾，用舍固有命。", "天方斲斯文，魯叟虛歷聘。", "黎元則可哀，窮死吾何病。"]'),
('91f2a856-92f9-45ba-9047-c11fdc3ec8ee','野興四首  其一','陸游','宋','宋诗','song-poetry','','[]','來日無多去日遒，朱顔那肯爲人留。',64,'全唐诗/poet.song.134000.json','["來日無多去日遒，朱顔那肯爲人留。", "簷聲點滴無時雨，野氣蒼茫極目秋。", "朝出釣魚來北渚，夜耕驅犢上西疇。", "此心所要常無愧，寂寞衡門死即休。"]'),
('99d12fe0-4f04-4ed8-8d72-7a76011f3d89','野興四首  其二','陸游','宋','宋诗','song-poetry','','[]','江湖蕭散葛天民，敕放還山一幅巾。',64,'全唐诗/poet.song.134000.json','["江湖蕭散葛天民，敕放還山一幅巾。", "老去饑羸惟恃粥，病來舉動每須人。", "道窮舉世知心少，學進吾兒著語親。", "更有一端差自慰，短檠不作白頭新。"]'),
('677d81b9-d4d2-49c8-8a8f-9ae7bb0a06af','野興四首  其三','陸游','宋','宋诗','song-poetry','','[]','早見高皇宇宙新，耄年猶作太平民。',64,'全唐诗/poet.song.134000.json','["早見高皇宇宙新，耄年猶作太平民。", "虛名僅可欺橫目，戇論曾經犯逆鱗。", "原野暮雲低欲雨，陂湖秋水浩無津。", "蕭條生計君無笑，一鉢藜羹敵八珍。"]'),
('2c175167-acbf-4a9c-b1d3-f65364162f7b','野興四首  其四','陸游','宋','宋诗','song-poetry','','[]','飽見人間行路難，暫陪鵷鷺意先闌。',64,'全唐诗/poet.song.134000.json','["飽見人間行路難，暫陪鵷鷺意先闌。", "集仙院裏三題石，神武門前兩挂冠。", "饑卧了無千里志，倦飛元怯九霄寒。", "客來莫笑蓬窗陋，若比巢居已太寬。"]'),
('e14d604d-d901-4a9e-99a8-05b5434af546','示元敏','陸游','宋','宋诗','song-poetry','','[]','學問參千古，工夫始一經。',48,'全唐诗/poet.song.134000.json','["學問參千古，工夫始一經。", "寧論綬若若，且喜佩青青。", "汝業方當進，吾言要細聽。", "仍須知稼穡，勉爲國添丁。"]'),
('98bc9bb4-5d2e-4ee6-920f-39850b3f6e65','八月四日夜夢中作','陸游','宋','宋诗','song-poetry','','[]','太華巉巉敷水長，白驢依舊繫斜陽。',64,'全唐诗/poet.song.134000.json','["太華巉巉敷水長，白驢依舊繫斜陽。", "山深乳洞藥爐冷，花發雲房醅甕香。", "鄰叟一樽迎谷口，蠻童三髻拜溪傍。", "中原俯仰成今古，物外自閑人自忙。"]'),
('a288a5cb-a9d7-4a39-a3e1-987b7c711f55','明日復理夢中意作','陸游','宋','宋诗','song-poetry','','[]','白盡髭鬚兩頰紅，頹然自以放名翁。',64,'全唐诗/poet.song.134000.json','["白盡髭鬚兩頰紅，頹然自以放名翁。", "客從謝事歸時散，詩到無人愛處工。", "高挂蒲帆上黄鶴，獨吹銅笛過垂虹。", "閑人浪迹由來事，那計猿驚蕙帳空。"]'),
('5efea70e-b154-44aa-8b3c-e88287672a31','又明日復作長句自規','陸游','宋','宋诗','song-poetry','','[]','大學淵源不易窮，古人立志自童蒙。',64,'全唐诗/poet.song.134000.json','["大學淵源不易窮，古人立志自童蒙。", "醉猶溫克方成德，夢亦齋莊始見功。", "痛哭孰能悲陷溺，力行猶足變雕蟲。", "太空雲翳終當散，吾道常如日正中。"]'),
('af6d3bb8-0c5f-4b46-8be3-471120302e40','示子孫','陸游','宋','宋诗','song-poetry','','[]','累葉爲儒業不隳，定知賢傑有生時。',64,'全唐诗/poet.song.134000.json','["累葉爲儒業不隳，定知賢傑有生時。", "學須造次常於是，道豈須臾或可離。", "我老已無明日計，心存猶惜寸陰移。", "巍巍夫子雖天縱，禮樂官名盡有師。"]'),
('3cd33612-fa5e-4bba-9b4e-bfcb8b0fde7c','秋夕','陸游','宋','宋诗','song-poetry','','[]','承學雖云淺，初心敢自輕。',48,'全唐诗/poet.song.134000.json','["承學雖云淺，初心敢自輕。", "飄零爲祿仕，蹭蹬得詩名。", "撫事悲長劍，懷人感短檠。", "不堪秋雨夕，鼓角下高城。"]'),
('b847a414-9009-4233-ab1e-bf017b2a052e','徂歲','陸游','宋','宋诗','song-poetry','','[]','徂歲風烟慘，幽居市井遥。',48,'全唐诗/poet.song.134000.json','["徂歲風烟慘，幽居市井遥。", "甑香炊薏米，泉潔煮芎苗。", "野廟迎神晚，村船過埭囂。", "西窗一樽酒，亦足慰無聊。"]'),
('dd001ff8-7d5f-4e4c-9d9e-10bf44a7f011','村居遣興三首  其一','陸游','宋','宋诗','song-poetry','','[]','追數交朋略散亡，臂孱足蹇固其常。',64,'全唐诗/poet.song.134000.json','["追數交朋略散亡，臂孱足蹇固其常。", "一年又見秋風至，孤夢潜隨夜漏長。", "不辦誦書如倚相，頗能噉飯勝張蒼。", "回看薄宦成何味，只借朝衫作戲場。"]'),
('1459c8ec-7d72-4fa2-ba0e-18f721b2941c','村居遣興三首  其二','陸游','宋','宋诗','song-poetry','','[]','萬里征途興已闌，三間破屋住猶寬。',64,'全唐诗/poet.song.134000.json','["萬里征途興已闌，三間破屋住猶寬。", "山薑著雨房重斂，南燭先霜實半丹。", "野市秋陰更蕭瑟，書生老瘦轉酸寒。", "掩關也有消愁處，一卷騷經醉後看。"]'),
('2fd945db-b74e-483f-aca8-7fecb1ff35b8','村居遣興三首  其三','陸游','宋','宋诗','song-poetry','','[]','野堂疏豁近江皋，喜見南山秋氣高。',64,'全唐诗/poet.song.134000.json','["野堂疏豁近江皋，喜見南山秋氣高。", "野外漸寒群木脫，草根薄暮百蟲號。", "筑陂濬畎更相勉，伐荻剶桑敢愛勞。", "亦念耄荒當自佚，欲將世業付兒曹。"]'),
('1ddd53bc-19bb-444f-864b-6f9abf348731','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其一','陸游','宋','宋诗','song-poetry','','[]','嚙雪猶能活窖中，儈牛亦可隱牆東。',32,'全唐诗/poet.song.134000.json','["嚙雪猶能活窖中，儈牛亦可隱牆東。", "來歸里社當知幸，萬卷書邊一老翁。"]'),
('fc6063be-5dbc-40f0-937a-8c956e2f3e08','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其二','陸游','宋','宋诗','song-poetry','','[]','小兒緣天摘列宿，老子含飴弄稚孫。',32,'全唐诗/poet.song.134000.json','["小兒緣天摘列宿，老子含飴弄稚孫。", "郊居得此豈不樂，無奈催租人打門。"]'),
('a38d9c98-f2f6-473a-a5d0-774e3a1beb25','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其三','陸游','宋','宋诗','song-poetry','','[]','早携書劍三隨計，晚辱弓旌四造朝。',32,'全唐诗/poet.song.134000.json','["早携書劍三隨計，晚辱弓旌四造朝。", "心愧石帆山下叟，一生不識浙江潮。"]'),
('e21ebcb4-f469-40f4-84a5-488b15adc5e3','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其四','陸游','宋','宋诗','song-poetry','','[]','筋骸未廢寧爲老，烟火猶通豈是貧。',32,'全唐诗/poet.song.134000.json','["筋骸未廢寧爲老，烟火猶通豈是貧。", "時跨一驢山縣去，園丁野老盡相親。"]'),
('16010e60-d014-4b00-9fef-dfa117465b07','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其五','陸游','宋','宋诗','song-poetry','','[]','蓍囊藥笈每隨身，問病求占日日新。',32,'全唐诗/poet.song.134000.json','["蓍囊藥笈每隨身，問病求占日日新。", "向道不能渠豈信，隨宜酬答免違人。"]'),
('52de4203-2498-41d0-9d5a-ab26ea71765b','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其六','陸游','宋','宋诗','song-poetry','','[]','藥粗野老偏稱效，詩淺山僧妄謂工。',32,'全唐诗/poet.song.134000.json','["藥粗野老偏稱效，詩淺山僧妄謂工。", "懷餅裹茶來問訊，不妨一笑寂寥中。"]'),
('8147f00f-fb78-4220-aa61-5553175ff694','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其七','陸游','宋','宋诗','song-poetry','','[]','家居愈老厭拘纏，旅舍僧房意自便。',32,'全唐诗/poet.song.134000.json','["家居愈老厭拘纏，旅舍僧房意自便。", "乞菜作羹殊有味，借床小憩即成眠。"]'),
('2dacbfef-adb9-494d-9281-37245037abef','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其八','陸游','宋','宋诗','song-poetry','','[]','鄉閭敬老意常勤，一味甘鮮必見分。',32,'全唐诗/poet.song.134000.json','["鄉閭敬老意常勤，一味甘鮮必見分。", "大胾在前無箸食，始知富貴本浮雲。"]'),
('47c01d71-f8aa-4b56-ada6-143143110c32','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其九','陸游','宋','宋诗','song-poetry','','[]','市樓嘈囋知豐歲，驛樹輪囷傲早霜。',32,'全唐诗/poet.song.134000.json','["市樓嘈囋知豐歲，驛樹輪囷傲早霜。", "六十年間凡幾到，剩沽新酒對斜陽。"]'),
('fa7d6935-e8eb-4fb2-8b3b-81f5f9ada7f3','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其一○','陸游','宋','宋诗','song-poetry','','[]','燂湯具浴僧窗暖，舂黍供炊旅甑香。',32,'全唐诗/poet.song.134000.json','["燂湯具浴僧窗暖，舂黍供炊旅甑香。", "自笑平生爲客熟，關山千里一衣囊。"]'),
('cf480668-52c1-423e-8a2d-25c781199d54','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其一一','陸游','宋','宋诗','song-poetry','','[]','胡麻刈罷下蕎初，引水家家灌晚蔬。',32,'全唐诗/poet.song.134000.json','["胡麻刈罷下蕎初，引水家家灌晚蔬。", "但有茅簷隨處好，淵明可獨愛吾廬。"]'),
('7f3778c3-33eb-482c-b556-352edae651dd','甲子秋八月偶思出遊往往累日不能歸或遠至傍縣凡得絕句十有二首雜錄入稿中亦不復詮次也  其一二','陸游','宋','宋诗','song-poetry','','[]','秋風敗葉委蒼苔，小蹇閑遊始此回。',32,'全唐诗/poet.song.134000.json','["秋風敗葉委蒼苔，小蹇閑遊始此回。", "溪上風烟爭晚渡，縣前燈火賣新醅。"]'),
('77291b6b-6007-47bb-8201-d91a4b33bf1d','遊山','陸游','宋','宋诗','song-poetry','','[]','四序雖悉佳，莫若新秋時。',96,'全唐诗/poet.song.134000.json','["四序雖悉佳，莫若新秋時。", "已脫烹煮厄，未興摇落悲。", "鷺集水落渚，鵲爭風墮枝。", "烟村烏桕丹，晚日望最奇。", "豈無一舴艋，往赴幽人期。", "婆娑下堂迎，壞衲顛倒披。", "丹果垂中庭，碧花蔓疏籬。", "秋高財一來，怪我今年衰。"]'),
('a62b09b9-0bec-4894-a440-94da49ac4fbf','對酒','陸游','宋','宋诗','song-poetry','','[]','天上何曾許寄愁，酒中正自可忘憂。',64,'全唐诗/poet.song.134000.json','["天上何曾許寄愁，酒中正自可忘憂。", "不能上樹作巢飲，尚辦滿船供拍浮。", "神仙可學君豈信，衣食裁足吾何求。", "但憶人如王粲輩，相携一笑賦登樓。"]'),
('400a7081-5ba2-4c56-a951-7fe9130a6d48','遣舟迎子遹因寄古風十四韵','陸游','宋','宋诗','song-poetry','','[]','今日拆汝書，一讀眼爲明。',168,'全唐诗/poet.song.134000.json','["今日拆汝書，一讀眼爲明。", "知汝即日歸，明當遣舟迎。", "想汝片帆東，翩若飛鴻征。", "薄暮過梅市，咿謳雙櫓聲。", "到家亦尚早，城樓初發更。", "草草一尊酒，爲汝手自傾。", "夜分不能寐，頓忘衰病嬰。", "豈惟病良已，白頭黑絲生。", "暫別亦不惡，益重父子情。", "自今日相守，北窗同短檠。", "六經焰久伏，百氏方縱橫。", "世俗擯孤學，未易口舌爭。", "此責在學者，草萊勿自輕。", "汝壯父未死，相勉在力行。"]'),
('3e09c9bf-d206-4ea3-9559-0150fd03de4c','重寄子遹','陸游','宋','宋诗','song-poetry','','[]','秋風日日望歸裝，忽報來期喜欲狂。',32,'全唐诗/poet.song.134000.json','["秋風日日望歸裝，忽報來期喜欲狂。", "衰病無因檝迎汝，夢隨殘月過浮梁。"]'),
('f89dbe0a-a9bb-4636-9e69-2730e537b840','飯後偶題','陸游','宋','宋诗','song-poetry','','[]','環堵蕭然百慮忘，天教得飯飫枯腸。',64,'全唐诗/poet.song.134000.json','["環堵蕭然百慮忘，天教得飯飫枯腸。", "長橋鮓美桃花嫩，北苑茶新带胯方。", "漠漠寒花欹晚照，翩翩孤蝶弄秋光。", "解衣捫腹西窗下，賴有新詩破日長。"]'),
('0c717cfc-8122-45c3-b4b9-d0091d78e406','秋興二首  其一','陸游','宋','宋诗','song-poetry','','[]','流光冉冉迫崦嵫，常抱秋風宋玉悲。',64,'全唐诗/poet.song.134000.json','["流光冉冉迫崦嵫，常抱秋風宋玉悲。", "才盡已無楓落句，身存又見雁來時。", "自憐閉戶龐眉叟，初對還家大耳兒。", "一盞青燈照寒影，不妨細舉別來詩。"]'),
('2126a598-fbbd-435e-a27e-7744aaefd435','秋興二首  其二','陸游','宋','宋诗','song-poetry','','[]','世事元看等一毫，紛紛寵辱陋兒曹。',64,'全唐诗/poet.song.134000.json','["世事元看等一毫，紛紛寵辱陋兒曹。", "雁行橫野月初上，桐葉滿庭霜未高。", "細考蟲魚箋爾雅，廣收草木續離騷。", "更餘一事君知否，卧聽床頭滴小槽。"]'),
('5ee1683e-2f7e-41b8-a60d-7cfb021aa854','舍北行飯','陸游','宋','宋诗','song-poetry','','[]','飯飽逍遥信所之，芡塘蔬圃遍遊嬉。',64,'全唐诗/poet.song.134000.json','["飯飽逍遥信所之，芡塘蔬圃遍遊嬉。", "梧楸凋落風高後，瓜瓠輪囷雨足時。", "犬喜人歸迎野路，鵲營巢穩占低枝。", "晚來懶復呼童子，自掩柴門上扊扅。"]'),
('48c92f5b-95e9-404c-97af-2a329897534d','舍南野步','陸游','宋','宋诗','song-poetry','','[]','枯蔓絡荆籬，幽花映荻扉。',48,'全唐诗/poet.song.134000.json','["枯蔓絡荆籬，幽花映荻扉。", "馴麞驚不起，歸鶴倦猶飛。", "野色連收網，邊愁入搗衣。", "壯圖空自笑，事事與心違。"]'),
('9853e9a4-3d42-4c35-8b42-df7f1cd7aed3','感昔五首  其一','陸游','宋','宋诗','song-poetry','','[]','行年三十憶南遊，穩駕滄溟萬斛舟。',32,'全唐诗/poet.song.134000.json','["行年三十憶南遊，穩駕滄溟萬斛舟。", "常記早秋雷雨霽，柁師指點說流求。"]'),
('dd1e1b1e-04d3-48f7-a189-b37398582f09','感昔五首  其二','陸游','宋','宋诗','song-poetry','','[]','馬瘦行遲自一奇，溪山佳處看無遺。',32,'全唐诗/poet.song.134000.json','["馬瘦行遲自一奇，溪山佳處看無遺。", "酒壚强挽人同醉，散去何曾識是誰。"]'),
('6fa2c28f-1aac-43b2-bbda-ba1d69166dc8','感昔五首  其三','陸游','宋','宋诗','song-poetry','','[]','負琴腰劍成三友，出蜀歸吳歷百城。',32,'全唐诗/poet.song.134000.json','["負琴腰劍成三友，出蜀歸吳歷百城。", "最是客途愁絕處，巫山廟下聽猿聲。"]'),
('b85d3ed2-c162-4b17-9979-017f512e0a33','感昔五首  其四','陸游','宋','宋诗','song-poetry','','[]','岳陽三伏正炎蒸，爽氣凄風見未曾。',32,'全唐诗/poet.song.134000.json','["岳陽三伏正炎蒸，爽氣凄風見未曾。", "白浪蹴天樓欲動，當時恨不到黄陵。"]'),
('f93203f4-8667-4dd6-a946-e27aa4835b92','感昔五首  其五','陸游','宋','宋诗','song-poetry','','[]','行遍天涯只漫勞，歸來登覽興方豪。',32,'全唐诗/poet.song.134000.json','["行遍天涯只漫勞，歸來登覽興方豪。", "雲生神禹千年穴，雪捲靈胥八月濤。"]'),
('76383227-3279-4344-8a32-5942ffdad7a9','病齒','陸游','宋','宋诗','song-poetry','','[]','似病非病臂已瘳，當墮未墮齒難留。',64,'全唐诗/poet.song.134000.json','["似病非病臂已瘳，當墮未墮齒難留。", "一杯藜粥吾所美，幸可自辦不待求。", "既無齧骨犯曲禮，亦免祝鯁煩成周。", "形骸外物付悠悠，那將老境供閑愁。"]'),
('9cdaad78-48fa-4ef7-abcf-7a073e8d8fb2','揮手','陸游','宋','宋诗','song-poetry','','[]','揮手群玉府，說駕石帆山。',48,'全唐诗/poet.song.134000.json','["揮手群玉府，說駕石帆山。", "偶與片雲出，却隨孤鶴還。", "松風暮蕭瑟，石溜夜淙潺。", "阿敏讀書處，更添茆一間。"]'),
('3f9147b7-ec29-453e-959f-41ff0356bf84','過鄰家','陸游','宋','宋诗','song-poetry','','[]','初寒偏著苦吟身，情話時時過近鄰。',64,'全唐诗/poet.song.134000.json','["初寒偏著苦吟身，情話時時過近鄰。", "嘉穟連雲無水旱，齊民轉壑自酸辛。", "室廬封鐍多逋戶，市邑蕭條少醉人。", "甑未生塵羹有糝，吾曹切勿怨常貧。"]'),
('6e0ccbd0-a0d7-4366-b518-ab356fbc7898','甲子秋八月丙辰雞初鳴時夢劉韶美示詩八篇高古可愛明旦作此詩志之','陸游','宋','宋诗','song-poetry','','[]','韶美仙去三十年，一念及之常悵然。',64,'全唐诗/poet.song.134000.json','["韶美仙去三十年，一念及之常悵然。", "秋窗忽夢接顔色，萬里老鶴歸遼天。", "贈詩溫其似玉瓚，我亦粗識關雎亂。", "建安黄初不足言，筆端直覺無秦漢。"]'),
('da184a3d-be69-4487-a246-c217cf73097d','山居','陸游','宋','宋诗','song-poetry','','[]','客至何曾共劇談，行藏獨有老農諳。',64,'全唐诗/poet.song.134000.json','["客至何曾共劇談，行藏獨有老農諳。", "覓官肯信山居樂，食淡方知飯味甘。", "一脈泉通澆藥圃，萬重雲鎖釣魚庵。", "好奇自笑心無厭，行遍江南憶劍南。"]'),
('5cb796c3-6c46-4356-8954-7326bb239d68','歸老','陸游','宋','宋诗','song-poetry','','[]','兩脚走萬里，歸老樵風溪。',83,'全唐诗/poet.song.134000.json','["兩脚走萬里，歸老樵風溪。", "雖遠京雒塵，窮巷還多泥。", "纍纍家狗，喔喔失旦雞。", "幸非徙比景，何恨棲會稽。", "今年更可笑，傴僂自灌畦。", "榮雖不滿眼，悔亦免噬臍。", "萬事付一尊，師友阮與嵇。"]'),
('17d3b706-624c-4657-ad8e-7308b8cf0c0d','送子坦赴鹽官縣市征','陸游','宋','宋诗','song-poetry','','[]','父子團欒笑語譁，豈知雲散各天涯。',64,'全唐诗/poet.song.134000.json','["父子團欒笑語譁，豈知雲散各天涯。", "長亭結束秋將晚，別酒凄凉日易斜。", "我坐耄年艱就養，汝非仰祿肯離家。", "遊山尚有平生意，試爲閑尋一鹿車。"]'),
('51cbd3a2-35fe-474f-b259-37447b3a9803','寄子坦','陸游','宋','宋诗','song-poetry','','[]','目斷西陵細靄中，津亭想汝繫孤篷。',64,'全唐诗/poet.song.134000.json','["目斷西陵細靄中，津亭想汝繫孤篷。", "頗憂昨暮雲吞日，猶幸今朝雨壓風。", "就食亦知難戀戀，挂帆終恨太匆匆。", "寒沙不是無來雁，頻寄書歸問老翁。"]'),
('922c6230-5685-4905-9c35-fb13d454f9b4','書感','陸游','宋','宋诗','song-poetry','','[]','老荷寬恩許退耕，絲毫無報亦何情。',64,'全唐诗/poet.song.134000.json','["老荷寬恩許退耕，絲毫無報亦何情。", "民貧樂歲尚艱食，道喪異端方肆行。", "黨禍本從名輩出，弊端常向盛時生。", "古人骨冷青松下，誰起英魂與細評。"]'),
('12bf5d45-9958-4ee4-8b20-4b63502ab806','自扁門歸','陸游','宋','宋诗','song-poetry','','[]','橘柚纍纍未著霜，陂塘渺渺度秋光。',64,'全唐诗/poet.song.134000.json','["橘柚纍纍未著霜，陂塘渺渺度秋光。", "長橋虹卧當官道，重閣翬飛出女牆。", "烟際遠舟俄已隱，天邊驚雁不成行。", "歸來有底誇兒輩，笑指奚奴古錦囊。"]'),
('8b37daa9-f8ee-4d1f-90fd-953dad554091','遣興','陸游','宋','宋诗','song-poetry','','[]','兔徑遊觀足，蝸廬卧起寬。',48,'全唐诗/poet.song.134000.json','["兔徑遊觀足，蝸廬卧起寬。", "垂名千古易，無愧寸心難。", "燈火娛清夜，風霜變早寒。", "一經家世事，吾興未應闌。"]'),
('517e02d0-c669-41f7-8bc2-e67b92035dbd','詩酒','陸游','宋','宋诗','song-poetry','','[]','詩酒平生樂，無如老病侵。',48,'全唐诗/poet.song.134000.json','["詩酒平生樂，無如老病侵。", "才衰愁韵險，量退怯杯深。", "宿露滋金藟，微霜點纈林。", "呼鷹五陵路，惆悵少年心。"]'),
('d4840540-29d7-4b44-a4c1-31e9b0076738','晚秋野興二首  其一','陸游','宋','宋诗','song-poetry','','[]','病骨支離不耐秋，今年九月即輕裘。',64,'全唐诗/poet.song.134000.json','["病骨支離不耐秋，今年九月即輕裘。", "細書燈下幸能讀，舊友夢中時與遊。", "官賦畢輸無吠犬，農功已息有閑牛。", "不知冠蓋朝天客，也得心安似我不。"]'),
('ee594d96-cc38-4512-943e-cdc664ff7573','晚秋野興二首  其二','陸游','宋','宋诗','song-poetry','','[]','徹底無能徹骨貧，自憐虛作六朝民。',64,'全唐诗/poet.song.134000.json','["徹底無能徹骨貧，自憐虛作六朝民。", "學因病廢捐長日，志與年衰愧古人。", "露溼亂螢飛暗廡，霜清饑雀噪空囷。", "一生眼境常如此，草賦憑誰問大鈞。"]'),
('b582a4ea-8b20-4bd4-ad5f-be200168994e','舟中口占','陸游','宋','宋诗','song-poetry','','[]','養生妙理本平平，未可常談笑老生。',64,'全唐诗/poet.song.134000.json','["養生妙理本平平，未可常談笑老生。", "業力頓消知學進，人情愈薄喜身輕。", "鶴雛日長丹砂頂，巖溜時聞玉佩聲。", "最是扁舟暮歸處，一川風月遠相迎。"]'),
('31ffab21-3498-4978-9753-c2f487bdee71','閉門','陸游','宋','宋诗','song-poetry','','[]','閉門何所樂，聊息此生勞。',48,'全唐诗/poet.song.134000.json','["閉門何所樂，聊息此生勞。", "霜薄殘蕪綠，風酣萬木號。", "研朱點周易，飲酒讀離騷。", "斷盡功名念，非關快剪刀。"]'),
('b4e0bd94-6ac2-41ec-a5c2-52ad09638e8f','暮秋六首  其一','陸游','宋','宋诗','song-poetry','','[]','多雨今秋水渺然，溝溪無處不通船。',32,'全唐诗/poet.song.134000.json','["多雨今秋水渺然，溝溪無處不通船。", "山回忽得烟村路，始信桃源是地仙。"]'),
('9c371916-c2b8-485a-82e6-4be4df80e483','暮秋六首  其二','陸游','宋','宋诗','song-poetry','','[]','閑傾清聖濁賢酒，穩泛朝南暮北風。',32,'全唐诗/poet.song.134000.json','["閑傾清聖濁賢酒，穩泛朝南暮北風。", "射的山前雲幾片，一秋不散伴漁翁。"]'),
('4961175b-80fa-4339-9e53-34ef1472bec7','暮秋六首  其三','陸游','宋','宋诗','song-poetry','','[]','百年大耋龍鍾日，九月初寒慘淡天。',32,'全唐诗/poet.song.134000.json','["百年大耋龍鍾日，九月初寒慘淡天。", "嶺谷高低明野火，村居遠近起炊烟。"]'),
('c87cd049-cda0-4942-9bfb-fd6e52d8d3f9','暮秋六首  其四','陸游','宋','宋诗','song-poetry','','[]','舍前舍後養魚塘，溪北溪南打稻場。',32,'全唐诗/poet.song.134000.json','["舍前舍後養魚塘，溪北溪南打稻場。", "喜事一雙黄蛺蝶，隨人來往弄秋光。"]'),
('8f888353-b2b2-464b-84b9-69cbc2a2a2aa','暮秋六首  其五','陸游','宋','宋诗','song-poetry','','[]','九月山村已驟寒，看雲殊怯倚闌干。',32,'全唐诗/poet.song.134000.json','["九月山村已驟寒，看雲殊怯倚闌干。", "一杯濁酒栽培睡，不覺春雷起鼻端。"]'),
('dd369530-7b2f-4707-b16e-394f7168d7f6','暮秋六首  其六','陸游','宋','宋诗','song-poetry','','[]','清秋又是一年新，滿眼丹楓映白蘋。',32,'全唐诗/poet.song.134000.json','["清秋又是一年新，滿眼丹楓映白蘋。", "海內故人書斷絕，汀洲鷗鷺却心親。"]'),
('cfdff11c-1d95-41cc-b2cb-89fd7d6717e3','農舍四首  其一','陸游','宋','宋诗','song-poetry','','[]','三農雖隙亦匆忙，穡事何曾一夕忘。',32,'全唐诗/poet.song.134000.json','["三農雖隙亦匆忙，穡事何曾一夕忘。", "欲曬胡麻愁屢雨，未收蕎麥怯新霜。"]'),
('07ab1021-ae7c-44e6-888f-d9701045d055','農舍四首  其二','陸游','宋','宋诗','song-poetry','','[]','神農之學未爲非，日夜勤勞備歲饑。',32,'全唐诗/poet.song.134000.json','["神農之學未爲非，日夜勤勞備歲饑。", "雨畏禾頭蒸耳出，潤憂麥粒化蛾飛。"]'),
('d918179a-7bc2-4bff-823c-3c6535cbcf44','農舍四首  其三','陸游','宋','宋诗','song-poetry','','[]','萬錢近縣買黄犢，襏襫行當東作時。',32,'全唐诗/poet.song.134000.json','["萬錢近縣買黄犢，襏襫行當東作時。", "堪笑江東王謝輩，唾壺麈尾事兒嬉。"]'),
('8fe312be-fc63-4892-886e-151edf74622f','農舍四首  其四','陸游','宋','宋诗','song-poetry','','[]','杜門雖與世相違，未許人嘲作計非。',32,'全唐诗/poet.song.134000.json','["杜門雖與世相違，未許人嘲作計非。", "長綆雲邊牽犢過，小舟月下載犁歸。"]'),
('f6ef4376-bde2-44dc-95bb-014eecdef08e','九月十日夜獨坐','陸游','宋','宋诗','song-poetry','','[]','蓬窗燈火耿疏籬，正是寒沙雁到時。',64,'全唐诗/poet.song.134000.json','["蓬窗燈火耿疏籬，正是寒沙雁到時。", "頭少二毛真篤老，口無縱理亦長饑。", "朝聞夕死固當勉，幼學壯行嗟已遲。", "小豎夜闌私怪我，儼然危坐若深思。"]'),
('be97542f-d064-4a0a-b359-259f580646f4','述意','陸游','宋','宋诗','song-poetry','','[]','憂患無窮生有涯，惟須百事屏紛華。',64,'全唐诗/poet.song.134000.json','["憂患無窮生有涯，惟須百事屏紛華。", "人誰敢侮修身士，天不能窮力穡家。", "頻喚老僧同夜粥，間從鄰叟試秋茶。", "結茅林下從來事，瓦屋三間已太奢。"]'),
('91ad76dc-da40-43ee-a4d7-3e2482f8a42a','小疾自警','陸游','宋','宋诗','song-poetry','','[]','老來土弗强，舉箸輒作病。',144,'全唐诗/poet.song.134000.json','["老來土弗强，舉箸輒作病。", "造物蓋警之，何啻三下令。", "而我不自珍，若與疾豎競。", "豈惟昧攝養，實亦闕忠敬。", "顛踣乃自詒，何用死不瞑。", "自今師古訓，念念貴清靜。", "羔豚昔所美，放斥如遠佞。", "淖糜煮石泉，香飯炊瓦甑。", "采蔬擷藥苗，巾羃相照映。", "膨脝亦宜戒，僅飽勿憚剩。", "隱書有至理，要使氣常勝。", "因之戒友朋，苦語君試聽。"]'),
('ac5146fe-c8b0-4d81-a186-68c416b28d01','白龍','陸游','宋','宋诗','song-poetry','','[]','九月癸酉暮，白龍見西方。',72,'全唐诗/poet.song.134000.json','["九月癸酉暮，白龍見西方。", "是時久晴明，日落天正蒼。", "玉宇無纖雲，凌空獨高翔。", "蜿蜒久乃隱，父老嘆未嘗。", "清臺占五行，此事實殊常。", "我非劉子政，聊記以短章。"]'),
('08a4f702-9da9-45b3-b66e-e551ff076dcf','學易二首  其一','陸游','宋','宋诗','song-poetry','','[]','卒歲勿多求，壺餐與褐裘。',48,'全唐诗/poet.song.134000.json','["卒歲勿多求，壺餐與褐裘。", "心安由自足，身貴爲無求。", "易化千年鶴，難馴萬里鷗。", "閉門方學易，未暇揖浮丘。"]'),
('47782815-380e-4dcd-908a-64a3b9dcc51f','學易二首  其二','陸游','宋','宋诗','song-poetry','','[]','學古忘衰疾，齋心洗昨非。',48,'全唐诗/poet.song.134000.json','["學古忘衰疾，齋心洗昨非。", "拳拳奉天理，坦坦息心機。", "改過先幽隱，收功在細微。", "耄期猶自警，俯仰惜餘暉。"]'),
('7d4e41fd-19ed-46a3-85f4-717e333a0102','閑中作','陸游','宋','宋诗','song-poetry','','[]','呼童按摩罷，倚壁久伸餘。',48,'全唐诗/poet.song.134000.json','["呼童按摩罷，倚壁久伸餘。", "棋局可忘老，鳥聲能起予。", "掃簷憐罥蝶，投餌出潜魚。", "向晚明窗下，還來讀舊書。"]'),
('d9b5f02e-19f6-438b-94a9-294f1060fa55','枕上','陸游','宋','宋诗','song-poetry','','[]','嗈嗈初聽雁南征，喔喔俄聞雞一鳴。',64,'全唐诗/poet.song.134000.json','["嗈嗈初聽雁南征，喔喔俄聞雞一鳴。", "夢境往來雙隻堠，宦途興廢短長檠。", "何由生計裁能足，不願人間過取名。", "飯軟茶甘吾事了，但愁無酒酌公榮。"]'),
('21904844-91be-4d97-9609-76468f2831dd','出遊五首  其一','陸游','宋','宋诗','song-poetry','','[]','一樽隨處可開顔，此事深疑造物慳。',64,'全唐诗/poet.song.134000.json','["一樽隨處可開顔，此事深疑造物慳。", "地可登臨多恨遠，身常强健又須閑。", "山圍小市烟初斂，霜著橫林葉半殷。", "徙倚闌干君勿厭，日斜猶及棹舟還。"]'),
('60988f95-6dbc-47f1-b1aa-8dca77832dfd','出遊五首  其二','陸游','宋','宋诗','song-poetry','','[]','漁村酒市本無期，小蹇扁舟信所之。',64,'全唐诗/poet.song.134000.json','["漁村酒市本無期，小蹇扁舟信所之。", "丹葉滿林霜落後，紫萍黏塊水枯時。", "山林閑寂歸雖早，齒髮衰殘病已遲。", "努力及時謀自適，錦囊多貯暮秋詩。"]'),
('a59811ee-6194-4054-b164-0d1977d61f18','出遊五首  其三','陸游','宋','宋诗','song-poetry','','[]','山有籃輿步有舟，放翁身健得閑遊。',64,'全唐诗/poet.song.134000.json','["山有籃輿步有舟，放翁身健得閑遊。", "羊牛點點日將夕，蒲柳蕭蕭天正秋。", "細徑僧歸雲外寺，疏燈人語酒家樓。", "歸途更愛湖橋月，獨倚闌干爲小留。"]'),
('81d7bf15-7ece-4818-b070-5df93f7a1225','出遊五首  其四','陸游','宋','宋诗','song-poetry','','[]','霜氣蕭條木葉黄，佳時病起意差强。',64,'全唐诗/poet.song.134000.json','["霜氣蕭條木葉黄，佳時病起意差强。", "雲烟古寺聞僧梵，燈火長橋見戲場。", "一枕清風幽夢斷，數匙旅飯野蔬香。", "道邊莫笑衰殘甚，獨往山林興未央。"]'),
('5559dae8-8c71-46f4-af02-99299055d3c1','出遊五首  其五','陸游','宋','宋诗','song-poetry','','[]','禹窆胥濤中路分，畫橈衝破一川雲。',64,'全唐诗/poet.song.134000.json','["禹窆胥濤中路分，畫橈衝破一川雲。", "柯橋僧閣凌空起，梅市漁歌带月聞。", "蟹束寒蒲大盈尺，鱸穿細柳重兼斤。", "酒家報我新醅熟，且撥閑愁寄一欣。"]'),
('655f9ad5-0767-4b4f-9fe2-2a57ebed8e7b','家居三首  其一','陸游','宋','宋诗','song-poetry','','[]','清世念遺民，常情重老人。',48,'全唐诗/poet.song.134000.json','["清世念遺民，常情重老人。", "饋漿煩郡府，分胙愧鄉鄰。", "穫稻黄雲卷，舂粳玉粒新。", "膨脝自摩腹，一笑欲忘貧。"]'),
('bd4ffbb7-5c36-4571-97cd-a2d060234197','家居三首  其二','陸游','宋','宋诗','song-poetry','','[]','老眊詩名減，登臨笑口開。',48,'全唐诗/poet.song.134000.json','["老眊詩名減，登臨笑口開。", "釀泉爲酒熟，倩鶴附書回。", "紗帽方簪菊，筇枝又探梅。", "清狂君勿笑，曾是薄蓬萊。"]'),
('0ef9db24-300d-4134-98fe-4db54d8493bf','家居三首  其三','陸游','宋','宋诗','song-poetry','','[]','蒲葦村深地，風霜歲晚天。',48,'全唐诗/poet.song.134000.json','["蒲葦村深地，風霜歲晚天。", "溪柴勝熾炭，黎布敵純綿。", "有客問奇字，無人嘲晝眠。", "誰言此翁老，懷抱尚超然。"]'),
('9f7b456a-c069-42c5-b8ec-6baccce9aabe','贈隱者二首  其一','陸游','宋','宋诗','song-poetry','','[]','疇昔從君處，玄都太古壇。',48,'全唐诗/poet.song.134000.json','["疇昔從君處，玄都太古壇。", "月高旛影直，霜重佩聲寒。", "鶴駕三山近，壺天萬里寬。", "相逢初未省，但認切雲冠。"]'),
('233969a3-555b-4e0e-95f0-b770cfec2804','贈隱者二首  其二','陸游','宋','宋诗','song-poetry','','[]','力量超終古，光明破積昏。',48,'全唐诗/poet.song.134000.json','["力量超終古，光明破積昏。", "獨行寧有待，妙用本忘言。", "神定嬰兒戲，丹靈豎子奔。", "緒餘應不靳，小出濟元元。"]'),
('e06aefa8-7592-4343-b45c-66bea0bc7d41','貧中自戲','陸游','宋','宋诗','song-poetry','','[]','種枳爲籬草結廬，人間知足更誰如。',64,'全唐诗/poet.song.134000.json','["種枳爲籬草結廬，人間知足更誰如。", "澗深松老忘榮謝，天闊雲閑任卷舒。", "門冷併無殘客迹，家貧常讀絕編書。", "有金可散還關念，多事從來笑漢疏。"]'),
('70e237e2-67d8-4d21-a2de-47c415e42ccb','風雨夜坐','陸游','宋','宋诗','song-poetry','','[]','寒風凄緊雨空濛，舍北新丹數樹楓。',64,'全唐诗/poet.song.134000.json','["寒風凄緊雨空濛，舍北新丹數樹楓。", "欹枕舊遊來眼底，掩書餘味在胸中。", "松明對影談玄客，篠火圍爐采藥翁。", "君看龜堂新境界，固應難與俗人同。"]'),
('11708af9-9e68-42e1-9fa7-26715c5ff169','示村醫','陸游','宋','宋诗','song-poetry','','[]','玉函肘後了無功，每寓奇方嘯傲中。',64,'全唐诗/poet.song.134000.json','["玉函肘後了無功，每寓奇方嘯傲中。", "衫袖玩橙清鼻觀，枕囊貯菊愈頭風。", "新詩吟罷愁如洗，好景逢來病欲空。", "却羨龍鍾布裘客，埭西賣藥到村東。"]'),
('c6ffb3b9-54be-4a1b-8513-1ddf91527f3d','秋雨','陸游','宋','宋诗','song-poetry','','[]','一秋風雨蔽白日，積水鬼神愁太陰。',64,'全唐诗/poet.song.134000.json','["一秋風雨蔽白日，積水鬼神愁太陰。", "寒螿悲鳴草根溼，水鳥暝哭菰叢深。", "殘年不覺日月逝，病骨惟愁霜露侵。", "常有淖糜支旦暮，一毫寧復少年心。"]'),
('b2778ce9-7f82-4b99-8069-ea65deceb24f','雜興六首  其一','陸游','宋','宋诗','song-poetry','','[]','散步持書卷，閑眠枕藥囊。',48,'全唐诗/poet.song.134000.json','["散步持書卷，閑眠枕藥囊。", "馴麞隨几杖，癡蝶入衣裳。", "病起年光速，身閑日影長。", "爲憐紅樹好，久立向西廂。"]'),
('2caf73f3-e3b9-4c15-9e64-b85f4a38cb45','雜興六首  其二','陸游','宋','宋诗','song-poetry','','[]','客問維摩疾，人哀范叔寒。',48,'全唐诗/poet.song.134000.json','["客問維摩疾，人哀范叔寒。", "詩囊負童背，藥笈挂驢鞍。", "野果攢眉澀，村醪捩齒酸。", "老雞殊可念，旦旦報平安。"]'),
('0e84259c-1eff-47ef-a77e-6c1b848ede2b','雜興六首  其三','陸游','宋','宋诗','song-poetry','','[]','愛物停垂釣，劬身自荷鋤。',48,'全唐诗/poet.song.134000.json','["愛物停垂釣，劬身自荷鋤。", "時從鄰父飲，日授稚孫書。", "尚棄登山屐，寧須下澤車。", "平生雙不借，投老伴歸歟。"]'),
('82fd80ec-abc5-4f41-b259-f54b859ef4b5','雜興六首  其四','陸游','宋','宋诗','song-poetry','','[]','平生獨何幸，命若與人謀。',48,'全唐诗/poet.song.134000.json','["平生獨何幸，命若與人謀。", "疲懦逃深責，空疏得早休。", "位卑輕得喪，迹遠少恩讎。", "莫怪歸耕樂，文園久倦遊。"]'),
('0d59784d-fcb1-45f0-8c84-40a93277ac94','雜興六首  其五','陸游','宋','宋诗','song-poetry','','[]','倒橐得千錢，從人買釣船。',48,'全唐诗/poet.song.134000.json','["倒橐得千錢，從人買釣船。", "秋風宿村步，暮雪醉江天。", "得意鷗波外，忘歸雁浦邊。", "平生笑嚴子，猶有姓名傳。"]'),
('7c189c6e-d492-4457-937c-fa0f2a0fbdf8','雜興六首  其六','陸游','宋','宋诗','song-poetry','','[]','澤居憂下溼，老病覺中乾。',48,'全唐诗/poet.song.134000.json','["澤居憂下溼，老病覺中乾。", "違俗恐不免，倚天聊自寬。", "受規如獲藥，喜退甚彈冠。", "不是憎勳業，心知骨相寒。"]'),
('ed8270a3-5355-4aae-9154-64c73447a51f','江亭','陸游','宋','宋诗','song-poetry','','[]','野市逢虛日，江亭候暮潮。',48,'全唐诗/poet.song.134000.json','["野市逢虛日，江亭候暮潮。", "蟲號霜後草，人立雨中橋。", "病骨羸將折，殘魂黯欲消。", "無心作村醉，酒旆苦相招。"]'),
('22d1b9e7-b5f8-4f64-ba94-9931331ca415','晚歸','陸游','宋','宋诗','song-poetry','','[]','梅市橋邊弄夕霏，菱歌聲裏棹船歸。',32,'全唐诗/poet.song.134000.json','["梅市橋邊弄夕霏，菱歌聲裏棹船歸。", "白鷗去盡還堪恨，不爲幽人暖釣磯。"]'),
('b67073c4-f963-4bb8-b8e6-d99883896ec4','懷昔','陸游','宋','宋诗','song-poetry','','[]','奮迹窮閻本甚微，刺天何敢慕群飛。',64,'全唐诗/poet.song.134000.json','["奮迹窮閻本甚微，刺天何敢慕群飛。", "業文僅與驢書券，學射纔因鼠發機。", "罟擭縱橫真脫命，風波澒洞尚餘威。", "朝冠挂了方無事，却愛山僧百衲衣。"]'),
('fb12b3a9-6456-4e9e-95a1-1ed7a6bc2c97','初寒示鄰曲','陸游','宋','宋诗','song-poetry','','[]','村北村南數十家，陂池重複谷谽谺。',64,'全唐诗/poet.song.134000.json','["村北村南數十家，陂池重複谷谽谺。", "荻叢缺處見漁火，蓬戶閉時聞紡車。", "淺瀨水清雙立鷺，橫林葉盡萬棲鴉。", "是中佳興無窮極，懶著青鞋上若耶。"]'),
('528c4a8d-cff7-460a-a43f-03e4593969db','夢中作','陸游','宋','宋诗','song-poetry','','[]','富貴誇人死即休，每輕庸子覓封侯。',64,'全唐诗/poet.song.134000.json','["富貴誇人死即休，每輕庸子覓封侯。", "讀書歷見古人面，好義常先天下憂。", "獨往何妨刀買犢，大烹却要鼎函牛。", "坐皆豪傑真成快，不負凌雲百尺樓。"]'),
('d0c48c0b-f5a5-42b6-8027-b5b85e57f2a1','初寒二首  其一','陸游','宋','宋诗','song-poetry','','[]','老遇初寒候，貧當絕祿時。',48,'全唐诗/poet.song.134000.json','["老遇初寒候，貧當絕祿時。", "衣裘俱在笥，薪炭不愆期。", "鶉滿群童網，魚浮百石陂。", "比鄰每分餉，捫腹可無饑。"]'),
('40f230fb-0562-4072-a99f-b8c5e2aee35b','初寒二首  其二','陸游','宋','宋诗','song-poetry','','[]','重簾禦晚吹，密瓦護晨霜。',48,'全唐诗/poet.song.134000.json','["重簾禦晚吹，密瓦護晨霜。", "焰焰磚爐火，霏霏石鼎香。", "行遲依木杖，坐久穴藜床。", "晝亦無聊甚，胡爲厭夜長。"]'),
('ddf69d40-deaf-4f99-8461-7578cc107e90','鉏菜','陸游','宋','宋诗','song-poetry','','[]','江湖霜雪薄，終歲富嘉蔬。',48,'全唐诗/poet.song.134000.json','["江湖霜雪薄，終歲富嘉蔬。", "菘韭常相續，萵蔓亦有餘。", "家貧缺粱肉，身病忌蛙魚。", "幸有荒畦在，何妨日荷鉏。"]'),
('6b05e5c3-0b46-48f1-8f3a-bb9c6c68b9c0','對酒','陸游','宋','宋诗','song-poetry','','[]','賦性雖耽酒，其如老病身。',48,'全唐诗/poet.song.134000.json','["賦性雖耽酒，其如老病身。", "氣衰成小戶，醅濁號賢人。", "疏廣矜君賜，劉伶畏婦嗔。", "蘭亭獨超絕，千載擅清真。"]'),
('79102ae2-1c60-4828-a557-88a22348a842','夜卧久不得寐復披衣起呼燈作草書數紙乃復酣枕明旦作此詩記之','陸游','宋','宋诗','song-poetry','','[]','才下多阨窮，地僻罕人客。',168,'全唐诗/poet.song.134000.json','["才下多阨窮，地僻罕人客。", "半生走四海，竟無第一策。", "暮年忽大悟，惟有緊閉門。", "朝作一池墨，弄筆招羈魂。", "初若奔騄驥，忽如掣蛟鯨。", "鬼神森出沒，雷雨更晦明。", "飛揚興已極，投筆竟就床。", "酣酣一枕睡，不覺幽夢長。", "手携避秦人，行上腰带鞓。", "下視河流黄，仰看天宇青。", "大呼自驚覺，夜半燈欲死。", "茆簷雨點滴，身乃在萬里。", "挑燈影突兀，顧問汝是誰。", "留侯雖强食，輕舉亦何疑。"]'),
('f5efb6bb-1259-4d67-894f-37e9e230a7a1','孤雲','陸游','宋','宋诗','song-poetry','','[]','四十年來住此山，入朝無補又東還。',32,'全唐诗/poet.song.134000.json','["四十年來住此山，入朝無補又東還。", "倚闌莫怪多時立，爲愛孤雲盡日閑。"]'),
('3205b406-67eb-4531-aa40-1a5f9205b46d','自閔','陸游','宋','宋诗','song-poetry','','[]','破帽羸驂厭垢氛，挂冠歸伴故溪雲。',64,'全唐诗/poet.song.134000.json','["破帽羸驂厭垢氛，挂冠歸伴故溪雲。", "年光疾病占强半，日景睡眠居七分。", "廬冢蕭條頻霣涕，交朋零落久離群。", "殘年豈復行孤學，自閔猶尊昔所聞。"]'),
('cab61bf2-54b8-44b0-89aa-df2c71016729','贈雞','陸游','宋','宋诗','song-poetry','','[]','青銅三百買烏雞，闢地牆東爲擇棲。',32,'全唐诗/poet.song.134000.json','["青銅三百買烏雞，闢地牆東爲擇棲。", "更聘一雌全物性，莫辭風雨五更啼。"]'),
('dd187391-21cc-432a-afa9-38a69945b84b','子遹爲其長兄置酒予亦與焉作五字示之','陸游','宋','宋诗','song-poetry','','[]','烏衣兄弟集，我亦據胡床。',48,'全唐诗/poet.song.134000.json','["烏衣兄弟集，我亦據胡床。", "晚菊數枝在，小園幽興長。", "霜清桑落熟，湯嫩雨前香。", "草草雖堪笑，他年未易忘。"]'),
('d4316584-612c-48ee-b367-b50dc16414f4','太息三首  其一','陸游','宋','宋诗','song-poetry','','[]','太息貧家似破船，不容一夕得安眠。',32,'全唐诗/poet.song.134000.json','["太息貧家似破船，不容一夕得安眠。", "春憂水潦秋防旱，左右枝梧且過年。"]'),
('0d11b33d-ebde-4745-9dcc-cf00cb84fb5b','太息三首  其二','陸游','宋','宋诗','song-poetry','','[]','禱廟祈神望歲穰，今年中熟更堪傷。',32,'全唐诗/poet.song.134000.json','["禱廟祈神望歲穰，今年中熟更堪傷。", "百錢斗米無人要，貫朽何時發積藏。"]'),
('b4d919c4-31d8-4d63-98b6-9c83e8aab5d0','太息三首  其三','陸游','宋','宋诗','song-poetry','','[]','北陌東阡有故墟，辛勤見汝昔營居。',32,'全唐诗/poet.song.134000.json','["北陌東阡有故墟，辛勤見汝昔營居。", "豪吞暗蝕皆逃去，窺戶無人草滿廬。"]'),
('9e3c090a-b217-40d1-ae9e-da55bf6a7ab6','代鄰家子作','陸游','宋','宋诗','song-poetry','','[]','社日淋漓酒滿衣，黄雞正嫩白鵝肥。',32,'全唐诗/poet.song.134000.json','["社日淋漓酒滿衣，黄雞正嫩白鵝肥。", "弟兄相顧無涯喜，扶得吾翁爛醉歸。"]'),
('2308e95d-cb48-46eb-8faa-ee1d31034625','山行','陸游','宋','宋诗','song-poetry','','[]','山光秀可餐，溪水清可啜。',120,'全唐诗/poet.song.134000.json','["山光秀可餐，溪水清可啜。", "白雲映空碧，突起若積雪。", "我行溪山間，靈府爲澄澈。", "崚嶒崖角立，蟠屈路九折。", "黄楊與冬青，鬰鬰自成列。", "其根貫石罅，橫逸相糾結。", "上捫雕鶻巢，下歷豺虎穴。", "流泉不可見，鏘然響環玦。", "出山日已暮，林火遠明滅。", "小憩得樵家，題詩記幽絕。"]'),
('2f75678b-7f39-465c-8ec1-fa44e24303dc','行過西山至柳姑廟晚歸','陸游','宋','宋诗','song-poetry','','[]','倚杖西山麓，褰衣古廟壖。',48,'全唐诗/poet.song.134000.json','["倚杖西山麓，褰衣古廟壖。", "斷雲依釣浦，細雨壓炊烟。", "廢學慚詩退，安貧覺氣全。", "霜天日易晚，鐘鼓隔城傳。"]'),
('6ac57447-ab5d-4294-a339-195faa38ffcd','月夕幽居有感','陸游','宋','宋诗','song-poetry','','[]','五嶽名山采藥身，可憐騎馬踏京塵。',64,'全唐诗/poet.song.134000.json','["五嶽名山采藥身，可憐騎馬踏京塵。", "浮名本是挻災物，謝事寧非得道因。", "出岫每招雲結伴，巢松仍與鶴爲鄰。", "劍南舊隱雖乖隔，依舊柴門月色新。"]'),
('5bc2d603-95a4-4402-adfa-e2a902bc79ac','寒夜將旦作','陸游','宋','宋诗','song-poetry','','[]','白髮垂肩無二毛，胸中消盡少年豪。',64,'全唐诗/poet.song.134000.json','["白髮垂肩無二毛，胸中消盡少年豪。", "河傾月沒夜將旦，木落草枯秋已高。", "窗下燈殘候蟲語，牆隅棲冷老雞號。", "曲肱不復更成寐，起視寒空如斷鰲。"]'),
('9a1f2f5b-8c80-4ad5-a805-a29b8e665e48','舍北獨步','陸游','宋','宋诗','song-poetry','','[]','霜露霑衣迫歲徂，天公欲爲老人娛。',64,'全唐诗/poet.song.134000.json','["霜露霑衣迫歲徂，天公欲爲老人娛。", "斷雲新月供詩句，蒼檜丹楓列畫圖。", "風葉蕭蕭歸獨鶴，烟波渺渺漾雙鳧。", "孤村薄暮誰從我，惟是詩囊與酒壺。"]'),
('2e5b208f-e2ec-4dac-a437-1837220055c7','山村道中思蜀','陸游','宋','宋诗','song-poetry','','[]','當年萬里客西南，藥市題詩倚半酣。',64,'全唐诗/poet.song.134000.json','["當年萬里客西南，藥市題詩倚半酣。", "偶爲三遊群玉府，遂妨重到百花潭。", "剡溪謾說思安道，函谷誰能識老聃。", "空乞丹青作橫幅，半堤寒日策羸驂。"]'),
('2eba8127-454f-48c9-bfdb-dc3aff41a550','不如茅屋底四首  其一','陸游','宋','宋诗','song-poetry','','[]','鑄印大如斗，佩劍長拄頤。',24,'全唐诗/poet.song.134000.json','["鑄印大如斗，佩劍長拄頤。", "不如茅屋底，睡到日高時。"]'),
('39aac128-67d1-445c-bc1c-37077abc4a5d','不如茅屋底四首  其二','陸游','宋','宋诗','song-poetry','','[]','南伐逾銅柱，西征出玉關。',24,'全唐诗/poet.song.134000.json','["南伐逾銅柱，西征出玉關。", "不如茅屋底，高枕看青山。"]'),
('10a2f2d5-d536-4eaf-bce7-3e4fd5ffe21c','不如茅屋底四首  其三','陸游','宋','宋诗','song-poetry','','[]','火齊堆盤起，珊瑚列庫藏。',24,'全唐诗/poet.song.134000.json','["火齊堆盤起，珊瑚列庫藏。", "不如茅屋底，父子事耕桑。"]'),
('7858044d-130f-40d7-a025-4a58d3aa1228','不如茅屋底四首  其四','陸游','宋','宋诗','song-poetry','','[]','列鼎賓筵盛，籠坊從騎都。',24,'全唐诗/poet.song.134000.json','["列鼎賓筵盛，籠坊從騎都。", "不如茅屋底，醉倒喚兒扶。"]'),
('af09c8ba-af61-457d-96e3-6ff4a574911c','菜羹','陸游','宋','宋诗','song-poetry','','[]','青菘綠韭古嘉蔬，蓴絲菰白名三吳。',96,'全唐诗/poet.song.134000.json','["青菘綠韭古嘉蔬，蓴絲菰白名三吳。", "臺心短黄奉天厨，熊蹯駝峰美不如。", "老農手自闢幽圃，土如膏肪水如乳。", "供家賴此不外取，襏襫寧辭走烟雨。", "雞豚下箸不可常，况復妄想太官羊。", "地爐篝火煮菜香，舌端未享鼻先嘗。"]'),
('738bf82b-f01c-429c-9982-e0419e37142a','十月暄甚人多疾十六日風雨作寒氣候方少正作短歌以記之','陸游','宋','宋诗','song-poetry','','[]','昔我從行臺，宿師南山旁。',216,'全唐诗/poet.song.134000.json','["昔我從行臺，宿師南山旁。", "仲秋已戒寒，九月常霣霜。", "入冬即大雪，人馬有仆僵。", "土床熾薪炭，旃毳如胡羌。", "果蔬悉已冰，熟視不得嘗。", "獵騎荷戈歸，爭獻狐與狼。", "是時意氣快，豈復思江鄉。", "邇來四十載，餘景迫耄荒。", "結茅鏡湖曲，氣候歲靡常。", "殘暑排不去，單衣作重陽。", "霜晚木未丹，地燠草不黄。", "玄冥失號令，瘧鬼意頡頏。", "忽焉風雨惡，縱擊勢莫當。", "頗疑地撼軸，又恐河决防。", "和泥補竅穴，乞火燎衣裳。", "霰雪雖未作，疾癘幸退藏。", "風爐薺糝美，瓦甑粳飯香。", "比鄰共安健，相與歌虞唐。"]'),
('4f3880ea-c5e8-44c9-a680-bc8095300e2e','冬夜題齋壁','陸游','宋','宋诗','song-poetry','','[]','髮不能勝二寸冠，天教送老向江干。',64,'全唐诗/poet.song.134000.json','["髮不能勝二寸冠，天教送老向江干。", "倚牆筇杖伴人瘦，縞瓦清霜爭月寒。", "壯志追思良可悔，危途遍歷始知難。", "一身著了餘何事，茅屋三間已太寬。"]'),
('bea0d155-5ba5-431c-ae1f-f6ce2cd8a46c','自遣','陸游','宋','宋诗','song-poetry','','[]','蔬食任無魚，山行可借驢。',48,'全唐诗/poet.song.134000.json','["蔬食任無魚，山行可借驢。", "指攣猶把釣，眼澀未捐書。", "客少勝紛若，家貧亦晏如。", "時時顧影嘆，頑似十年初。"]'),
('b49f9783-4ef6-41d7-9312-53fe1af61990','蕩蕩','陸游','宋','宋诗','song-poetry','','[]','蕩蕩唐虞去日遒，孔林千載亦荒丘。',64,'全唐诗/poet.song.134000.json','["蕩蕩唐虞去日遒，孔林千載亦荒丘。", "六經殘缺幸可考，百氏縱橫誰復憂。", "釋書恐非易論語，王迹其在詩春秋。", "君臣父子未嘗泯，吾道尚傳君但求。"]'),
('78c84d42-a5f8-4826-ab01-6d7e7ee755d6','晨起','陸游','宋','宋诗','song-poetry','','[]','曉枕初興白髮翁，弊裘百衲葑爐紅。',64,'全唐诗/poet.song.134000.json','["曉枕初興白髮翁，弊裘百衲葑爐紅。", "獨居漫受書狐媚，滯思難矜筆陣雄。", "舊學蟲魚箋爾雅，晚知稼穡講豳風。", "一身自喜無餘事，且度殘年風雪中。"]'),
('b24701d6-f31e-4727-92c0-a53bb155be6b','述感','陸游','宋','宋诗','song-poetry','','[]','斷簡承孤學，窮閻負壯心。',48,'全唐诗/poet.song.134000.json','["斷簡承孤學，窮閻負壯心。", "方憂一齒落，何止二毛侵。", "買地開幽圃，招僧理廢琴。", "浮生祇如此，感慨不須深。"]'),
('8aba3cf1-9ad6-4073-a7e4-e45cbddc63f8','甲子歲十月二十四日夜半夢遇故人於山水間飲酒賦詩既覺僅能記一二乃追補之二首  其一','陸游','宋','宋诗','song-poetry','','[]','拂衣金馬門，稅駕石帆村。',48,'全唐诗/poet.song.134000.json','["拂衣金馬門，稅駕石帆村。", "喚起華山夢，招回湘水魂。", "心親頻握手，目擊欲忘言。", "最喜藤陰下，翛然共一樽。"]'),
('53cc17c4-a743-4462-bd5d-85e0b6e806fa','甲子歲十月二十四日夜半夢遇故人於山水間飲酒賦詩既覺僅能記一二乃追補之二首  其二','陸游','宋','宋诗','song-poetry','','[]','小山緣曲澗，路斷得藤陰。',48,'全唐诗/poet.song.134000.json','["小山緣曲澗，路斷得藤陰。", "忽遇平生友，重論一片心。", "興闌棋局散，意豁酒杯深。", "雞唱俄驚覺，凄然泪滿襟。"]'),
('1f9306ca-080d-4656-9cf7-0929746f22f0','舟中夜賦','陸游','宋','宋诗','song-poetry','','[]','千里風塵季子裘，五湖烟浪志和舟。',64,'全唐诗/poet.song.134000.json','["千里風塵季子裘，五湖烟浪志和舟。", "燈殘復吐惱孤夢，雨落還收生旅愁。", "城上霜笳入霄漢，烟中漁火耿汀洲。", "牧之未極詩人趣，但謂能輕萬戶侯。"]'),
('2e8d43c1-d11a-4c5a-981d-1527a88263ec','舟中曉賦','陸游','宋','宋诗','song-poetry','','[]','木落霜清水鳥呼，扁舟夜泊古城隅。',64,'全唐诗/poet.song.134000.json','["木落霜清水鳥呼，扁舟夜泊古城隅。", "吹殘畫角鐘初動，低盡寒空斗欲無。", "浪迹已同鷗境界，遠遊方羨雁程途。", "高檣健席從今始，遍歷三湘與五湖。"]'),
('de5885d5-c45c-45ff-b947-898ec2a75fe5','漁家','陸游','宋','宋诗','song-poetry','','[]','江上漁家水蘸扉，閑雲片片傍苔磯。',64,'全唐诗/poet.song.134000.json','["江上漁家水蘸扉，閑雲片片傍苔磯。", "釣收鷺下虛舟立，橋斷僧尋別徑歸。", "海近岡巒多迤邐，天寒霧雨正霏微。", "羊裘老作桐江叟，點檢初心幸未違。"]'),
('4b0172b3-21ac-456b-8359-7a94e5602c57','遠遊','陸游','宋','宋诗','song-poetry','','[]','少年遊宦日，骯髒耻沉浮。',48,'全唐诗/poet.song.134000.json','["少年遊宦日，骯髒耻沉浮。", "見虎猶攘臂，逢狐肯叩頭。", "力行雖自許，早退豈人謀。", "小艇烟波上，飄然得遠遊。"]'),
('1a2e2a9a-0510-48aa-bf3a-ee25affd3911','與兒孫小飲','陸游','宋','宋诗','song-poetry','','[]','歲暮寒多雨，村深早閉門。',48,'全唐诗/poet.song.134000.json','["歲暮寒多雨，村深早閉門。", "荒園摘葵芥，近市買雞豚。", "短褐聯三世，幽窗共一樽。", "吾曹常得此，餘事不須論。"]'),
('e349834d-667b-4964-9e0c-88b885fdee65','遂初','陸游','宋','宋诗','song-poetry','','[]','狂本類三閭，歸仍慕二疏。',48,'全唐诗/poet.song.134000.json','["狂本類三閭，歸仍慕二疏。", "何由滿人笑，但可遂吾初。", "奕奕沙堤馬，栖栖下澤車。", "細看俱外物，俯首老犁鋤。"]'),
('29ec0d7b-b64a-4a44-9cc5-9c42d9c384f0','與村鄰聚飲二首  其一','陸游','宋','宋诗','song-poetry','','[]','冬日鄉閭集，珍烹得徧嘗。',48,'全唐诗/poet.song.134000.json','["冬日鄉閭集，珍烹得徧嘗。", "蟹供牢九美，魚煮膾殘香。", "雞跖宜菰白，豚肩雜韭黄。", "一歡君勿惜，豐歉歲何常。"]'),
('0650a694-45d4-47e9-b535-5cbb5da9c96c','與村鄰聚飲二首  其二','陸游','宋','宋诗','song-poetry','','[]','交好貧尤篤，鄉情老更親。',48,'全唐诗/poet.song.134000.json','["交好貧尤篤，鄉情老更親。", "𩺃香紅糝熟，炙美綠椒新。", "俗似山川古，人如酒醴醇。", "一杯相屬罷，吾亦愛吾鄰。"]'),
('5af53156-923c-4a50-8db5-60c32a3ff019','夜坐示子虡','陸游','宋','宋诗','song-poetry','','[]','裘薄知霜重，燈殘覺夜闌。',48,'全唐诗/poet.song.134000.json','["裘薄知霜重，燈殘覺夜闌。", "爲農宜廢學，謝事等無官。", "疏懶貧難醒，沉綿死有端。", "大兒千里至，聊復爲加餐。"]'),
('47c81b8b-a9ca-4723-aa25-4b2c96db8edb','行飯暮歸','陸游','宋','宋诗','song-poetry','','[]','暫置觀書不耐閑，飄然梅塢竹籬間。',64,'全唐诗/poet.song.134000.json','["暫置觀書不耐閑，飄然梅塢竹籬間。", "霜風盡脫千林葉，雲氣平沉一面山。", "笑喚筇枝扶蹇步，聊憑村酒借朱顔。", "廟壖牆下歸來晚，宿鳥紛紛已漸還。"]'),
('1959cd11-aa00-4f3b-8556-fe4ef23cb11d','寒雨中夜坐','陸游','宋','宋诗','song-poetry','','[]','江村風雨晚冥冥，閉戶添衣愴客情。',64,'全唐诗/poet.song.134000.json','["江村風雨晚冥冥，閉戶添衣愴客情。", "爐爇松肪如蠟爨，鼎煎茶浪起灘聲。", "團欒賴有兒同話，剝啄應無客可迎。", "聊舉一杯生耳熱，頹然酣枕到窗明。"]'),
('ceaecdaf-0e2f-458e-8f43-82d64df9ff29','枕上','陸游','宋','宋诗','song-poetry','','[]','世間命薄有誰如，僵卧空山夢亦孤。',64,'全唐诗/poet.song.134000.json','["世間命薄有誰如，僵卧空山夢亦孤。", "三尺窗前燈半死，萬重雲外雁相呼。", "久貧僅守殘書笈，未死猶須幾酒壺。", "趣辦一棺那得緩，古人四十揣頭顱。"]'),
('0c200e9f-cd05-4914-b623-7c124512f1d6','即事二首  其一','陸游','宋','宋诗','song-poetry','','[]','心與巖泉靜，形如野鶴臞。',48,'全唐诗/poet.song.134000.json','["心與巖泉靜，形如野鶴臞。", "朝餐美藜藿，夜學講唐虞。", "婢老無釵澤，僮寒闕袴襦。", "所欣惟一事，無吏督殘租。"]'),
('9eb72934-7267-45fe-8eb5-4f2f535ea30c','即事二首  其二','陸游','宋','宋诗','song-poetry','','[]','穄飯流匙滑，葵羹出鬴香。',48,'全唐诗/poet.song.134000.json','["穄飯流匙滑，葵羹出鬴香。", "有時留野客，亦復餉鄰牆。", "老圃傳占法，行僧遺藥方。", "未爲全絕物，終勝利名場。"]'),
('5eaf7afa-f315-436e-8642-c29379fa2532','雜感六首  其一','陸游','宋','宋诗','song-poetry','','[]','買馬當可乘，筑舍當可居。',48,'全唐诗/poet.song.134000.json','["買馬當可乘，筑舍當可居。", "快馬多覆敗，傑屋鬼所狙。", "徒行與露坐，安穩無後虞。", "所以古達人，秋風憶蓴鱸。"]'),
('ff32637a-aa60-45b5-b4e9-ba5e82d556b7','雜感六首  其二','陸游','宋','宋诗','song-poetry','','[]','士生誦二典，怳若生唐虞。',48,'全唐诗/poet.song.134000.json','["士生誦二典，怳若生唐虞。", "陞降奉玉帛，可否聞吁俞。", "闕里得其傳，功與造化俱。", "孰知千載後，乃尊重譯書。"]'),
('90090ae1-2a05-444c-8ce4-12cf7e617226','雜感六首  其三','陸游','宋','宋诗','song-poetry','','[]','擁裘南窗下，堅坐試定力。',48,'全唐诗/poet.song.134000.json','["擁裘南窗下，堅坐試定力。", "爐香亦不散，伴我到曛黑。", "絕交近爲我，遊世易顛踣。", "默默何所爲，且復自休息。"]'),
('310ac179-3a18-4ebc-b54f-17369546eb03','雜感六首  其四','陸游','宋','宋诗','song-poetry','','[]','上峽聞竹枝，入秦聞烏烏。',48,'全唐诗/poet.song.134000.json','["上峽聞竹枝，入秦聞烏烏。", "奏曲未及終，涕泪凄已濡。", "還山風月夕，菱唱起鏡湖。", "雖無遠遊感，白首亦窮途。"]'),
('42ee6e1d-2153-4aca-a116-fd17f5b5f2c3','雜感六首  其五','陸游','宋','宋诗','song-poetry','','[]','吾聞之古方，有病當鮮食。',48,'全唐诗/poet.song.134000.json','["吾聞之古方，有病當鮮食。", "如其不能爾，金丹亦無益。", "我老更事多，此語知造極。", "子房從赤松，千載推達識。"]'),
('5b2878ab-695f-486c-ba51-bb5fa419d049','雜感六首  其六','陸游','宋','宋诗','song-poetry','','[]','夢育小兒女，便有無窮愛。',48,'全唐诗/poet.song.134000.json','["夢育小兒女，便有無窮愛。", "謁醫問疾恙，對客誇警邁。", "晨雞忽喚覺，此愛復安在。", "人生困糾纏，一笑脫囚械。"]'),
('d11f4bc8-565e-48f6-a1ec-f32ec3e148d5','閑中自嘲','陸游','宋','宋诗','song-poetry','','[]','鏡湖西畔有漁扉，竊比玄英似庶幾。',64,'全唐诗/poet.song.134000.json','["鏡湖西畔有漁扉，竊比玄英似庶幾。", "風月定交殊耐久，烟波得意可忘歸。", "曾行萬里求微祿，亦伴諸公踐駭機。", "試問即今成底事，晨餐依舊北山薇。"]'),
('0fd8953b-c216-45c4-9b05-d9ad44a87565','暇日坐山麓松石間作','陸游','宋','宋诗','song-poetry','','[]','偶曳枯筇出槿籬，松間盤石坐移時。',64,'全唐诗/poet.song.134000.json','["偶曳枯筇出槿籬，松間盤石坐移時。", "饑麞齧草無餘綠，乳鵲營巢有墮枝。", "幽事類分皆可譜，高情辭達自成詩。", "莫嗟寂寂終吾世，正是他年一段奇。"]'),
('f044fdff-945e-44b8-8531-2afffb074015','得子虡臨安舟中書因寄','陸游','宋','宋诗','song-poetry','','[]','江水悠悠雙鯉魚，眼明初拆入關書。',64,'全唐诗/poet.song.134000.json','["江水悠悠雙鯉魚，眼明初拆入關書。", "殘年已覺身如客，一念還成泪濺裾。", "春近預憂歸夢短，潮回莫遣寄聲疏。", "何時可棄微官縛，五畝荒畦共荷鋤。"]'),
('f62b1657-0c36-4b90-93d3-fbf4b6cb2831','書喜二首  其一','陸游','宋','宋诗','song-poetry','','[]','寵辱元知不足驚，退居兀兀餞餘生。',64,'全唐诗/poet.song.134000.json','["寵辱元知不足驚，退居兀兀餞餘生。", "冰魚可釣羹材足，霜稻方登糴價平。", "鄰媼已安諸子養，園丁初葺數椽成。", "鄰閭喜事吾曹共，一醉寧辭洗破觥。"]'),
('3247595e-c80b-4373-aa46-482a2555f122','書喜二首  其二','陸游','宋','宋诗','song-poetry','','[]','十月東吳草未枯，村村耕牧可成圖。',64,'全唐诗/poet.song.134000.json','["十月東吳草未枯，村村耕牧可成圖。", "歲收儉薄雖中熟，民得蠲除已小蘇。", "家塾競延師教子，里門罕見吏徵租。", "老昏不記唐年事，試問元和有此無。"]'),
('0b014cc2-5312-468d-9ea2-8f920d3c6a00','老學庵夜興','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u534e\u5c71"]','冷卧空齋枕曲肱，饑鷹驚起髮鬅鬙。',64,'全唐诗/poet.song.134000.json','["冷卧空齋枕曲肱，饑鷹驚起髮鬅鬙。", "烟霞華嶽逃名客，風雪廬山入定僧。", "槲葉蔽身勝衣帛，金丹照室不燃燈。", "禿翁自笑無名字，聊向江湖襲舊稱。"]'),
('ed0becb6-9cf6-4e06-b053-c6521b06e873','感昔七首  其一','陸游','宋','宋诗','song-poetry','','[]','百丈庚寅上峽時，至今猶健豈前期。',32,'全唐诗/poet.song.134000.json','["百丈庚寅上峽時，至今猶健豈前期。", "家人暗換吾何嘆，鏡裏衰翁復是誰。"]'),
('a2d0ee91-b2b7-4482-baa0-7dd80ef9b7ab','感昔七首  其二','陸游','宋','宋诗','song-poetry','','[]','神女祠前猿夜鳴，相公溪上草初生。',32,'全唐诗/poet.song.134000.json','["神女祠前猿夜鳴，相公溪上草初生。", "重遊惟有西窗夢，一點燈青夢不成。"]'),
('032b2469-e644-4107-9a4c-1ad7d0eef91d','感昔七首  其三','陸游','宋','宋诗','song-poetry','','[]','白帝城邊鶯亂啼，憶騎瘦馬踏春泥。',32,'全唐诗/poet.song.134000.json','["白帝城邊鶯亂啼，憶騎瘦馬踏春泥。", "老來感舊多凄愴，孤夢時時到瀼西。"]'),
('d25a952f-3700-4ff5-813e-0bd3d7425f35','感昔七首  其四','陸游','宋','宋诗','song-poetry','','[]','小益晨裝雨作泥，南沮涉水馬長嘶。',32,'全唐诗/poet.song.134000.json','["小益晨裝雨作泥，南沮涉水馬長嘶。", "山腰細棧移新路，驛壁流塵暗舊題。"]'),
('f0368318-49f5-4f66-9604-c13fc757e37b','感昔七首  其五','陸游','宋','宋诗','song-poetry','','[]','曾從征西十萬師，白頭回顧只成悲。',32,'全唐诗/poet.song.134000.json','["曾從征西十萬師，白頭回顧只成悲。", "雲深駱谷傳烽處，雪密嶓山校獵時。"]'),
('0eade29d-3c06-4b2d-b0a5-87adaac78b08','感昔七首  其六','陸游','宋','宋诗','song-poetry','','[]','老君洞外小朱扉，雲壓寒空雪欲飛。',32,'全唐诗/poet.song.134000.json','["老君洞外小朱扉，雲壓寒空雪欲飛。", "結陣弓刀邊壘去，挂鞍狐兔獵場歸。"]'),
('d630f2eb-802a-4c0a-a5e2-0fd6dcd563a3','感昔七首  其七','陸游','宋','宋诗','song-poetry','','[]','少時失脚利名間，寸步何曾不險艱。',32,'全唐诗/poet.song.134000.json','["少時失脚利名間，寸步何曾不險艱。", "造物恐人渾忘却，夢中憂患尚如山。"]'),
('22e9c50f-b6da-45f4-9d69-e40d54d8d9a6','孤村','陸游','宋','宋诗','song-poetry','','[]','少年誤計落人間，晚卧孤村日掩關。',64,'全唐诗/poet.song.134000.json','["少年誤計落人間，晚卧孤村日掩關。", "小室易溫爐火省，幽窗常暗架書閑。", "梅橫籬落春初動，雲鬧川原雪尚慳。", "欲喚一藤同勝踐，恨無傑句壓溪山。"]'),
('e3315782-dac4-4881-a8ce-515f689981ca','村舍書事','陸游','宋','宋诗','song-poetry','','[]','紙窗百衲地爐紅，圍坐牛醫卜肆翁。',64,'全唐诗/poet.song.134000.json','["紙窗百衲地爐紅，圍坐牛醫卜肆翁。", "時節杯盤來往熟，朝晡鹽酪有無通。", "男丁共結春耕耦，婦女相呼夜績同。", "老子頹然最無事，客歸自策讀書功。"]'),
('cd445d81-5361-4de5-8522-1bffd860d5ef','小葺居舍','陸游','宋','宋诗','song-poetry','','[]','野水楓林下，殘年亦自存。',48,'全唐诗/poet.song.134000.json','["野水楓林下，殘年亦自存。", "刈茅支漏屋，插棘補頹垣。", "把釣襟靈爽，爭棋笑語喧。", "晚窗幽興極，共酌黍醅渾。"]'),
('f8e86683-42db-4564-8f04-9711147d6963','冬至','陸游','宋','宋诗','song-poetry','','[]','老遇陽生海上村，川雲漠漠雨昏昏。',64,'全唐诗/poet.song.134000.json','["老遇陽生海上村，川雲漠漠雨昏昏。", "鄰家祭徹初分胙，賀客泥深不到門。", "萬卷縱橫忘歲月，百年行止付乾坤。", "明朝晴霽猶堪出，南陌東阡共一樽。"]'),
('1af975b2-2352-439c-82ac-a85cf170aff5','夜坐示子遹兼示元敏','陸游','宋','宋诗','song-poetry','','[]','微霰不成雪，大風俄散雲。',48,'全唐诗/poet.song.134000.json','["微霰不成雪，大風俄散雲。", "孤燈翳還吐，斷雁遠猶聞。", "冉冉新春動，遥遥清夜分。", "兒孫未須睡，吾與汝論文。"]'),
('0722b6d9-e179-4f18-a1a3-017a3ca44c00','客懷','陸游','宋','宋诗','song-poetry','','[]','客懷病思兩凄凄，瘦馬長靴濺雪泥。',64,'全唐诗/poet.song.134000.json','["客懷病思兩凄凄，瘦馬長靴濺雪泥。", "道左忽逢曾宿驛，壁間閑看舊留題。", "村醅酸薄陳山果，旅飯蕭條嚼凍齏。", "何處人間非夢境，怳然重到劍關西。"]'),
('4464f847-7c83-417b-b5f1-5a94c040b299','雜書幽居事五首  其一','陸游','宋','宋诗','song-poetry','','[]','抱甕窮園叟，還山老布衣。',48,'全唐诗/poet.song.134000.json','["抱甕窮園叟，還山老布衣。", "死邊常得活，鬧處偶容歸。", "釣恐魚吞餌，棋憂客墮機。", "此心君會否，洗盡百年非。"]'),
('e2d49faf-8833-45a7-a0f4-5e11ac78c866','雜書幽居事五首  其二','陸游','宋','宋诗','song-poetry','','[]','淡薄齊榮辱，恢疏略怨恩。',48,'全唐诗/poet.song.134000.json','["淡薄齊榮辱，恢疏略怨恩。", "爐常養丹母，手自斲桐孫。", "炎火下照海，黄河高泝源。", "道翁來不速，一笑倒吾樽。"]'),
('e51a33f1-b99a-4855-bfe7-4213e0cb28a7','雜書幽居事五首  其三','陸游','宋','宋诗','song-poetry','','[]','庭曠多延月，齋空半貯雲。',48,'全唐诗/poet.song.134000.json','["庭曠多延月，齋空半貯雲。", "松聲行路共，泉脈近鄰分。", "采藥九蒸曝，朝真三沐熏。", "林間有叢杞，繞屋夜狺狺。"]'),
('c23b4704-686c-441e-9e2b-9e3f7f9be845','雜書幽居事五首  其四','陸游','宋','宋诗','song-poetry','','[]','貧困雖終老，胸中尚浩然。',48,'全唐诗/poet.song.134000.json','["貧困雖終老，胸中尚浩然。", "直令頭搶地，未害鼻撩天。", "種菜慳三畝，苫茅僅數椽。", "布衾常不暖，夜夜亦安眠。"]'),
('3f307745-060f-4d7a-ab36-e60f4aec5844','雜書幽居事五首  其五','陸游','宋','宋诗','song-poetry','','[]','卜筑南湖上，梅花幾度春。',48,'全唐诗/poet.song.134000.json','["卜筑南湖上，梅花幾度春。", "身緣作詩瘦，家爲買山貧。", "野步維漁艇，江樓岸醉巾。", "誰知會稽叟，不愧葛天民。"]'),
('950174b5-084b-438b-81bd-b824a561532b','題齋壁','陸游','宋','宋诗','song-poetry','','[]','門前枯葉滿荒街，堂下殘蕪擁土階。',64,'全唐诗/poet.song.134000.json','["門前枯葉滿荒街，堂下殘蕪擁土階。", "蓬蓽蕭條如旅店，豆蔬淡薄學僧齋。", "晝存真火溫枵腹，夜挽黄流灌病骸。", "喚取鄰翁同結社，它年仙去與君偕。"]'),
('065c2865-ee63-471c-a012-636fd44fbae7','探梅','陸游','宋','宋诗','song-poetry','','[]','歲月相尋豈有窮，早梅喚醒醉眠翁。',64,'全唐诗/poet.song.134000.json','["歲月相尋豈有窮，早梅喚醒醉眠翁。", "坐中酒量人人別，花底春風處處同。", "白帝城邊微雪過，青衣江上夕陽紅。", "錦囊空復殘詩在，分付悲歡一夢中。"]'),
('0bbdcb95-fd2b-4130-8709-2947eddb2696','新移竹栽喜於得雨而池中鸂鶒乃以水溢而去戲以長句記之','陸游','宋','宋诗','song-poetry','','[]','霧雨三日天沉陰，西溪水長二尺深。',64,'全唐诗/poet.song.134000.json','["霧雨三日天沉陰，西溪水長二尺深。", "土濡新竹有生意，池滿文禽無住心。", "竹根蘇活賴此雨，禽亦歸飛戲烟浦。", "去留雖異各欣然，抽萌哺子全其天。"]'),
('e76f2f7a-04d3-4c6f-8521-85736b1d9739','讀宛陵先生詩','陸游','宋','宋诗','song-poetry','','[]','李杜不復作，梅公真壯哉。',48,'全唐诗/poet.song.134000.json','["李杜不復作，梅公真壯哉。", "豈惟凡骨換，要是頂門開。", "鍛鍊無遺力，淵源有自來。", "平生解牛手，餘刃獨恢恢。"]'),
('a6739e52-d828-4864-8932-0fc2c088c1c2','勉學','陸游','宋','宋诗','song-poetry','','[]','學力艱危見，精誠夢寐知。',48,'全唐诗/poet.song.134000.json','["學力艱危見，精誠夢寐知。", "眾人雖莫察，吾道豈容欺。", "雷雨含元氣，蓍龜决大疑。", "爲儒能體此，端不負先師。"]'),
('dc4939e5-c126-4f74-b6d0-b77749bb51fc','道室試筆六首  其一','陸游','宋','宋诗','song-poetry','','[]','浮雲萬事不到眼，千歲人間心尚孩。',32,'全唐诗/poet.song.134000.json','["浮雲萬事不到眼，千歲人間心尚孩。", "屏風疊下看花落，扇子峽中聞雪來。"]'),
('41dd5a8c-fd0e-431c-8b0a-3331fad968d4','道室試筆六首  其二','陸游','宋','宋诗','song-poetry','','[]','兜羅綿雲常滿谷，勃落葉衣無四時。',32,'全唐诗/poet.song.134000.json','["兜羅綿雲常滿谷，勃落葉衣無四時。", "中原百戰血塗野，此老醉眠初不知。"]'),
('2e1918be-c646-4c56-b6c4-835a065d53b9','道室試筆六首  其三','陸游','宋','宋诗','song-poetry','','[]','事來得失若山重，放下始知前日狂。',32,'全唐诗/poet.song.134000.json','["事來得失若山重，放下始知前日狂。", "一枝藜杖一壺酒，何處人間無醉鄉。"]'),
('69b6bd9b-1354-45b6-bac0-177fcebb3c33','道室試筆六首  其四','陸游','宋','宋诗','song-poetry','','[]','吾家學道今四世，世佩施真三住銘。',32,'全唐诗/poet.song.134000.json','["吾家學道今四世，世佩施真三住銘。", "一窗蘿月照孤詠，萬壑松風吹半醒。"]'),
('8739119f-a533-403c-9167-8c4439c8df5f','道室試筆六首  其五','陸游','宋','宋诗','song-poetry','','[]','死來尚戀遊金谷，病廢猶難放柳枝。',32,'全唐诗/poet.song.134000.json','["死來尚戀遊金谷，病廢猶難放柳枝。", "等是胸中不浩浩，樂天莫笑季倫癡。"]'),
('13e32e4f-baba-4a55-b8ec-b9ac8200c222','道室試筆六首  其六','陸游','宋','宋诗','song-poetry','','[]','明明行路有神仙，世士求仙却不然。',32,'全唐诗/poet.song.134000.json','["明明行路有神仙，世士求仙却不然。", "貪冒苦多廉讓少，恐君未得盡天年。"]'),
('37129ba1-aec6-4f98-b159-10247f58112d','治心','陸游','宋','宋诗','song-poetry','','[]','治心無他法，要使百念空。',84,'全唐诗/poet.song.134000.json','["治心無他法，要使百念空。", "秋毫作其間，有若海颶風。", "颶風孰能止，三日力自窮。", "我徐躡其後，杲杲日出東。", "向來一噫者，畢竟誰爲雄。", "萬里靜海氛，一望開天容。", "會從安期生，高會蓬萊宮。"]'),
('929e89d2-4f52-468c-a3bf-fa325afaaf65','夜夢遇老人於松石間若舊嘗從其遊者再拜敘間闊老人亦酬接甚至云','陸游','宋','宋诗','song-poetry','','[]','遼海曾從化鶴丁，百年塵土污巾瓶。',64,'全唐诗/poet.song.134000.json','["遼海曾從化鶴丁，百年塵土污巾瓶。", "萬山深處遇行李，再拜起時如醉醒。", "綠樹巖前開藥笈，白驢背上指丹經。", "雲霄平步尋常事，不用求方更解形。"]'),
('03efe8d3-8091-4e0c-895f-ac5a15879c8b','過鄰家','陸游','宋','宋诗','song-poetry','','[]','病去詩情動，寒深酒戒開。',48,'全唐诗/poet.song.134000.json','["病去詩情動，寒深酒戒開。", "兒孫扶每出，鄰里喚還來。", "雲重時飛雪，春遲未見梅。", "山園多芋栗，夜話且燔煨。"]'),
('46efbb1e-21b8-4352-8f4c-c3c257f89d82','村飲','陸游','宋','宋诗','song-poetry','','[]','舊隱青山在，衰顔白髮新。',48,'全唐诗/poet.song.134000.json','["舊隱青山在，衰顔白髮新。", "推移忝前輩，疏懶似高人。", "擊鼓驅殤鬼，吹簫樂社神。", "家家皆有酒，莫吐相君茵。"]'),
('6f333674-cd84-4c5b-b433-f677033d64d7','市飲','陸游','宋','宋诗','song-poetry','','[]','學道無多事，消陰服眾魔。',48,'全唐诗/poet.song.134000.json','["學道無多事，消陰服眾魔。", "春雷驚蟄戶，海日浴鯨波。", "大勇收全勝，靈襟襲太和。", "何妨會稽市，取酒獨酣歌。"]'),
('79423b9d-2cf2-4143-81a9-956bcaa46603','社飲','陸游','宋','宋诗','song-poetry','','[]','東作初占嗣歲宜，蠶官又近乞靈時。',64,'全唐诗/poet.song.134000.json','["東作初占嗣歲宜，蠶官又近乞靈時。", "傾家釀酒無遺力，倒社迎神盡及期。", "先醉後醒驚老憊，路長足蹇嘆歸遲。", "西村漸過新塘近，宿鳥歸飛已滿枝。"]'),
('bf810630-e5ae-4c3e-a0fd-68dcc16ddd6e','舟中作','陸游','宋','宋诗','song-poetry','','[]','一葉輕舟一破裘，飄然江海送悠悠。',64,'全唐诗/poet.song.134000.json','["一葉輕舟一破裘，飄然江海送悠悠。", "閑知睡味甜如蜜，老覺羈懷淡似秋。", "失侶雲間孤雁下，耐寒波面兩鳧浮。", "年逾八十真當去，似爲雲山尚小留。"]'),
('de798674-c71b-46f2-8cdd-aa611ff6840d','風雲晝晦夜遂大雪','陸游','宋','宋诗','song-poetry','','[]','大風從北來，洶洶十萬軍。',144,'全唐诗/poet.song.134000.json','["大風從北來，洶洶十萬軍。", "草木盡偃仆，道路暝不分。", "山澤氣上騰，天受之爲雲。", "山雲如馬牛，水雲如魚黿。", "朝暗翳白日，暮重壓厚坤。", "高城岌欲動，我屋何足掀。", "兒怖床下伏，婢恐堅閉門。", "老翁兩耳聵，無地著戚欣。", "夜艾不知雪，但覺手足皸。", "布衾冷似鐵，燒糠作微溫。", "豈不思一飲，流塵暗空樽。", "已矣可奈何，凍死向孤村。"]'),
('7b6b97df-1f19-4ca2-86a6-e38f2cf62ae8','大雪','陸游','宋','宋诗','song-poetry','','[]','海天黯黯萬重雲，欲到前村路不分。',32,'全唐诗/poet.song.134000.json','["海天黯黯萬重雲，欲到前村路不分。", "烈風吹雪深一丈，大布縫衫重七斤。"]'),
('8c183caf-b78c-448e-8e5d-0aa8bf513c0b','雪夜','陸游','宋','宋诗','song-poetry','','[]','病卧湖邊五畝園，雪風一夜坼蘆藩。',64,'全唐诗/poet.song.134000.json','["病卧湖邊五畝園，雪風一夜坼蘆藩。", "燎爐薪炭衣篝暖，圍坐兒孫笑語溫。", "菜乞鄰家作菹美，酒賒近市带醅渾。", "平居自是無來客，明日衝泥誰叩門。"]'),
('efed416a-7b51-42a7-8e75-bd9597222199','雪霽','陸游','宋','宋诗','song-poetry','','[]','米盡囊空莫問渠，天公自解養迂疏。',64,'全唐诗/poet.song.134000.json','["米盡囊空莫問渠，天公自解養迂疏。", "雪泥壅路斷來客，朝日滿窗宜讀書。", "漸暖橫林聞語鳥，乍晴幽圃富嘉蔬。", "東家小蹇那須借，早晚吾兒送鹿車。"]'),
('f83c5bdd-0c9c-4c19-8ffd-31519f5e9a4d','雪後','陸游','宋','宋诗','song-poetry','','[]','雨解平簷雪，風收際海雲。',48,'全唐诗/poet.song.134000.json','["雨解平簷雪，風收際海雲。", "根蘇萱出土，冰斷水生紋。", "遊舫家家葺，行歌巷巷聞。", "太平原有象，端爲謝東君。"]'),
('a3b19518-1e89-4e4d-b49f-b7662e4b9b61','夜寒與客燒乾柴取暖戲作','陸游','宋','宋诗','song-poetry','','[]','槁竹乾薪隔歲求，正虞雪夜客相投。',64,'全唐诗/poet.song.134000.json','["槁竹乾薪隔歲求，正虞雪夜客相投。", "如傾瀲瀲蒲萄酒，似擁重重貂鼠裘。", "一睡策勳殊可喜，千金論價恐難酬。", "他時鐵馬榆關外，憶此猶當笑不休。"]'),
('2a976c5e-8c09-4ab0-9897-797f9c275304','排悶','陸游','宋','宋诗','song-poetry','','[]','殘雪融成雨，寒燈結作花。',48,'全唐诗/poet.song.134000.json','["殘雪融成雨，寒燈結作花。", "睡稀聽齧鼠，坐久送棲鴉。", "食似開僧鉢，居如寓店家。", "餘年不須問，即此是生涯。"]'),
('cc71eec5-8537-4747-a246-2e9f1db534d9','席上有舉呂居仁詩者因次其韵示坐客','陸游','宋','宋诗','song-poetry','','[]','是身如鼠穴太倉，七十始辦求深藏。',64,'全唐诗/poet.song.134000.json','["是身如鼠穴太倉，七十始辦求深藏。", "扶衰復拜求舊詔，入對講殿瞻顒昂。", "期年蒙恩許謝病，家居更辱鄉黨敬。", "今夕不醉無庸歸，此老餘年君所知。"]'),
('24ab309a-d973-4b0d-a1be-8e6a962afc7c','予使江西時以詩投政府丐湖湘一麾會召還不果偶讀舊稿有感','陸游','宋','宋诗','song-poetry','','[]','文字塵埃我自知，向來諸老誤相期。',32,'全唐诗/poet.song.134000.json','["文字塵埃我自知，向來諸老誤相期。", "揮毫留得江山助，不到瀟湘豈有詩。"]'),
('c103b2ea-6cca-45ad-ac74-bc7bbbbe328b','柳橋','陸游','宋','宋诗','song-poetry','','[]','村路初晴雪作泥，經旬不到小橋西。',32,'全唐诗/poet.song.134000.json','["村路初晴雪作泥，經旬不到小橋西。", "出門頓覺春來早，柳染輕黄已蘸溪。"]'),
('ee08f95b-9ab6-43fa-a04a-d6834b441971','鷗','陸游','宋','宋诗','song-poetry','','[]','海上輕鷗何處尋，烟波萬里信浮沉。',32,'全唐诗/poet.song.134000.json','["海上輕鷗何處尋，烟波萬里信浮沉。", "今朝忽向船頭見，消盡平生得喪心。"]'),
('6e3f3130-6bfb-4395-aa0a-99269b0e7e5b','鷺','陸游','宋','宋诗','song-poetry','','[]','雪霽春回亦樂哉，棋軒正對小灘開。',32,'全唐诗/poet.song.134000.json','["雪霽春回亦樂哉，棋軒正對小灘開。", "翩翩飛鷺真吾友，肯爲幽人一再來。"]'),
('d873199d-1982-4bd1-ae62-263f4cfbdd2a','感物','陸游','宋','宋诗','song-poetry','','[]','日落烏將數子歸，風和雉挾兩雌飛。',32,'全唐诗/poet.song.134000.json','["日落烏將數子歸，風和雉挾兩雌飛。", "不如村舍安孤寂，父子飄然兩褐衣。"]'),
('e24f215c-edbc-4f8c-8bd8-183726633ef5','甲子歲暮','陸游','宋','宋诗','song-poetry','','[]','世間巧拙亦何施，萬事難禁歲月移。',32,'全唐诗/poet.song.134000.json','["世間巧拙亦何施，萬事難禁歲月移。", "遲死幾時天有意，要令自悟不須師。"]'),
('c1cbe57a-7456-46ba-b59d-2031feb35c54','出遊至僧舍及逆旅戲贈絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','山僧邂逅即情親，野叟留連語更真。',32,'全唐诗/poet.song.134000.json','["山僧邂逅即情親，野叟留連語更真。", "淡淡論交端有味，一彈指頃百年身。"]'),
('957b4f30-26d8-48d9-9633-82c29a804f03','出遊至僧舍及逆旅戲贈絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','飯炊適熟如延客，犬喜來迎似到家。',32,'全唐诗/poet.song.134000.json','["飯炊適熟如延客，犬喜來迎似到家。", "雨滴茅簷草烟溼，不妨笑語暫喧譁。"]'),
('718c129a-7d5d-4456-af02-a6bd8639d5ac','歲暮出遊','陸游','宋','宋诗','song-poetry','','[]','殘曆消磨無半紙，一年光景又成非。',64,'全唐诗/poet.song.134000.json','["殘曆消磨無半紙，一年光景又成非。", "瓦溝雪水滴欲盡，江路梅花開尚稀。", "竹院篝燈留度宿，旗亭誇酒勸無歸。", "此身自笑知何似，萬里遼天一鶴飛。"]'),
('edc9519d-4323-4f5b-937e-68f6497f6c0a','出遊所至皆欣然相迎口占示之','陸游','宋','宋诗','song-poetry','','[]','寓館兼山澤，行裝半雨晴。',48,'全唐诗/poet.song.134000.json','["寓館兼山澤，行裝半雨晴。", "隨宜分藥物，投老惜人情。", "邂逅成新識，殷勤講舊盟。", "農家尤可念，迎勞輟春耕。"]'),
('b7816c82-5ab4-401a-80b3-9bc5cff57dde','題旅舍壁','陸游','宋','宋诗','song-poetry','','[]','老子殘年未易量，出門隨處得彷徉。',64,'全唐诗/poet.song.134000.json','["老子殘年未易量，出門隨處得彷徉。", "窗欞日淡僧房暖，竈突烟青旅甑香。", "濁酒可求敲野店，舊題猶在拂頹牆。", "閑來又取丹經讀，夜就松明解布囊。"]'),
('70c65d32-1e8a-48ce-b46a-a21f2d22f729','野人舍小飲','陸游','宋','宋诗','song-poetry','','[]','梅市波光遠，柯橋柳色新。',48,'全唐诗/poet.song.134000.json','["梅市波光遠，柯橋柳色新。", "百年情分熟，數酌笑言親。", "沙上人爭渡，街頭婦賣薪。", "鼕鼕隔林鼓，歲暮賽江神。"]'),
('bd28ca19-334c-48d0-84ab-8b611ef18357','自近村歸','陸游','宋','宋诗','song-poetry','','[]','雪晴村路尚殘泥，茅屋清寒正要低。',64,'全唐诗/poet.song.134000.json','["雪晴村路尚殘泥，茅屋清寒正要低。", "野渡船虛飛鳥集，烟村路近蹇驢嘶。", "堅頑那復愁空橐，老健猶能伴架犁。", "蹴榻不僵君會否，更須百甕享黄齏。"]'),
('71cc8481-a970-49b6-b4a3-1e8a4ff57153','夢華山','陸游','宋','宋诗','song-poetry','','[]','古松偃蹇谷谽谺，太華峰前野老家。',32,'全唐诗/poet.song.134000.json','["古松偃蹇谷谽谺，太華峰前野老家。", "久客未歸丹竈冷，碧桃八十一番花。"]'),
('51803f59-61f7-4f4a-a132-2e7dffa40175','歲暮與鄰曲飲酒用前輩獨酌韵','陸游','宋','宋诗','song-poetry','','[]','出會稽南門，九里有聚落。',120,'全唐诗/poet.song.134000.json','["出會稽南門，九里有聚落。", "雖非衣冠區，農圃可共酌。", "野實雜甘酸，草具無厚薄。", "小童能擊筑，一笑相與樂。", "徒手出叢花，空中取丸藥。", "主禮雖可笑，眾客亦起酢。", "聊持綴宿好，未用嘲淡泊。", "窮達則不同，亦踐真率約。", "予年過八十，故物但城郭。", "作詩寄清歡，未愧華表鶴。"]'),
('961e21c6-092c-4de6-8fa7-ec372e24f2ed','山中飲酒','陸游','宋','宋诗','song-poetry','','[]','百屋堆金錢，萬戶封公侯。',96,'全唐诗/poet.song.134000.json','["百屋堆金錢，萬戶封公侯。", "富貴人所羨，熟計終繆悠。", "有酒君但飲，有山君但遊。", "雖云亦夢事，要是勝一籌。", "獨醉新豐市，遺魂招馬周。", "清嘯蘇門山，曠度交公休。", "爛爛目如電，凜凜氣愈遒。", "騎鯨歸東海，已矣吾何求。"]'),
('add7930f-4b90-4c42-8434-7b224b8c7cdf','客亭','陸游','宋','宋诗','song-poetry','','[]','荻浦烟汀並海涯，一枝柔櫓語咿啞。',64,'全唐诗/poet.song.134000.json','["荻浦烟汀並海涯，一枝柔櫓語咿啞。", "久從野老非生客，慣寓僧廬勝在家。", "乘興村村俱有酒，逢春處處可尋花。", "朝來雪霽梅初動，又向郵亭閱歲華。"]'),
('c952c9e1-58da-48cf-9a07-4488f9ada697','除夜','陸游','宋','宋诗','song-poetry','','[]','野水楓林屋數椽，寒爐無火坐無氈。',64,'全唐诗/poet.song.134000.json','["野水楓林屋數椽，寒爐無火坐無氈。", "殘燈耿耿愁孤影，小雪霏霏送舊年。", "椒酒辟瘟傾瀲灧，藍袍俘鬼舞跰躚。", "從今供養惟春薺，莫羨愚公日萬錢。"]'),
('b4cd5688-9020-4296-a8cf-9b2470a2bb97','乙丑元日','陸游','宋','宋诗','song-poetry','','[]','好在屠蘇酒，扶衰把一卮。',48,'全唐诗/poet.song.134000.json','["好在屠蘇酒，扶衰把一卮。", "家貧爲壽略，曆閏換年遲。", "薦廟須扶拜，題門强綴詩。", "惟思買春困，熟睡過花時。"]'),
('97390061-990b-4537-99c7-a4a64f196924','元日讀易','陸游','宋','宋诗','song-poetry','','[]','伏羲三十餘萬歲，傳者太山一毫芒。',64,'全唐诗/poet.song.134000.json','["伏羲三十餘萬歲，傳者太山一毫芒。", "春秋雖自魯麟絕，禮樂蓋先秦火亡。", "孟軻財能道封建，孔子已不言鴻荒。", "於虖易學幸未泯，安得名山處處藏。"]'),
('59d7a08d-594c-42a8-aadf-2dfca064f1e0','自開歲陰雨連日未止','陸游','宋','宋诗','song-poetry','','[]','江雲漠漠雨昏昏，歸老山陰學灌園。',64,'全唐诗/poet.song.134000.json','["江雲漠漠雨昏昏，歸老山陰學灌園。", "十里羊腸僅通路，三家鐺脚自成村。", "應時餺飥聊從俗，耐久鍾馗儼在門。", "近縣傳聞頗多盜，呼兒插棘補頹垣。"]'),
('66081f48-19db-4102-8a94-483fba391965','枯菊二首  其一','陸游','宋','宋诗','song-poetry','','[]','翠羽金錢夢已闌，空餘殘蕊抱枝乾。',32,'全唐诗/poet.song.134000.json','["翠羽金錢夢已闌，空餘殘蕊抱枝乾。", "紛紛輕薄隨流水，黄與姚花一樣看。"]'),
('751c70aa-072a-4473-945b-dd6e105dd232','枯菊二首  其二','陸游','宋','宋诗','song-poetry','','[]','積雪嚴霜轉眼空，春回無處不春風。',32,'全唐诗/poet.song.134000.json','["積雪嚴霜轉眼空，春回無處不春風。", "欲知造物無窮妙，但看萱根與菊叢。"]'),
('767b6887-6a02-4b48-a496-e62f4efd891e','村舍雜興五首  其一','陸游','宋','宋诗','song-poetry','','[]','冉冉年華速，昏昏睡思濃。',48,'全唐诗/poet.song.134000.json','["冉冉年華速，昏昏睡思濃。", "廢書心自愧，謝病客能容。", "雨急鐘微度，溪湍碓自舂。", "可憐燈下影，隨處伴衰慵。"]'),
('42a90bae-db5c-43fc-a682-50554e707d96','村舍雜興五首  其二','陸游','宋','宋诗','song-poetry','','[]','堅卧非由病，端居不是齋。',48,'全唐诗/poet.song.134000.json','["堅卧非由病，端居不是齋。", "世情元自薄，人事固多乖。", "晨飯炊稊米，宵行點豆䕸。", "昔人言可用，第一忌安排。"]'),
('42e93e29-4fef-41c0-90f5-b3157e46ea8a','村舍雜興五首  其三','陸游','宋','宋诗','song-poetry','','[]','白首返吾鄉，功名罷激昂。',48,'全唐诗/poet.song.134000.json','["白首返吾鄉，功名罷激昂。", "掃除魔眷屬，砭熨病膏肓。", "老圃勤供菜，蠻童解炷香。", "黄昏那用問，且喜日舒長。"]'),
('12315536-9e35-4711-900e-ac7098dd1a54','村舍雜興五首  其四','陸游','宋','宋诗','song-poetry','','[]','粥罷重投枕，燈殘起讀書。',48,'全唐诗/poet.song.134000.json','["粥罷重投枕，燈殘起讀書。", "閉門常自得，作計更誰如。", "箭茁白於玉，椶花長比魚。", "盤餐有此味，勿怪食無餘。"]'),
('344e5775-6dd7-4868-96ee-f7ddab3df3a7','村舍雜興五首  其五','陸游','宋','宋诗','song-poetry','','[]','遊宦風波惡，還家日月長。',48,'全唐诗/poet.song.134000.json','["遊宦風波惡，還家日月長。", "厭煩思病忘，避俗欲陽狂。", "絕意功名會，收身翰墨場。", "著書吾豈敢，尚可述農桑。"]'),
('6427e47e-0589-45c0-bf6f-d7bc39f36d20','夜興','陸游','宋','宋诗','song-poetry','','[]','窮巷行人絕，高城漏鼓稀。',48,'全唐诗/poet.song.134000.json','["窮巷行人絕，高城漏鼓稀。", "劇談頻翦燭，久坐旋更衣。", "饑鼠衝人過，啼鴉冒夜飛。", "客歸吾未睡，孤影自相依。"]'),
('5c937063-2201-4bc3-9a10-9a006e4ebae4','示鄰曲','陸游','宋','宋诗','song-poetry','','[]','北陌東阡好弟兄，耄年幸復主齊盟。',64,'全唐诗/poet.song.134000.json','["北陌東阡好弟兄，耄年幸復主齊盟。", "同嘗春韭秋菘味，共聽朝猿夜鶴聲。", "百世不忘耕稼業，一壺時敘里閭情。", "諸孫識字吾真足，安用鵬摶九萬程。"]'),
('2dcdb115-4322-4287-a9ee-95f31c29ebfd','夢中作','陸游','宋','宋诗','song-poetry','','[]','華山敷水本閑人，一念無端墮世塵。',32,'全唐诗/poet.song.134000.json','["華山敷水本閑人，一念無端墮世塵。", "八十餘年多少事，藥爐丹竈尚如新。"]'),
('893a8c9b-ca07-4032-8130-0f9b68ebb5d6','春雨','陸游','宋','宋诗','song-poetry','','[]','倚闌正爾受斜陽，細雨霏霏渡野塘。',64,'全唐诗/poet.song.134000.json','["倚闌正爾受斜陽，細雨霏霏渡野塘。", "本爲柳枝留淺色，却教梅蕊洗幽香。", "小霑蝶粉初何惜，暫澀鶯聲亦未妨。", "造物無心寧遍物，憑誰閑與問東皇。"]'),
('5e82db79-60fd-4bc9-bcda-f9b0c37692d5','草堂','陸游','宋','宋诗','song-poetry','','[]','幸有湖邊舊草堂，敢煩地主筑林塘。',64,'全唐诗/poet.song.134000.json','["幸有湖邊舊草堂，敢煩地主筑林塘。", "漉殘醅甕葛巾溼，插遍野梅紗帽香。", "風緊春寒那可敵，身閑晝漏不勝長。", "浩歌陌上君無怪，世譜推原自楚狂。"]'),
('4a1c1bd0-2824-46b2-8acd-24dde881f2cd','道室','陸游','宋','宋诗','song-poetry','','[]','筮遇風山第六爻，翛然盡謝俗間交。',64,'全唐诗/poet.song.134000.json','["筮遇風山第六爻，翛然盡謝俗間交。", "謀生舊買雲三頃，託宿新分鶴半巢。", "露下丹芽生藥壟，月明金粉落松梢。", "眉間喜動君知否，借得丹經手自抄。"]'),
('fa28de21-f935-4ef6-8764-579b84357a55','旅次有贈','陸游','宋','宋诗','song-poetry','','[]','黄鶴樓前逢劍客，青衣江口見詩人。',64,'全唐诗/poet.song.134000.json','["黄鶴樓前逢劍客，青衣江口見詩人。", "天涯莫起漂零感，物外終爲自在身。", "賣馬求船雖少日，阻風中酒動兼旬。", "中原早晚胡塵靜，緱月嵩雲要卜鄰。"]'),
('4af82172-969b-461a-8c42-21c46154570b','雜感五首以不愛入州府爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','莘渭二老人，耕釣俱白首。',96,'全唐诗/poet.song.134000.json','["莘渭二老人，耕釣俱白首。", "功烈在人間，如天有北斗。", "方其未遇時，自處固不苟。", "夫豈邀虛名，欲眩千載後。", "降及秦漢王，望古猶培塿。", "猶能守所聞，外物不得誘。", "君看魯二生，亦豈聖人偶。", "凜然諸儒間，人可我獨不。"]'),
('058a6225-9323-4425-88e3-ff137c817a23','雜感五首以不愛入州府爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','山棲天與癖，酒復甚所愛。',96,'全唐诗/poet.song.134000.json','["山棲天與癖，酒復甚所愛。", "雖云慚黄綺，亦慕嵇阮輩。", "失脚落人間，二事略皆廢。", "晚歸卧雲壑，謂此在券內。", "如何疾屢作，大與初意背。", "好山雖在眼，動步輒有礙。", "酒戒復堅持，如堤憂蟻潰。", "何以遣餘年，閉戶淡煮菜。"]'),
('a992746b-49ad-46e9-babd-fccfff4b158a','雜感五首以不愛入州府爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','鷽鳩搶榆枋，枯魚過河泣。',96,'全唐诗/poet.song.134000.json','["鷽鳩搶榆枋，枯魚過河泣。", "鵬鯤九萬里，此豈汝所及。", "丈夫志古人，絕世而獨立。", "遠遊馬蹄穿，高卧劍鋒澀。", "其初所抱負，固自高嶪岌。", "安能與兒曹，俯首就維縶。", "君看折腰趨，孰若舉手揖。", "芝老尚可餐，修門戒輕入。"]'),
('91d2d423-02d1-416a-a24b-50862492efd6','雜感五首以不愛入州府爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','洚水初平時，草木充九州。',96,'全唐诗/poet.song.134000.json','["洚水初平時，草木充九州。", "禽獸孳育繁，與人爲敵讎。", "于時聖人作，日夜爲民憂。", "思有以勝之，食肉而服裘。", "然後人奠居，禾黍歲有秋。", "豈知千載後，戕殺無時休。", "一食刀机赤，百味供膳羞。", "豪侈方相誇，哀哉非始謀。"]'),
('d2d7330a-f349-46ec-9232-6f89d3f13380','雜感五首以不愛入州府爲韵  其五','陸游','宋','宋诗','song-poetry','','[]','我年甫三十，出身事明主。',96,'全唐诗/poet.song.134000.json','["我年甫三十，出身事明主。", "狂愚斥不用，晚辟征西府。", "蹭蹬過錦城，邂逅客嚴武。", "十年醉郫筒，陽狂頗自許。", "青城訪隱翁，西市買幽圃。", "如何復不遂，歸聽鏡湖雨。", "結廬三間茅，泛宅一枝櫓。", "天真儻可全，吾其老烟浦。"]'),
('ac6b8ce5-2529-45c2-ae0e-f6a329557368','自詠絕句八首  其一','陸游','宋','宋诗','song-poetry','','[]','雙鬢蕭條失故青，躬耕猶得養餘齡。',32,'全唐诗/poet.song.134000.json','["雙鬢蕭條失故青，躬耕猶得養餘齡。", "明時恩大無由報，欲爲鄉鄰講孝經。"]'),
('daca97a3-b781-4d94-959a-c7d312ad82a5','自詠絕句八首  其二','陸游','宋','宋诗','song-poetry','','[]','深村人有結繩風，晚歲身爲带索翁。',32,'全唐诗/poet.song.134000.json','["深村人有結繩風，晚歲身爲带索翁。", "啜粥茹蔬茅屋底，誰知也過百年中。"]'),
('8d35a54f-7934-4d90-aad2-8201329b1057','自詠絕句八首  其三','陸游','宋','宋诗','song-poetry','','[]','不淪鬼錄不登仙，遊戲杯觴近百年。',32,'全唐诗/poet.song.134000.json','["不淪鬼錄不登仙，遊戲杯觴近百年。", "小市跨驢寒日裏，任教人作畫圖傳。"]'),
('c08bad34-155d-40e3-a9e2-ec3b299752a1','自詠絕句八首  其四','陸游','宋','宋诗','song-poetry','','[]','逆旅門前撥不開，先生醉策蹇驢來。',32,'全唐诗/poet.song.134000.json','["逆旅門前撥不開，先生醉策蹇驢來。", "未言乞得囊中藥，一見童顔且壓災。"]'),
('950916fa-c68c-4238-ab59-c94d7df88696','自詠絕句八首  其五','陸游','宋','宋诗','song-poetry','','[]','遠遊索手不赍糧，薪米臨時取道傍。',32,'全唐诗/poet.song.134000.json','["遠遊索手不赍糧，薪米臨時取道傍。", "今日晴明行亦好，經旬風雨住何妨。"]'),
('38f1ff6e-6403-4f5f-a303-3cbca6a99d7a','自詠絕句八首  其六','陸游','宋','宋诗','song-poetry','','[]','一條紙被平生足，半碗藜羹百味全。',32,'全唐诗/poet.song.134000.json','["一條紙被平生足，半碗藜羹百味全。", "放下元來總無事，雞鳴犬吠送殘年。"]'),
('5de868e1-aabb-4514-9d33-ba93763f3fa0','自詠絕句八首  其七','陸游','宋','宋诗','song-poetry','','[]','平生寧獨愛吾廬，何處茅簷不可居。',32,'全唐诗/poet.song.134000.json','["平生寧獨愛吾廬，何處茅簷不可居。", "晝闕僮奴停接客，夜無膏火罷觀書。"]'),
('a8a673bc-a73f-418d-baf3-63c039a68e3e','自詠絕句八首  其八','陸游','宋','宋诗','song-poetry','','[]','睡著何曾厭夜長，老人少睡坐何傷。',32,'全唐诗/poet.song.134000.json','["睡著何曾厭夜長，老人少睡坐何傷。", "無燈無火春寒惡，破絮粗氈即道場。"]'),
('35c1c235-fd64-4b8e-9856-b0e2fc583e7a','風月吟','陸游','宋','宋诗','song-poetry','','[]','去日如馳衰有驗，萬事惟當就收斂。',96,'全唐诗/poet.song.134000.json','["去日如馳衰有驗，萬事惟當就收斂。", "可憐未與酒相忘，風月婆娑猶不厭。", "有時清夜行中庭，幅巾藜杖影竛竮。", "松風十里吹殘夢，蘿月三更照半醒。", "河傾雞唱吟未已，爽透髮根清入齒。", "晨光底事不貸人，轆轤汲水啼鴉起。"]'),
('99dcd67c-df75-4da9-914b-97ce824fca32','年光','陸游','宋','宋诗','song-poetry','','[]','無賴年光逐水流，人間隨處送悠悠。',64,'全唐诗/poet.song.134000.json','["無賴年光逐水流，人間隨處送悠悠。", "千帆落浦湘天晚，孤笛吟風鄠縣秋。", "小市鶯花時痛飲，故宮禾黍亦閑愁。", "久留只恐驚凡目，又向西凉上酒樓。"]'),
('6ca7fb5b-a332-42d1-9f9f-c4076793d1bf','龜堂','陸游','宋','宋诗','song-poetry','','[]','莫笑龜堂陋，生涯實有餘。',48,'全唐诗/poet.song.134000.json','["莫笑龜堂陋，生涯實有餘。", "春寒擁重褐，晨飯富藏蔬。", "薄技雕蟲爾，虛名畫餅如。", "兒時論語在，敢負此心初。"]'),
('62836fe2-ec1c-4704-b4d6-b8e8c5e6fe87','春晴','陸游','宋','宋诗','song-poetry','','[]','春如人易老，愁與漏俱長。',48,'全唐诗/poet.song.134000.json','["春如人易老，愁與漏俱長。", "酒著多思睡，花熏直欲狂。", "新晴乾蝶翅，微暖滑鶯吭。", "誰見龜堂叟，搘藤送夕陽。"]'),
('ae23c9c9-f1bc-46ee-9237-fd233cc57137','閉門二首  其一','陸游','宋','宋诗','song-poetry','','[]','殘髮凋零不滿巾，閉門聊得養天真。',64,'全唐诗/poet.song.134000.json','["殘髮凋零不滿巾，閉門聊得養天真。", "恐傷藥草停除地，爲惜松槎禁伐薪。", "獨木架成新略彴，一峰買得小嶙峋。", "蕭然便覺渾無事，談笑時時過近鄰。"]'),
('0193ec76-fa17-45cb-8aba-f38f3631c80e','閉門二首  其二','陸游','宋','宋诗','song-poetry','','[]','衰疾厭厭不易醫，閉門惟與睡相宜。',64,'全唐诗/poet.song.134000.json','["衰疾厭厭不易醫，閉門惟與睡相宜。", "狂曾忤物慵迎客，瘦不勝衣悔作詩。", "數簡隱書忘世味，半甌春茗過花時。", "寂寥終歲君無誚，正是幽居一段奇。"]'),
('cd74133f-d4aa-4d1b-827d-939893ceac9c','有所感','陸游','宋','宋诗','song-poetry','','[]','世事真成風馬牛，細思愈覺此生浮。',64,'全唐诗/poet.song.134000.json','["世事真成風馬牛，細思愈覺此生浮。", "舊交散後知心少，行路難來出戶愁。", "氣節陵夷誰獨立，文章衰壞正橫流。", "魯中狂士今安有，泪盡朱雲草滿丘。"]'),
('191920b6-14cb-427f-ac24-d49566eaac6d','八十一吟','陸游','宋','宋诗','song-poetry','','[]','八十古云耄，吾今不啻過。',48,'全唐诗/poet.song.134000.json','["八十古云耄，吾今不啻過。", "山程兩芒屩，水宿一漁蓑。", "雞唱劉琨舞，牛疲甯戚歌。", "春寒欺短褐，將奈此翁何。"]'),
('905e45cf-1aee-49e7-8e56-8e554b71c709','高吟','陸游','宋','宋诗','song-poetry','','[]','食少支撐惟恃粥，力衰舉動輒須人。',32,'全唐诗/poet.song.134000.json','["食少支撐惟恃粥，力衰舉動輒須人。", "誰知造物猶遺漏，擁鼻高吟又一春。"]'),
('e9c497a8-2d43-4391-b7af-ad749c5a276b','湖上作','陸游','宋','宋诗','song-poetry','','[]','耳目聰明手足輕，應酬幽事未忘情。',64,'全唐诗/poet.song.134000.json','["耳目聰明手足輕，應酬幽事未忘情。", "百年日向漁樵過，千里雲從几席生。", "樽酒每招鄰父共，圖書時與小兒評。", "但餘烟水無儔侶，堪笑沙鷗欲抗衡。"]'),
('39cdfc95-fec3-4463-a32a-57b10d5549fa','賞花','陸游','宋','宋诗','song-poetry','','[]','湖上花光何處尋，朱朱白白自成林。',64,'全唐诗/poet.song.134000.json','["湖上花光何處尋，朱朱白白自成林。", "衰年何預傷春事，閑客猶懷愛物心。", "欲墮每愁風驟起，正開却要日微陰。", "蘭亭禹廟平生事，一榼芳醪莫厭深。"]'),
('c43525aa-551a-4030-a9a1-0179e5c4d6f6','園廬','陸游','宋','宋诗','song-poetry','','[]','天假殘年使荷鉏，白頭父子守園廬。',64,'全唐诗/poet.song.134000.json','["天假殘年使荷鉏，白頭父子守園廬。", "四朝曾遇千齡會，七世相傳一束書。", "物理從來多倚伏，人情莫遣得親疏。", "功名自有英雄了，吾輩惟當憶遂初。"]'),
('0d5ad960-48ab-4c48-9ed4-a66db56b9e5d','乍晴行西村','陸游','宋','宋诗','song-poetry','','[]','堤樹叢祠北，烟村古埭南。',48,'全唐诗/poet.song.134000.json','["堤樹叢祠北，烟村古埭南。", "買魚論木盎，挑薺滿荆籃。", "積潦經旬月，晴光見二三。", "農功殊可念，保麥復祈蠶。"]'),
('cf087859-c10d-4784-8a81-81c57085ccb0','書嘆','陸游','宋','宋诗','song-poetry','','[]','塵甑炊畬粟，羸僮策蹇驢。',48,'全唐诗/poet.song.134000.json','["塵甑炊畬粟，羸僮策蹇驢。", "自從行卷日，直至挂冠餘。", "揣分元知止，求官實抱虛。", "園蔬幸無恙，父子日携鋤。"]'),
('e15ddf92-3371-4ed6-8cfd-2afbfd2e3bac','新製小冠二首  其一','陸游','宋','宋诗','song-poetry','','[]','淺醉微吟獨倚闌，輕雲淡月不多寒。',32,'全唐诗/poet.song.134000.json','["淺醉微吟獨倚闌，輕雲淡月不多寒。", "悠然顧影成清嘯，新製栟櫚二寸冠。"]'),
('082f7616-dd3f-4283-9fc7-d9971a3f3022','新製小冠二首  其二','陸游','宋','宋诗','song-poetry','','[]','栟櫚冠子輕宜髮，綀布單衣爽辟塵。',32,'全唐诗/poet.song.134000.json','["栟櫚冠子輕宜髮，綀布單衣爽辟塵。", "縱不能詩亦堪畫，年餘八十水雲身。"]'),
('c9c73ffa-72b5-498d-8b4d-f1cb7090637c','書逆旅壁','陸游','宋','宋诗','song-poetry','','[]','市遠過三里，店孤無四鄰。',48,'全唐诗/poet.song.134000.json','["市遠過三里，店孤無四鄰。", "窄纔容一客，久或住經旬。", "病嫗求風藥，樵兒饋爨薪。", "人情愈諳熟，來往不辭頻。"]'),
('d45b13ca-22f9-4b73-a490-e616c1acd199','倚樓二首  其一','陸游','宋','宋诗','song-poetry','','[]','曲曲闌干縹緲間，哦詩本欲破除閑。',32,'全唐诗/poet.song.134000.json','["曲曲闌干縹緲間，哦詩本欲破除閑。", "無端又起天涯感，淡墨生綃數點山。"]'),
('10d17423-ebf8-4673-a645-955ed4123003','倚樓二首  其二','陸游','宋','宋诗','song-poetry','','[]','樓上憑闌小立時，淡烟漠漠雨絲絲。',32,'全唐诗/poet.song.134000.json','["樓上憑闌小立時，淡烟漠漠雨絲絲。", "年光日日有佳處，不解春寒偏入詩。"]'),
('dd18a178-0521-4a60-9aaf-e1de47c21dfb','小雨','陸游','宋','宋诗','song-poetry','','[]','小雨明復暗，餘寒去又來。',48,'全唐诗/poet.song.134000.json','["小雨明復暗，餘寒去又來。", "新苔緣砌上，殘杏過籬開。", "垂老身餘幾，逢春心尚孩。", "江天近寒食，林外過輕雷。"]'),
('bf9a1598-06c1-44ea-bd98-c12a90b2e6f9','書嘆','陸游','宋','宋诗','song-poetry','','[]','無能自號癡頑老，尚健人驚矍鑠翁。',64,'全唐诗/poet.song.134000.json','["無能自號癡頑老，尚健人驚矍鑠翁。", "未向松根藏病骨，尚尋花底醉春風。", "翩翩孤影如歸鶴，冉冉流年付斷蓬。", "曾謁高皇識隆準，傷心無復一人同。"]'),
('a8974881-7fd8-4f1c-aaa9-74023057b3bd','遷雞柵歌','陸游','宋','宋诗','song-poetry','','[]','烏雞買來逾歲年，庭中赤幘何昂然。',128,'全唐诗/poet.song.134000.json','["烏雞買來逾歲年，庭中赤幘何昂然。", "吾孫初生畏晨唱，家人共議欲汝捐。", "鳥窮必啄奴豈憚，雞賣將烹吾所憐。", "貴人賤畜雖古訓，物理寧不思兩全。", "舊棲况亦苦沮洳，新柵幸可圖完堅。", "東園稍去房奧遠，挾雌將雛從此遷。", "竹簞朝暮有餘粒，瓦缶亦自盛清泉。", "喈喈風雨守汝職，腷膊勿恤驚吾眠。"]'),
('cfd17bc1-8904-4630-9b4f-a0b9f3367717','春興','陸游','宋','宋诗','song-poetry','','[]','暖靄催桑眼，晴光長草心。',48,'全唐诗/poet.song.134000.json','["暖靄催桑眼，晴光長草心。", "沙平看卧犢，密葉聽鳴禽。", "買酒貧爲祟，登山病不禁。", "終年惟一褐，捫虱又春深。"]'),
('74d4d7be-d888-4b22-ba32-0eb508cc95fc','小園','陸游','宋','宋诗','song-poetry','','[]','蕭散遺塵事，栽培得小園。',48,'全唐诗/poet.song.134000.json','["蕭散遺塵事，栽培得小園。", "土鬆花意活，林暖鳥言繁。", "餐酪供晨鉢，葅芹薦晚樽。", "餘年君莫問，送老向孤村。"]'),
('388cdf06-5359-4129-947d-e7b511dd9fa3','二月晦日夜夢欲卜居近邑道遇老父告以不利欣然從之','陸游','宋','宋诗','song-poetry','','[]','夢中行卜居，道遇白髯叟。',72,'全唐诗/poet.song.134000.json','["夢中行卜居，道遇白髯叟。", "一面出苦言，戒我棄勿取。", "人之生實難，失脚墮虎口。", "我深感其言，解衣奉杯酒。", "豈知立談間，得此直諒友。", "起坐心茫然，天闊樓挂斗。"]'),
('6c665fd4-ede0-4775-9224-0b4dff47c2b5','新晴','陸游','宋','宋诗','song-poetry','','[]','苦雨幾終月，新晴喜夕陽。',48,'全唐诗/poet.song.134000.json','["苦雨幾終月，新晴喜夕陽。", "扶行呼稚子，隨意下茅堂。", "草茂知麞健，巢新覺燕忙。", "興闌歸亦好，袖手獨焚香。"]'),
('2d5e7c54-4e4e-46ba-b539-4b5f3d557824','病中作','陸游','宋','宋诗','song-poetry','','[]','苦雨侵衰骨，餘寒著弊裘。',48,'全唐诗/poet.song.134000.json','["苦雨侵衰骨，餘寒著弊裘。", "病多辭社飲，貧甚輟春遊。", "日日親蔬圃，時時弄釣舟。", "回頭語造物，與子兩無求。"]'),
('2fe90d9c-f119-42cb-b000-c77f8065a48f','示子遹','陸游','宋','宋诗','song-poetry','','[]','敢恨吾生後聖賢，六經雖缺尚成編。',64,'全唐诗/poet.song.134000.json','["敢恨吾生後聖賢，六經雖缺尚成編。", "本來堯舜身親見，孰謂丘軻道不傳。", "妙理豈求逢掖外，淳風寧在結繩前。", "此身未死還堪勉，更伴吾兒學數年。"]'),
('95e2704c-f911-4c1a-b233-3903c921c046','窮居','陸游','宋','宋诗','song-poetry','','[]','羸病無時已，窮居只自悲。',48,'全唐诗/poet.song.134000.json','["羸病無時已，窮居只自悲。", "巾偏非雨墊，衣弊豈塵緇。", "米盡時炊稗，樽空慣啜漓。", "逐貧雖有賦，乞食未成詩。"]'),
('152dda2b-d666-403d-8340-cacb4bfe3318','春晚自近村歸','陸游','宋','宋诗','song-poetry','','[]','山陰道上柳如絲，策蹇悠悠信所之。',64,'全唐诗/poet.song.134000.json','["山陰道上柳如絲，策蹇悠悠信所之。", "曲水已過修禊集，餘寒不減試燈時。", "貧猶自力常謀醉，病不能閑日賦詩。", "誰道茅簷苦幽獨，一鈎新月是相知。"]'),
('7864fa99-690a-4788-a05a-6f9c6c3db82f','開孫滿月','陸游','宋','宋诗','song-poetry','','[]','夜夢奇童拜且言，今乃幸得生高門。',64,'全唐诗/poet.song.134000.json','["夜夢奇童拜且言，今乃幸得生高門。", "夢後一日得開孫，虎兒墮地百獸奔。", "未論頭角與眉宇，但聽啼聲誰敢侮。", "就令長大未必奇，亦作人間孔文舉。"]'),
('468e9571-9aee-4893-b74f-5a74dfa82094','小筑','陸游','宋','宋诗','song-poetry','','[]','西郊小筑臨烟汀，南山秀色入窗欞。',98,'全唐诗/poet.song.134000.json','["西郊小筑臨烟汀，南山秀色入窗欞。", "朝鐘暮鼓在何許，乃是會稽山陰之蘭亭。", "堂中老人白鬚鬢，手扶藤杖垂九齡。", "客來不語坐至夕，往者絕物今忘形。", "牆隅老雞新樹柵，長號催上東方星。", "老人亦起穿兩屨，巖泉漱齒讀黄庭。"]'),
('97d2a177-82c1-4deb-a1ee-8c7958605a95','春晚嘆','陸游','宋','宋诗','song-poetry','','[]','一風已快晴，微雲復成雨。',72,'全唐诗/poet.song.134000.json','["一風已快晴，微雲復成雨。", "盛麗女郎花，坐看委泥土。", "蜂房蜜已熟，科斗生兩股。", "堂堂一年春，結束聽杜宇。", "老夫久卧疾，乃復健如許。", "便當裹米粣，爛醉作端午。"]'),
('c39537e3-5ce0-4747-8ced-437877bdfb53','鴟鴉','陸游','宋','宋诗','song-poetry','','[]','翩然一鴉升，倏爾一鴟下。',72,'全唐诗/poet.song.134000.json','["翩然一鴉升，倏爾一鴟下。", "非惟飽殘餘，亦可免彈射。", "巡簷攫脯脩，入舍掠膾炙。", "嗟汝無盈厭，坐是取驅嚇。", "物情貴能改，一眚亦可貰。", "併語黄雀群，勿輕敗吾稼。"]'),
('ba7912e6-7507-456b-92ac-f6e140bf8208','舍東四詠 疏籬','陸游','宋','宋诗','song-poetry','','[]','數掩圍柴荆，王維畫不成。',24,'全唐诗/poet.song.134000.json','["數掩圍柴荆，王維畫不成。", "尤憐月中影，特地起詩情。"]'),
('9718acc7-ee2f-4e9c-88a8-9662842f5c16','舍東四詠 松棚','陸游','宋','宋诗','song-poetry','','[]','松棚尋丈地，客至共開顔。',24,'全唐诗/poet.song.134000.json','["松棚尋丈地，客至共開顔。", "堪笑杜陵老，坐思千萬間。"]'),
('3dc6943a-bfb9-45e0-88f0-9f93c2ba2801','舍東四詠 盆池','陸游','宋','宋诗','song-poetry','','[]','寒溜初通後，新荷未長時。',24,'全唐诗/poet.song.134000.json','["寒溜初通後，新荷未長時。", "誰持大圜鏡，爲我照鬚眉。"]'),
('8a9804c8-0c3a-4858-abce-0772215dfdfc','舍東四詠 小徑','陸游','宋','宋诗','song-poetry','','[]','環繞無十步，捷行財半之。',24,'全唐诗/poet.song.134000.json','["環繞無十步，捷行財半之。", "安西九千里，自有著鞭時。"]'),
('1bc70b36-e497-4f79-84ac-4a5d1836e6b4','示元敏','陸游','宋','宋诗','song-poetry','','[]','學貴身行道，儒當世守經。',48,'全唐诗/poet.song.134000.json','["學貴身行道，儒當世守經。", "心心慕繩檢，字字講聲形。", "吾已鬢眉白，汝方衿佩青。", "良時不可失，苦語直須聽。"]'),
('561f059f-5ac4-406c-a4b1-cf5c6ca0d7d9','暮春四首  其一','陸游','宋','宋诗','song-poetry','','[]','掠面微風吹宿酲，送春空有不勝情。',32,'全唐诗/poet.song.134000.json','["掠面微風吹宿酲，送春空有不勝情。", "風烟老盡王孫草，時聽桑間小婦聲。"]'),
('3d49ef21-af89-46c4-8574-cfaeca0e930a','暮春四首  其二','陸游','宋','宋诗','song-poetry','','[]','辛夷海棠俱作塵，鮆魚蓴菜亦嘗新。',32,'全唐诗/poet.song.134000.json','["辛夷海棠俱作塵，鮆魚蓴菜亦嘗新。", "一聲布穀便無說，紅藥雖開不屬春。"]'),
('fc97ebb8-5894-41ba-b8b4-74075f516c3e','暮春四首  其三','陸游','宋','宋诗','song-poetry','','[]','市橋岸下泛湖舟，雕檻疏簾半上鈎。',32,'全唐诗/poet.song.134000.json','["市橋岸下泛湖舟，雕檻疏簾半上鈎。", "春事幾何君惜醉，明朝赤幟插譙樓。"]'),
('1d146902-c112-4923-b9db-ac9f712d0805','暮春四首  其四','陸游','宋','宋诗','song-poetry','','[]','祓除已過暮春初，彩舫相銜十里餘。',32,'全唐诗/poet.song.134000.json','["祓除已過暮春初，彩舫相銜十里餘。", "浮蠟喜嘗新店酒，流塵閑拂壞垣書。"]'),
('6cee81a5-b3aa-4f41-974c-3ac0eeef479f','書感','陸游','宋','宋诗','song-poetry','','[]','楚些難招去幹魂，正令舌在向誰論。',64,'全唐诗/poet.song.134000.json','["楚些難招去幹魂，正令舌在向誰論。", "中分白日歸欹枕，全付青春與杜門。", "凜凜咥人愁履虎，區區染指畏嘗黿。", "殘年誓報嗟何有，虛負明時養老恩。"]'),
('32d80232-c8ee-48f9-ade1-c019bf38a386','晨起出南堂','陸游','宋','宋诗','song-poetry','','[]','曉枕華胥誰喚回，下堂拽杖一悠哉。',64,'全唐诗/poet.song.134000.json','["曉枕華胥誰喚回，下堂拽杖一悠哉。", "啼鴉已逐晨光起，飛鷺初衝宿靄來。", "石路少行生蔓草，柴扉多閉長莓苔。", "身閑亦未全無事，檢校幽花幾樹開。"]'),
('7d9463d8-3991-4de1-90ad-18a745e66597','春晚小飲','陸游','宋','宋诗','song-poetry','','[]','病卧虛齋一味慵，今年春事又成空。',64,'全唐诗/poet.song.134000.json','["病卧虛齋一味慵，今年春事又成空。", "籜龍奮迅風雷際，木筆凋零霧雨中。", "平野草深黄犢健，斷溪水長畫船通。", "小兒偶得官樓酒，鱟醢鰌乾一醉同。"]'),
('b9aaa02d-b998-4482-89b2-9a93c76c8721','殘春二首  其一','陸游','宋','宋诗','song-poetry','','[]','江鮆堆盤粔籹香，山家節物亦窮忙。',64,'全唐诗/poet.song.134000.json','["江鮆堆盤粔籹香，山家節物亦窮忙。", "桑間葚紫蠶齊老，水面秧青麥半黄。", "語燕似催春事去，遊絲不似客愁長。", "鄉村年少那知此，處處喧呼蹴鞠場。"]'),
('63e8ee8a-a428-4c79-badf-f9afcef4eecd','殘春二首  其二','陸游','宋','宋诗','song-poetry','','[]','過了清明日愈遲，年華不復在辛夷。',64,'全唐诗/poet.song.134000.json','["過了清明日愈遲，年華不復在辛夷。", "誰知綠葉陰成處，正是青天露坐時。", "茂草滿庭喧鼓吹，嫩湯出鼎試槍旗。", "衰翁敢作明年計，剩與東君惜語離。"]'),
('125af227-d228-4007-826d-d8f15730e055','聞山步有虎','陸游','宋','宋诗','song-poetry','','[]','茆屋穿漏雨送春，村路斷絕虎咥人。',32,'全唐诗/poet.song.134000.json','["茆屋穿漏雨送春，村路斷絕虎咥人。", "采桑鋤麥皆結伴，兒童出門翁媼嗔。"]'),
('5cd69c19-604b-49ed-9b65-a805019fc6bd','久雨初霽','陸游','宋','宋诗','song-poetry','','[]','兩月涔涔雨不休，今年春近尚重裘。',64,'全唐诗/poet.song.134000.json','["兩月涔涔雨不休，今年春近尚重裘。", "水深草茂群蛙怒，日出風和宿麥秋。", "陂壞堤防誰與筑，市遥鹽酪絕難求。", "農家辛苦尋常事，賣劍方當更買牛。"]'),
('7f6e6eca-ce8a-48a7-9c84-c2c4ed54be7d','初夏幽居雜賦七首  其一','陸游','宋','宋诗','song-poetry','','[]','雨霽逢初夏，胡床蔭綠槐。',48,'全唐诗/poet.song.134000.json','["雨霽逢初夏，胡床蔭綠槐。", "半酣方嵬峨，假寐忽咍臺。", "小穗閑簪麥，微酸細嚼梅。", "衰翁不禁老，更著物華催。"]'),
('766f84be-740f-47f4-80c7-52df0b67b5ff','初夏幽居雜賦七首  其二','陸游','宋','宋诗','song-poetry','','[]','過盡一春雨，園林氣少和。',48,'全唐诗/poet.song.134000.json','["過盡一春雨，園林氣少和。", "偶然扶楖栗，復爾坐盤陀。", "小草數行字，殘花一曲歌。", "公卿非傲汝，無奈愛閑何。"]'),
('d67662f0-6756-43d3-bbf3-c0bc303b70ad','初夏幽居雜賦七首  其三','陸游','宋','宋诗','song-poetry','','[]','水際閑將鶴，林間獨擁琴。',48,'全唐诗/poet.song.134000.json','["水際閑將鶴，林間獨擁琴。", "披叢采香草，映樹看珍禽。", "正使居無屋，猶勝突不黔。", "過春差覺健，處處得幽尋。"]'),
('d74fba79-900a-4b6f-84fd-b56ffdd56e57','初夏幽居雜賦七首  其四','陸游','宋','宋诗','song-poetry','','[]','籬落魚池北，房櫳道院東。',48,'全唐诗/poet.song.134000.json','["籬落魚池北，房櫳道院東。", "水紋藤坐榻，山字素屏風。", "采藥松岡近，投竿荻浦通。", "悠然搔短髮，心事寄冥鴻。"]'),
('4f3dda10-c919-4cb5-9fd5-5e4a2323fde3','初夏幽居雜賦七首  其五','陸游','宋','宋诗','song-poetry','','[]','曲曲羊腸徑，疏疏麂眼籬。',48,'全唐诗/poet.song.134000.json','["曲曲羊腸徑，疏疏麂眼籬。", "渴蜂窺硯水，狂蝶入書帷。", "一枕輕安夢，數聯蕭散詩。", "餘生已過足，不必到期頤。"]'),
('b9ec7756-b27c-49b1-8bab-079e30ff9b8e','初夏幽居雜賦七首  其六','陸游','宋','宋诗','song-poetry','','[]','闢地剪蓬蒿，何曾嘆作勞。',48,'全唐诗/poet.song.134000.json','["闢地剪蓬蒿，何曾嘆作勞。", "藥名尋本草，蘭族驗離騷。", "北澗穿籬過，南山出屋高。", "回頭看富貴，何啻一秋毫。"]'),
('9d2e4584-4f0f-44a8-b95a-a0ae5b49571f','初夏幽居雜賦七首  其七','陸游','宋','宋诗','song-poetry','','[]','修名寧復冀，餘日苦無多。',48,'全唐诗/poet.song.134000.json','["修名寧復冀，餘日苦無多。", "已嘆堂堂去，將如寂寂何。", "編籬護香草，埋盎貯清波。", "兒戲君無笑，相從且浩歌。"]'),
('b3afe4e9-5f03-4c10-904c-1970686269db','雨','陸游','宋','宋诗','song-poetry','','[]','家近蓬萊白玉京，草堂登望不勝清。',64,'全唐诗/poet.song.134000.json','["家近蓬萊白玉京，草堂登望不勝清。", "初驚野色昏昏至，已見波紋細細生。", "殘醉頓消迎亂點，微吟漸苦入寒聲。", "只愁今夕虛簷滴，又對清燈夢不成。"]'),
('976ba6cf-d1b2-49f1-bdec-e8d22020e343','自閔','陸游','宋','宋诗','song-poetry','','[]','主人元是客，儒士却成僧。',48,'全唐诗/poet.song.134000.json','["主人元是客，儒士却成僧。", "垂老貧如昔，經春醉未曾。", "褰衣身傴僂，顧影髮鬅鬙。", "忽憶東岡路，捫蘿試一登。"]'),
('c9eaa834-221e-4449-bdd7-955805afcd50','蔬食','陸游','宋','宋诗','song-poetry','','[]','牆陰春薺老，筍蕨正登盤。',48,'全唐诗/poet.song.134000.json','["牆陰春薺老，筍蕨正登盤。", "野饁元無婦，村醅不屬官。", "何由取熊掌，幸免買豬肝。", "猶勝煩秦相，綈袍閔一寒。"]'),
('81fe3e3f-6ac8-4796-937a-0e4e9a67aaf4','讀阮籍傳','陸游','宋','宋诗','song-poetry','','[]','天生父子立君臣，萬世寧容亂大倫。',32,'全唐诗/poet.song.134000.json','["天生父子立君臣，萬世寧容亂大倫。", "籍輩可誅無復議，禮非爲我爲何人。"]'),
('7e05632f-75f7-4611-9442-29d7f1ac6ce6','杜宇行','陸游','宋','宋诗','song-poetry','','[]','去年杜宇號阡陌，家家聚首憂蠶麥。',64,'全唐诗/poet.song.134000.json','["去年杜宇號阡陌，家家聚首憂蠶麥。", "豈惟比屋衣食憂，縣家亦負催科責。", "今年略不聞杜宇，蠶收麥熟人歌舞。", "豈惟襦新湯餅寬，鄰里相約先輸官。"]'),
('e56d45ff-c5ea-48f9-93d4-9e23ce6c7324','捕虎行','陸游','宋','宋诗','song-poetry','','[]','山村牧童遭虎噬，血肉俱盡餘雙髻。',64,'全唐诗/poet.song.134000.json','["山村牧童遭虎噬，血肉俱盡餘雙髻。", "家人行哭覓遺骨，道路聞之俱掩涕。", "州家督尉宿山中，已淬藥箭攢長弓。", "明朝得虎徹檻阱，繅絲擣麨歌年豐。"]'),
('597a0dbb-226f-4ea2-b2ac-0356534f342f','遣興','陸游','宋','宋诗','song-poetry','','[]','前歲峨冠領石渠，即今山市醉騎驢。',64,'全唐诗/poet.song.134000.json','["前歲峨冠領石渠，即今山市醉騎驢。", "目衰書卷研求懶，心弱詩章鍛鍊疏。", "風雨吾廬嗟獨破，齏鹽每食嘆無餘。", "燈前却有欣然處，稚子談經屢起予。"]'),
('0e895424-0120-45d7-aaba-69eb98b9ffa7','三齒墮歌','陸游','宋','宋诗','song-poetry','','[]','一葉落知天下秋，三齒墮矣吾生休。',118,'全唐诗/poet.song.134000.json','["一葉落知天下秋，三齒墮矣吾生休。", "詩人未脫紈袴態，尚樂華屋悲山丘。", "蓼花荻葉可以解我憂，鸕鶿白鷺可以從我遊。", "君看貂蟬與兜鍪，等爲岑岑壓我頭。", "豈知石闌干下買篛笠，一棹飄然烟雨舟。", "不須强預家國憂，亦莫妄陳帷幄籌。", "功名富貴兩悠悠，惟有杜宇可與謀。"]'),
('221f4921-b789-45db-8a42-5af4aa26eddc','龜堂初暑','陸游','宋','宋诗','song-poetry','','[]','淪漪一曲繞茅堂，葛帔紗巾喜日長。',64,'全唐诗/poet.song.134000.json','["淪漪一曲繞茅堂，葛帔紗巾喜日長。", "多事林鳩管晴雨，依人海燕度炎凉。", "深枝著子纍纍熟，幽草開花冉冉香。", "安得此時江海上，與君袖手看人忙。"]'),
('34552dfa-d65d-4ea4-b67f-964421fb08e5','衰嘆','陸游','宋','宋诗','song-poetry','','[]','十年三墮齒，久矣嘆吾衰。',48,'全唐诗/poet.song.134000.json','["十年三墮齒，久矣嘆吾衰。", "亹亹循天理，兢兢到死時。", "窮空顔子巷，勤苦董生帷。", "道遠餘生趣，常憂日影移。"]'),
('21bb490c-9655-4f30-bce2-f1fa9f876980','初夏閑步村落間','陸游','宋','宋诗','song-poetry','','[]','薄雲韜日不成晴，野水通池漸欲平。',64,'全唐诗/poet.song.134000.json','["薄雲韜日不成晴，野水通池漸欲平。", "綠葉忽低知鳥立，青萍微動覺魚行。", "醉遊放蕩初何適，睡起逍遥未易名。", "忽遇湖邊隱君子，相携一笑慰餘生。"]'),
('0096407b-c825-407f-8183-717ca4a48b06','夜興','陸游','宋','宋诗','song-poetry','','[]','鬢毛飽受雪霜侵，一褐蕭條寄故林。',64,'全唐诗/poet.song.134000.json','["鬢毛飽受雪霜侵，一褐蕭條寄故林。", "簷雨滴回羈枕夢，城笳喚起塞垣心。", "平生耻露囊中穎，垂老甘同爨下琴。", "燈燼欲殘看瘦影，不妨袖手坐愔愔。"]'),
('7f72e1d8-cf8a-480c-b99b-e28602e31f65','寄十二侄','陸游','宋','宋诗','song-poetry','','[]','庚寅吾入蜀，西過齊安城。',240,'全唐诗/poet.song.134000.json','["庚寅吾入蜀，西過齊安城。", "雪堂拜老仙，眉宇寒崢嶸。", "微泉尚如昔，激激琴筑聲。", "龍蛇入筆力，斷石卧縱橫。", "戊戌奉詔追，觸熱萬里程。", "歸途抵齊安，歲月浩可驚。", "三日乃東下，鼓角遥送迎。", "安國有老僧，元祐初載生。", "蟬聯說舊事，耳目猶聰明。", "徒行就船別，耿耿惻愴情。", "豈知二紀後，汝乃爲此行。", "追懷昔遊地，未語涕已傾。", "念汝雖並塞，殘虜方守盟。", "職雖在警盜，枹鼓寂不鳴。", "惟當奉法令，日夜撫孤惸。", "官卑俸入薄，切勿厭藜羹。", "勇如赤壁戰，節若江水清。", "人誰不汝知，况事賢公卿。", "三山與七家，相望兩柴荆。", "歸來講學暇，襏襫同春耕。"]'),
('c92ef84f-8a2d-400c-bc2e-053e45ed12e0','出塞四首借用秦少遊韵  其一','陸游','宋','宋诗','song-poetry','','[]','北伐下遼碣，西征取伊凉。',48,'全唐诗/poet.song.134000.json','["北伐下遼碣，西征取伊凉。", "壯士凱歌歸，豈復賦國殤。", "連頸俘女真，貸死遣牧羊。", "犬豕何足讎，汝自承餘殃。"]'),
('129f8023-cd45-4ff4-bc59-6452c98a1775','出塞四首借用秦少遊韵  其二','陸游','宋','宋诗','song-poetry','','[]','煌煌藝祖業，土宇盡九州。',48,'全唐诗/poet.song.134000.json','["煌煌藝祖業，土宇盡九州。", "當時王會圖，豈數汝黄頭。", "今茲縛纛下，狀若觳觫牛。", "萬里獻太社，裨將皆通侯。"]'),
('5c5cbc27-dac0-4e0f-ade4-73791ce20e84','出塞四首借用秦少遊韵  其三','陸游','宋','宋诗','song-poetry','','[]','符離既班師，北討意頗闌。',48,'全唐诗/poet.song.134000.json','["符離既班師，北討意頗闌。", "志士雖有懷，開說常苦艱。", "諸將初北首，易水秋風寒。", "黄旗馳捷奏，雪夜奪榆關。"]'),
('818c16df-56b3-48c9-bdcc-2184e111d4bc','出塞四首借用秦少遊韵  其四','陸游','宋','宋诗','song-poetry','','[]','小醜盜中原，異事古未有。',48,'全唐诗/poet.song.134000.json','["小醜盜中原，異事古未有。", "爾來閭左起，似是天假手。", "頭顱滿沙場，餘胾飼豬狗。", "天網本不疏，貸汝亦已久。"]'),
('e570d120-72f6-4cbb-b652-edadacf58112','命駕','陸游','宋','宋诗','song-poetry','','[]','命駕清晨出射堂，筇枝羽扇受微凉。',64,'全唐诗/poet.song.134000.json','["命駕清晨出射堂，筇枝羽扇受微凉。", "鴉將數子窺苔井，桐引新枝出粉牆。", "岸幘影邊茶正熟，投壺聲裏日初長。", "興闌却蹋湖堤去，十里山花滿袖香。"]'),
('3737ad51-b87e-48ea-a8ed-62c9b46e32d4','遊山遇雨','陸游','宋','宋诗','song-poetry','','[]','千秋觀前雨溼衣，石帆山下叩漁扉。',32,'全唐诗/poet.song.134000.json','["千秋觀前雨溼衣，石帆山下叩漁扉。", "鷓鴣苦道行不得，杜鵑更勸不如歸。"]'),
('8ac4c7b4-c108-404e-bd9c-3ee2cf8dec53','東籬雜題五首  其一','陸游','宋','宋诗','song-poetry','','[]','終日在東籬，清和適此時。',48,'全唐诗/poet.song.134000.json','["終日在東籬，清和適此時。", "鶯聲如妒夢，花氣欲撩詩。", "愛客茶新碾，留僧飯別炊。", "流年隨手過，不覺近期頤。"]'),
('5265cd34-ade3-4b93-8e23-87ccd6d1c574','東籬雜題五首  其二','陸游','宋','宋诗','song-poetry','','[]','深居遠悔吝，簡事養精神。',48,'全唐诗/poet.song.134000.json','["深居遠悔吝，簡事養精神。", "曳杖一蕭散，待茶時欠伸。", "風生叢竹嘯，露坼野花新。", "自作東籬後，經旬不過鄰。"]'),
('0b7e3399-84dd-4c0e-985a-bc4ff8182c11','東籬雜題五首  其三','陸游','宋','宋诗','song-poetry','','[]','昨日一花坼，今朝一草生。',48,'全唐诗/poet.song.134000.json','["昨日一花坼，今朝一草生。", "深林鳩婦聒，高棟燕巢成。", "熟果簷間墮，殘書枕畔橫。", "庵居澹無事，作意領新晴。"]'),
('e4c169b8-9c01-46c8-8a6b-5e24683e975e','東籬雜題五首  其四','陸游','宋','宋诗','song-poetry','','[]','南陌歸雖久，東籬興又新。',48,'全唐诗/poet.song.134000.json','["南陌歸雖久，東籬興又新。", "無求覺身貴，好儉失家貧。", "引水常終日，栽花又過春。", "桃源不須覓，已是葛天民。"]'),
('cdef031a-8bc7-4fcf-89f8-167ed64bae14','東籬雜題五首  其五','陸游','宋','宋诗','song-poetry','','[]','溝聲流激激，籬影立疏疏。',48,'全唐诗/poet.song.134000.json','["溝聲流激激，籬影立疏疏。", "平旦來澆藥，臨昏尚看魚。", "比鄰怪疏索，風月伴躊躇。", "安得王摩詰，憑渠畫草廬。"]'),
('1d9f2f93-ee34-43b8-8b62-5275699f5799','書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','本來只道千鈞重，看破元無一羽輕。',32,'全唐诗/poet.song.134000.json','["本來只道千鈞重，看破元無一羽輕。", "日月光明天廣大，不妨嘯傲過平生。"]'),
('2ec370cc-a2fa-4e6e-8e52-001dfa346d9f','書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','燕雛學母飛初熟，梅子團枝亦半黄。',32,'全唐诗/poet.song.134000.json','["燕雛學母飛初熟，梅子團枝亦半黄。", "麈尾唾壺俱屏去，尚存餘習炷爐香。"]'),
('a0ba0385-3609-45b7-a3ae-ddd14a4daf09','乙丑重五二首  其一','陸游','宋','宋诗','song-poetry','','[]','盤中共解青菰粽，衰甚猶簪艾一枝。',32,'全唐诗/poet.song.134000.json','["盤中共解青菰粽，衰甚猶簪艾一枝。", "寂寞廢詩仍止酒，今年真負此佳時。"]'),
('4c957501-5d55-4542-952c-cf75308b77ce','乙丑重五二首  其二','陸游','宋','宋诗','song-poetry','','[]','飛棹中流救屈平，俚歌寧復楚遺聲。',32,'全唐诗/poet.song.134000.json','["飛棹中流救屈平，俚歌寧復楚遺聲。", "危冠更在門楣上，但覺蕭敷與艾榮。"]'),
('c873147d-b078-4453-8749-825d97ab4474','夏夜枕上','陸游','宋','宋诗','song-poetry','','[]','卧聽殘更下麗譙，雖非遥夜亦迢迢。',32,'全唐诗/poet.song.134000.json','["卧聽殘更下麗譙，雖非遥夜亦迢迢。", "正令展轉無安枕，猶勝龍鍾趁早朝。"]'),
('690d0b19-1127-470d-b63a-6e2e59ade5d1','石帆夏日二首  其一','陸游','宋','宋诗','song-poetry','','[]','石帆山下雨冥冥，閑岸紗巾憩草亭。',64,'全唐诗/poet.song.134000.json','["石帆山下雨冥冥，閑岸紗巾憩草亭。", "單複篝衣時脫著，甜酸園果半黄青。", "鰥魚無隊依蒲藻，病鶴長鳴鎩翅翎。", "自笑若爲消永日，異書新錄相牛經。"]'),
('af41f647-eef4-41bd-bd59-664c485f4576','石帆夏日二首  其二','陸游','宋','宋诗','song-poetry','','[]','短棹飄然信所之，茶園漁市到無時。',64,'全唐诗/poet.song.134000.json','["短棹飄然信所之，茶園漁市到無時。", "風從蘋末蕭蕭起，月過花陰故故遲。", "蓴菜煮羹吳舊俗，竹枝度曲楚遺辭。", "頗聞項里楊梅熟，鄰曲相招莫後期。"]'),
('7cb52ffc-aae3-43b0-bcb9-0e7c4dc72c98','仲夏風雨不已','陸游','宋','宋诗','song-poetry','','[]','南陌東阡自在身，一年節物幾番新。',64,'全唐诗/poet.song.134000.json','["南陌東阡自在身，一年節物幾番新。", "鰣魚出後鶯花鬧，梅子熟時風雨頻。", "冠蓋敢同修禊客，桑麻不減避秦人。", "夕陽更有蕭然處，照影清溪整葛巾。"]'),
('44924a9d-162e-4fdb-be86-e2ce0c225570','幽居','陸游','宋','宋诗','song-poetry','','[]','旌節庭下葵，鼓吹池中蛙。',72,'全唐诗/poet.song.134000.json','["旌節庭下葵，鼓吹池中蛙。", "坐令灌園公，忽作富貴家。", "浮生均一鬨，事過但興嗟。", "蚩蚩彼何人，欲摘空中花。", "牆隅蔬可挽，巷口酒可賒。", "疏懶遂吾性，不賣東陵瓜。"]'),
('14aa6423-2b93-4083-9cb7-94cb9e1e1612','齒落','陸游','宋','宋诗','song-poetry','','[]','昔聞少陵翁，皓首惜墮齒。',72,'全唐诗/poet.song.134000.json','["昔聞少陵翁，皓首惜墮齒。", "退之更可憐，至謂豁可恥。", "放翁獨不然，頑頓世無比。", "齒摇忽脫去，取視乃大喜。", "譬如大木拔，豈有再安理。", "咀嚼浩無妨，更覺彘肩美。"]'),
('6dce3297-f98f-4fe9-b07d-fbec24199459','雨中排悶','陸游','宋','宋诗','song-poetry','','[]','殷殷雷繞村，淅淅雨鳴砌。',72,'全唐诗/poet.song.134000.json','["殷殷雷繞村，淅淅雨鳴砌。", "禽魚各自適，草木亦得意。", "顧此庵中人，老病獨憔悴。", "飯遲每懶索，兀兀方坐睡。", "平生飽憂患，性命已屢試。", "但得過今朝，明日可徐議。"]'),
('08f08d31-cc9a-4ca4-b210-9b4f7e645ca2','逆境','陸游','宋','宋诗','song-poetry','','[]','步步常由逆境行，極知造物欲其成。',64,'全唐诗/poet.song.134000.json','["步步常由逆境行，極知造物欲其成。", "磨礲久已盡芒角，烹煮豈容重發生。", "死到面前猶覺小，事於身外孰非輕。", "出門不必名山去，但見風烟已眼明。"]'),
('d781608b-46a0-4219-af56-fd265d11d303','夜興','陸游','宋','宋诗','song-poetry','','[]','脫冠殘髮冷颼飀，北斗闌干河漢秋。',64,'全唐诗/poet.song.134000.json','["脫冠殘髮冷颼飀，北斗闌干河漢秋。", "木末有風栖鵲起，亭皋無月亂螢流。", "酒慳僅得時時醉，詩退難禁夜夜愁。", "欲睡不妨還小立，一聲菱唱起滄洲。"]'),
('54e03612-2bea-4120-a79a-eecc1f140aa3','寄題李季章侍郎石林堂','陸游','宋','宋诗','song-poetry','','[]','林慮靈壁名宇宙，震澤舂陵稍居後。',163,'全唐诗/poet.song.134000.json','["林慮靈壁名宇宙，震澤舂陵稍居後。", "翟公黄鶴得數峰，對客掀髯詫奇秀。", "我行新灘見益奇，千巖萬竇雷雨垂。", "古來豈無好事者，根株盤踞不可移。", "佳郎筑堂聚眾石，坐卧對之旰忘食。", "千金博取直易爾，要是尤物歸精識。", "君不見牛奇章與李衛公，一生冰炭不相容。", "門前冠蓋各分黨，惟有愛石心則同。", "崎嶇宦路多危機，凜然石友人間稀。", "它時檥棹華亭岸，更看全窠買鶴歸。"]'),
('735eea56-3bb6-4536-94e4-e2fb24569929','流年','陸游','宋','宋诗','song-poetry','','[]','冉冉流年迫耄期，心情漸減舊兒嬉。',64,'全唐诗/poet.song.134000.json','["冉冉流年迫耄期，心情漸減舊兒嬉。", "唾壺麈尾已從省，茶竈筆床猶自隨。", "昨日客招東浦釣，今朝僧約北軒棋。", "敢將輕健誇鄰里，一笑元知要及時。"]'),
('f909dbf5-24c3-40ae-a128-1b5e55c11221','雨中鋤藥','陸游','宋','宋诗','song-poetry','','[]','庭中正苦日卓午，水面忽看雲過西。',32,'全唐诗/poet.song.134000.json','["庭中正苦日卓午，水面忽看雲過西。", "老子不辭衝急雨，小鋤香带藥畦泥。"]'),
('91613137-9968-4e18-863c-f66ba6ce22a6','自嘲','陸游','宋','宋诗','song-poetry','','[]','壯歲耽書廢夜眠，窗明猶在短檠前。',32,'全唐诗/poet.song.134000.json','["壯歲耽書廢夜眠，窗明猶在短檠前。", "如今自笑摧頹甚，卧看兒曹理斷編。"]'),
('e059b0fa-10f9-43f0-9579-d8dcaa9e3a1e','世事','陸游','宋','宋诗','song-poetry','','[]','世事如今盡伏輸，面能乾唾况其餘。',64,'全唐诗/poet.song.134000.json','["世事如今盡伏輸，面能乾唾况其餘。", "詩才退後愁强韵，眼力衰來怯細書。", "斂迹已思焚筆硯，作勞敢避把犂鉏。", "晴空萬里寬多少，一片閑雲足卷舒。"]'),
('ab16bc4e-5ab7-4616-b706-8b69c0abc383','悲齒落自解','陸游','宋','宋诗','song-poetry','','[]','年運而往君自寬，此生畢竟有衰殘。',32,'全唐诗/poet.song.134000.json','["年運而往君自寬，此生畢竟有衰殘。", "語訛嚼廢尋常事，只作兒童䃣齒看。"]'),
('a4a09fa3-1adc-4df5-adfa-b7812a93350c','送十五郎適臨安','陸游','宋','宋诗','song-poetry','','[]','求祿亦常事，出門寧自由。',48,'全唐诗/poet.song.134000.json','["求祿亦常事，出門寧自由。", "苦留雖惜別，細語却生愁。", "雨急投村市，鐘殘過寺樓。", "祇應今夕夢，先汝到江頭。"]'),
('238d95fe-c8b8-4080-8e6b-783d86a8316b','幽居夏日二首  其一','陸游','宋','宋诗','song-poetry','','[]','茅舍參差烟靄中，超然高興與誰同。',64,'全唐诗/poet.song.134000.json','["茅舍參差烟靄中，超然高興與誰同。", "形骸已與流年老，詩句猶爭造物功。", "子母瓜新間尊俎，公孫竹長映簾櫳。", "日長愈覺閑無事，隱具成書又一通。"]'),
('1e585ca0-b293-4b4f-8ab7-41b5fbb09abd','幽居夏日二首  其二','陸游','宋','宋诗','song-poetry','','[]','內史蘭亭晚卜鄰，永和風月凜如新。',64,'全唐诗/poet.song.134000.json','["內史蘭亭晚卜鄰，永和風月凜如新。", "功名不入閑人夢，詩酒猶關老子身。", "簷淺時時聞霣籜，池清一一見潜鱗。", "正令未逐飛仙去，要是巢居太古民。"]'),
('c7cbfa09-134e-42e1-9e25-039bf2ef0787','大雨','陸游','宋','宋诗','song-poetry','','[]','北窗欲化莊生蝶，睡思濛濛栖倦睫。',96,'全唐诗/poet.song.134000.json','["北窗欲化莊生蝶，睡思濛濛栖倦睫。", "川雲忽带急雨來，萬點縱橫打荷葉。", "坐收爽氣入詩律，更借凉颸吹醉頰。", "壞簷腐瓦凜欲墮，積潦中庭深可涉。", "兒愁漏溼廢夜課，婦畏泥塗停早饁。", "老翁自笑獨爾頑，更喜烟波摇短檝。"]'),
('5c64173b-a75f-4945-a73b-0ae2121bafdb','思雲門','陸游','宋','宋诗','song-poetry','','[]','一身膏脂略瘦盡，萬卷簡編如隔生。',32,'全唐诗/poet.song.134000.json','["一身膏脂略瘦盡，萬卷簡編如隔生。", "祇欲移家若耶去，亂雲深處聽灘聲。"]'),
('607518d6-111e-4216-8ce3-a5a2361308a3','夏夜','陸游','宋','宋诗','song-poetry','','[]','散髮荒池上，秋聲滿綠蒲。',48,'全唐诗/poet.song.134000.json','["散髮荒池上，秋聲滿綠蒲。", "磷飛乘月暗，梟語似人呼。", "學問無新得，功名負壯圖。", "拾薪炊麥飯，隨事且枝梧。"]'),
('bd533077-2040-4184-a795-e7779b84b59f','觀身','陸游','宋','宋诗','song-poetry','','[]','欲去浮華累，先觀老病身。',48,'全唐诗/poet.song.134000.json','["欲去浮華累，先觀老病身。", "濁醪何負汝，淡飯最宜人。", "意氣隨年往，工夫愧日新。", "祇將閑送老，虛作太平民。"]'),
('fe38beba-4b3e-45f0-a6d8-98fdcc768cdd','養氣','陸游','宋','宋诗','song-poetry','','[]','學道先養氣，吾聞三住章。',48,'全唐诗/poet.song.134000.json','["學道先養氣，吾聞三住章。", "屏除金鼎藥，糠秕玉函方。", "凜凜春冰履，兢兢拱璧藏。", "高談忘力守，此病最膏肓。"]'),
('4a5e3ddb-2a42-488d-9575-a8e48f75dbe9','日用','陸游','宋','宋诗','song-poetry','','[]','日用無淵奧，其中妙理存。',48,'全唐诗/poet.song.134000.json','["日用無淵奧，其中妙理存。", "但能明物性，不必學玄門。", "盡力扶元氣，精思去病根。", "昔人由此道，推己及元元。"]'),
('ea0cbfd7-558a-4be3-acd4-09bbc54c3c15','村市醉歸','陸游','宋','宋诗','song-poetry','','[]','伏櫪元知免駭機，翦翎豈復慕群飛。',64,'全唐诗/poet.song.134000.json','["伏櫪元知免駭機，翦翎豈復慕群飛。", "坐中客滿知心少，囊裏詩多得意稀。", "小市雨餘尋酒去，野橋日落策驢歸。", "不辭十里行空翠，終勝京塵化客衣。"]'),
('bf9221f7-0abc-43d4-82a4-2ac5d764e024','夏日感舊四首  其一','陸游','宋','宋诗','song-poetry','','[]','北窗枕簟卧陶翁，樹樹鳴蟬葉葉風。',64,'全唐诗/poet.song.134000.json','["北窗枕簟卧陶翁，樹樹鳴蟬葉葉風。", "睡覺殘書棲懶架，浴回細葛覆熏籠。", "一藤未遂名山去，半卷還驚舊歷空。", "妄想金丹君莫笑，清班曾是長仙蓬。"]'),
('85453bd2-cf8f-4002-8ba7-4e593f524981','夏日感舊四首  其二','陸游','宋','宋诗','song-poetry','','[]','五侍仙祠兩挂冠，此生略有半生閑。',64,'全唐诗/poet.song.134000.json','["五侍仙祠兩挂冠，此生略有半生閑。", "嘯歌雨笠烟蓑底，來往山村縣郭間。", "一粒何當換凡骨，數杯且復駐頹顔。", "胡塵掃盡知何日，不隱箕山即華山。"]'),
('ac09d1b0-5ac9-4da6-8daf-d8aec21fab07','夏日感舊四首  其三','陸游','宋','宋诗','song-poetry','','[]','吳人那慣粟漿酸，茶碗聊霑舌本乾。',64,'全唐诗/poet.song.134000.json','["吳人那慣粟漿酸，茶碗聊霑舌本乾。", "身病不堪閑客攪，日長惟憶異書看。", "流年冉冉誰能駐，長夏迢迢亦已殘。", "步有新船君賀我，西風先夢上嚴灘。"]'),
('3e6d4b79-93bb-4303-a7f4-3395deeb7896','夏日感舊四首  其四','陸游','宋','宋诗','song-poetry','','[]','獨居無復客嘲邊，終日頹然飽即眠。',64,'全唐诗/poet.song.134000.json','["獨居無復客嘲邊，終日頹然飽即眠。", "護硯小屏山縹緲，摇風團扇月嬋娟。", "桐陰忽見翻雙鵲，石罅時聞落細泉。", "避暑不須河朔飲，轉頭即見早秋天。"]'),
('c1981c22-d72d-4eec-96a8-6e6db0d06ac8','雨後','陸游','宋','宋诗','song-poetry','','[]','甘澍慰群望，浮雲還故墟。',48,'全唐诗/poet.song.134000.json','["甘澍慰群望，浮雲還故墟。", "新凉生枕簟，餘潤入犁鋤。", "簾上翩翩燕，蒲新鱍鱍魚。", "素秋猶半月，團扇意先疏。"]'),
('07f73a27-3967-47e6-abd2-651fdb5ddca6','東軒','陸游','宋','宋诗','song-poetry','','[]','榴花零落滿蒼苔，薝蔔忘憂亦已開。',32,'全唐诗/poet.song.134000.json','["榴花零落滿蒼苔，薝蔔忘憂亦已開。", "湖海片帆先已具，少安無躁待秋來。"]'),
('6fcab924-c304-4869-bd51-a2aa5a9162b5','寄子虡子遹','陸游','宋','宋诗','song-poetry','','[]','大兒再度吳門秋，小兒錢塘逾月留。',64,'全唐诗/poet.song.134000.json','["大兒再度吳門秋，小兒錢塘逾月留。", "恨身不能插兩翅，與汝相守寬百憂。", "聞鐘時宿雲外寺，待月亦上湖邊樓。", "但常保此豈不樂，路難悠悠非善謀。"]'),
('5cac177e-341e-4b27-a1c4-5862816d35b2','寄張季長','陸游','宋','宋诗','song-poetry','','[]','髮不勝簪短褐寬，每因臨鏡嘆衰殘。',64,'全唐诗/poet.song.134000.json','["髮不勝簪短褐寬，每因臨鏡嘆衰殘。", "未嘗三日不服藥，雖滿百年終闔棺。", "舊友豈知常阻闊，一尊那得敘悲歡。", "錦官花重應如昔，直欲凌風借羽翰。"]'),
('d0406f75-3eec-4d04-aa11-38b838925bc1','夏夜二首  其一','陸游','宋','宋诗','song-poetry','','[]','鳴蜩斷復續，宿鳥久始安。',48,'全唐诗/poet.song.134000.json','["鳴蜩斷復續，宿鳥久始安。", "觸熱汗沾衣，暮夜猶未乾。", "梧桐獨知秋，一葉墮井闌。", "行矣戒碪杵，四序環無端。"]'),
('a785dc44-b6d0-4ef9-aa12-675b92a7e5aa','夏夜二首  其二','陸游','宋','宋诗','song-poetry','','[]','落月不滿窗，驚鵲屢移樹。',48,'全唐诗/poet.song.134000.json','["落月不滿窗，驚鵲屢移樹。", "沉憂少睡眠，亦以衰疾故。", "五更忽作夢，立馬青衣渡。", "白首厭山村，郵亭憶征步。"]'),
('8fbb1ff0-1640-40c4-bdad-1e987114d067','讀趙昌甫詩卷','陸游','宋','宋诗','song-poetry','','[]','蝸廬溽暑不可過，把卷一讀趙子詩。',64,'全唐诗/poet.song.134000.json','["蝸廬溽暑不可過，把卷一讀趙子詩。", "如遊麻源第三谷，忽見梅花開一枝。", "寄書問信不可得，握臂晤語應無期。", "惟當飲水絕火食，海山忽有相逢時。"]'),
('90a52d0b-8fa2-476f-8e3e-cd6bd2c61f80','海氣','陸游','宋','宋诗','song-poetry','','[]','浴罷來水滸，適有漁舟橫。',96,'全唐诗/poet.song.134000.json','["浴罷來水滸，適有漁舟橫。", "浩然縱棹去，漫漫菰蒲聲。", "海祲乃爾奇，萬象空際生。", "驂驔牧龍馬，夭矯騰蛟鯨。", "或如搴大旗，或如執長兵。", "我欲記其變，忽已天宇清。", "成壞須臾間，使我嘆且驚。", "世事正如此，何者非强名。"]'),
('aa79eb13-58ed-4793-a3f8-ce66414d3da3','村居','陸游','宋','宋诗','song-poetry','','[]','舍後盤高岡，舍前面平野。',48,'全唐诗/poet.song.134000.json','["舍後盤高岡，舍前面平野。", "防盜枳作藩，蔽雨篠代瓦。", "數家相依倚，百事容乞假。", "薄暮耕樵歸，共話衡門下。"]'),
('ddc518c2-e3d3-425d-b30a-8220bf1a019f','戒殺','陸游','宋','宋诗','song-poetry','','[]','郊居去市遠，豬羊稀入饌。',72,'全唐诗/poet.song.134000.json','["郊居去市遠，豬羊稀入饌。", "既畜雞鶩群，復利魚蟹賤。", "暴殄非所安，擊鮮况親見。", "那得屠殺業，爲客美殽膳。", "餘年尚有幾，過日如露電。", "豈無園中蔬，敬奉君子宴。"]'),
('3c130fb3-ed57-4b83-a251-4dec612528bb','庭中夜賦','陸游','宋','宋诗','song-poetry','','[]','流汗沾衣不自支，庭中散髮立多時。',64,'全唐诗/poet.song.134000.json','["流汗沾衣不自支，庭中散髮立多時。", "烏烏畫角凌風起，淡淡銀河拂地垂。", "浮玉閑遊元自樂，浣花小筑亦何疑。", "東歸萬里君知否，要了滄洲一段奇。"]'),
('e8e9ba05-2752-4a95-8356-ff5fffab3260','秋近','陸游','宋','宋诗','song-poetry','','[]','石榴萱草併成空，又見牆陰莧葉紅。',64,'全唐诗/poet.song.134000.json','["石榴萱草併成空，又見牆陰莧葉紅。", "茶釅頗妨千里夢，簟凉初怯五更風。", "新瓜落刃冰盤裏，晚燕添巢畫閣中。", "身健流年俱可樂，故人自欠一尊同。"]'),
('a081c814-76d3-4a23-9370-8e8cbf0ef9f8','嘆老','陸游','宋','宋诗','song-poetry','','[]','齒墮因廢談，短髮不入把。',48,'全唐诗/poet.song.134000.json','["齒墮因廢談，短髮不入把。", "餘年似殘尊，欲盡不禁瀉。", "出門見鄉曲，每恨識面寡。", "往昔同戲兒，纍纍冢盈野。"]'),
('5b6fabc7-8c09-47ab-ac46-63014840a801','殘暑得小雨頗凉','陸游','宋','宋诗','song-poetry','','[]','午暑不可觸，忽驚如許凉。',48,'全唐诗/poet.song.134000.json','["午暑不可觸，忽驚如許凉。", "軒窗雲作暝，草木雨生香。", "蒲葉先秋霣，蟬聲入夜長。", "自欣無一事，岸幘倚胡床。"]'),
('def4a5f2-5b46-448a-a67d-d0635e6400bb','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其一','陸游','宋','宋诗','song-poetry','','[]','橫林渺渺夜生烟，野水茫茫遠拍天。',32,'全唐诗/poet.song.134000.json','["橫林渺渺夜生烟，野水茫茫遠拍天。", "菱唱一聲驚夢斷，始知身在釣魚船。"]'),
('33953617-c56d-47d0-b222-74f71ebf0ffe','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其二','陸游','宋','宋诗','song-poetry','','[]','河漢橫斜斗柄低，啼鴉掠水未成栖。',32,'全唐诗/poet.song.134000.json','["河漢橫斜斗柄低，啼鴉掠水未成栖。", "怪生凄爽侵肌骨，船繫秦皇酒甕西。"]'),
('2f9e1c1f-fb9d-4788-b559-d2a3465e9920','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其三','陸游','宋','宋诗','song-poetry','','[]','譙門鼓角寺樓鐘，一一風傳到短篷。',32,'全唐诗/poet.song.134000.json','["譙門鼓角寺樓鐘，一一風傳到短篷。", "喚得放翁殘酒醒，錦囊詩草不教空。"]'),
('1f8ed657-c668-4709-b9b3-d2e12c6c942e','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其四','陸游','宋','宋诗','song-poetry','','[]','小市易散無人行，茫茫湖橋惟月明。',32,'全唐诗/poet.song.134000.json','["小市易散無人行，茫茫湖橋惟月明。", "老夫解酲不用酒，自有千頃菰蒲聲。"]'),
('d9edd68b-b414-4537-a35a-83a47ad75787','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其五','陸游','宋','宋诗','song-poetry','','[]','雞頭纍纍如大珠，紅草綠荷風味殊。',32,'全唐诗/poet.song.134000.json','["雞頭纍纍如大珠，紅草綠荷風味殊。", "天與楊梅成二絕，吾鄉獨有異鄉無。"]'),
('5bd6ebcf-ecac-48ef-8465-358dd0726160','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其六','陸游','宋','宋诗','song-poetry','','[]','城南天鏡三百里，繚以重重翡翠屏。',32,'全唐诗/poet.song.134000.json','["城南天鏡三百里，繚以重重翡翠屏。", "最好長橋明月夜，寄船策蹇上蘭亭。"]'),
('fc1c5610-7151-4a12-9c40-8b5a2713c5c5','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其七','陸游','宋','宋诗','song-poetry','','[]','酒旆摇摇出竹籬，扁舟遠赴野人期。',32,'全唐诗/poet.song.134000.json','["酒旆摇摇出竹籬，扁舟遠赴野人期。", "一天風雨晚來惡，落盡白蓮渾不知。"]'),
('dc1f324d-2ffb-4b2b-a14f-b56b273a59cd','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其八','陸游','宋','宋诗','song-poetry','','[]','七月湖中風露新，臨流閑照白綸巾。',32,'全唐诗/poet.song.134000.json','["七月湖中風露新，臨流閑照白綸巾。", "荷花折盡渾閑事，老却蓴絲最惱人。"]'),
('e2b80a68-997a-4e0e-bdb5-ce96a6a62378','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其九','陸游','宋','宋诗','song-poetry','','[]','恰聽殘蟬禹寺門，又看新月石帆村。',32,'全唐诗/poet.song.134000.json','["恰聽殘蟬禹寺門，又看新月石帆村。", "後來復有龜堂老，千載猶應此意存。"]'),
('fd9ee64c-7b23-47d8-9a08-f1e84972114c','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其一○','陸游','宋','宋诗','song-poetry','','[]','娥江道上欲三更，垣屋參差閉月明。',32,'全唐诗/poet.song.134000.json','["娥江道上欲三更，垣屋參差閉月明。", "倚柁賦詩無傑思，斷腸分付棹歌聲。"]'),
('5ea4f444-94c8-4b0f-bee3-d783dbf81f40','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其一一','陸游','宋','宋诗','song-poetry','','[]','秋來湖闊渺無津，旋結漁舟作四鄰。',32,'全唐诗/poet.song.134000.json','["秋來湖闊渺無津，旋結漁舟作四鄰。", "滿眼是詩渠不領，可憐虛作水雲身。"]'),
('9f838861-6f78-4e54-8bb9-c733dd3b7618','乙丑夏秋之交小舟早夜往來湖中戲成絕句十二首  其一二','陸游','宋','宋诗','song-poetry','','[]','夢筆橋東夜繫船，殘燈耿耿不成眠。',32,'全唐诗/poet.song.134000.json','["夢筆橋東夜繫船，殘燈耿耿不成眠。", "千年未息靈胥怒，卷地潮聲到枕邊。"]'),
('653ce782-5750-4c78-a751-b80e74deea50','初秋四首  其一','陸游','宋','宋诗','song-poetry','','[]','生世元浮脆，人言七十稀。',48,'全唐诗/poet.song.134000.json','["生世元浮脆，人言七十稀。", "耄期今已及，氣力固應微。", "食冷常憂過，追凉每念歸。", "入秋纔幾日，卷簟換縑衣。"]'),
('c9d7b725-0438-4af5-a219-479f0c85ed19','初秋四首  其二','陸游','宋','宋诗','song-poetry','','[]','藉草沾衣露，沿溪掠面風。',48,'全唐诗/poet.song.134000.json','["藉草沾衣露，沿溪掠面風。", "桐凋無茂綠，蓮老有疏紅。", "小彴欹危度，鄰園曲折通。", "新秋得强健，一笑莫匆匆。"]'),
('b03ede27-0fa3-46a8-9818-bc12d0573b1a','初秋四首  其三','陸游','宋','宋诗','song-poetry','','[]','初夜月猶淡，入秋風已清。',48,'全唐诗/poet.song.134000.json','["初夜月猶淡，入秋風已清。", "螢孤無遠照，蟬斷有遺聲。", "命薄慚勛業，才疏負聖明。", "青鞋若耶路，亦足慰平生。"]'),
('781c302d-3ea8-44aa-bb7b-dff6efc541c4','初秋四首  其四','陸游','宋','宋诗','song-poetry','','[]','兀兀終年醉，空空四壁窮。',48,'全唐诗/poet.song.134000.json','["兀兀終年醉，空空四壁窮。", "那知雙雪鬢，又度幾秋風。", "高枕三峰老，深衣獨樂翁。", "騎驢向何許，搢箠有蠻童。"]'),
('ef169589-7f08-40d0-a69c-798086d52288','秋陰出遊','陸游','宋','宋诗','song-poetry','','[]','遮日雲生忽復收，黄鴉鳴喚伴林鳩。',64,'全唐诗/poet.song.134000.json','["遮日雲生忽復收，黄鴉鳴喚伴林鳩。", "也知雨意逢秋作，未害山翁竟日遊。", "陌上驛亭雙隻堠，烟中漁釣兩三舟。", "歸遲不是尋詩料，秣蹇民家偶小留。"]'),
('f425205d-c739-4f1e-bd2b-78aac36103da','杜宇','陸游','宋','宋诗','song-poetry','','[]','杜宇雖微禽，用意舉世稀。',120,'全唐诗/poet.song.134000.json','["杜宇雖微禽，用意舉世稀。", "念昔春盛時，天地皆芳菲。", "杜宇默無聲，不畏百鳥譏。", "東君將促駕，乃獨號鳴悲。", "日夜不肯休，流血沾其衣。", "念言身尚存，乃使春獨歸。", "飲啄雖如昔，此身當疇依。", "月明抱樹枝，敢忘此歔欷。", "雖無精衛勞，區區亦庶幾。", "寄言天壤間，勿謂斯禽微。"]'),
('de0f2bc6-2e6a-4918-bd6e-f02c05d5e780','養生','陸游','宋','宋诗','song-poetry','','[]','衰病猶弱國，地與齊楚鄰。',96,'全唐诗/poet.song.134000.json','["衰病猶弱國，地與齊楚鄰。", "朝憂羽書來，暮畏戎車塵。", "奔命不敢辭，所懼殘吾民。", "羸老正類此，日夜憂其身。", "起居食飲間，恐懼自貴珍。", "一念少放逸，禍敗生逡巡。", "所以古達者，訓戒常諄諄。", "不死正爾得，成真非有神。"]'),
('7138a04a-bad6-43cb-9ba8-53475886012e','初秋夜賦二首  其一','陸游','宋','宋诗','song-poetry','','[]','北斗垂欲盡，明河淡不流。',48,'全唐诗/poet.song.134000.json','["北斗垂欲盡，明河淡不流。", "低回半枕夢，蕭瑟一窗秋。", "老益尊儒術，閑仍爲國憂。", "孰云生死大，却已付悠悠。"]'),
('bca0133b-4032-4e8a-91de-440ffed76579','初秋夜賦二首  其二','陸游','宋','宋诗','song-poetry','','[]','炎熇猶末伏，清絕忽新秋。',48,'全唐诗/poet.song.134000.json','["炎熇猶末伏，清絕忽新秋。", "露氣房櫳冷，砧聲歲月遒。", "悲蛩草根語，孤磷竹間流。", "聞道河南北，飛蝗暗百州。"]'),
('68532078-c36b-4a73-ac9e-43eac26b48de','殘年','陸游','宋','宋诗','song-poetry','','[]','殘年垂八十，高卧豈逃名。',48,'全唐诗/poet.song.134000.json','["殘年垂八十，高卧豈逃名。", "泥巷多牛迹，茅簷有碓聲。", "炊菰觴父老，煮棗哺雛嬰。", "遣戍雖傳說，何時復兩京。"]'),
('f1e368ff-edc9-4df4-95f8-6c212dcc556a','記夢','陸游','宋','宋诗','song-poetry','','[]','環立江頭千萬峰，夢中於此倚枯筇。',64,'全唐诗/poet.song.134000.json','["環立江頭千萬峰，夢中於此倚枯筇。", "青冥誰見欹巾角，碧瀣閑將洗筆鋒。", "一卷素書雲笈貯，數升松麨水機舂。", "正呼鶴駕凌風去，驚覺西山烟外鐘。"]'),
('dbe04ccc-04ac-4a55-9f2b-2f8988152b7b','村飲','陸游','宋','宋诗','song-poetry','','[]','白稻登場喜食新，太倉月廩厭陳陳。',64,'全唐诗/poet.song.134000.json','["白稻登場喜食新，太倉月廩厭陳陳。", "叢祠懷肉有歸遺，官道橫眠多醉人。", "小市孤村真送老，浩歌起舞最關身。", "鹽醯乞貸尋常事，惱亂比鄰莫愧頻。"]'),
('45e4d99b-fc45-43da-88cf-acc83c6adeb6','老鰥','陸游','宋','宋诗','song-poetry','','[]','水際山前有老鰥，終年無事亦非閑。',64,'全唐诗/poet.song.134000.json','["水際山前有老鰥，終年無事亦非閑。", "淵源師友簡編上，土木形骸魚鳥間。", "零落斷雲依釣瀨，連涓新月照柴關。", "葵羹稗飯悠然過，一飽元非造物慳。"]'),
('dc5c0501-3fc5-4816-b1b1-d9658cee74e4','對食作','陸游','宋','宋诗','song-poetry','','[]','賤士窮愁殆萬端，幸隨所遇即能安。',64,'全唐诗/poet.song.134000.json','["賤士窮愁殆萬端，幸隨所遇即能安。", "乞漿得酒豈嫌薄，賣馬僦船常覺寬。", "少壯已辜三釜養，飄零敢道一袍單。", "飯餘捫腹吾真足，苜蓿何妨日滿盤。"]'),
('d6ab5127-675c-484f-9957-68c6fc757ca0','七月十九日大風雨雷電','陸游','宋','宋诗','song-poetry','','[]','雷車動地電火明，急雨遂作盆盎傾。',64,'全唐诗/poet.song.134000.json','["雷車動地電火明，急雨遂作盆盎傾。", "强弩夾射馬陵道，屋瓦大震昆陽城。", "豈獨魚蝦空際落，真成蓋屐舍中行。", "明朝雨止尋幽夢，尚聽飛濤濺瀑聲。"]'),
('e7d16ff0-a6a7-401d-87de-f2509ee9f7ac','湖上','陸游','宋','宋诗','song-poetry','','[]','三伏無多暑漸微，登臨清曉試縑衣。',64,'全唐诗/poet.song.134000.json','["三伏無多暑漸微，登臨清曉試縑衣。", "風高病木初凋葉，潦退流萍尚半扉。", "白首重來空感昔，清尊相屬欲忘歸。", "猶憐不負湖山處，好在平生舊釣磯。"]'),
('ef52c8a0-345d-4d4b-a97a-e7a549cd94a0','欲雨','陸游','宋','宋诗','song-poetry','','[]','正苦中天赫日流，房櫳忽復變颼飀。',64,'全唐诗/poet.song.134000.json','["正苦中天赫日流，房櫳忽復變颼飀。", "雲生江浦初成暝，葉下亭皋剩作秋。", "移穴族行憐垤蟻，爭巢婦去嘆林鳩。", "人間寒暑何窮已，碪杵行聞治褐裘。"]'),
('26cc6763-c047-4b30-8f2e-0a5d6a1f9fb6','秋懷四首  其一','陸游','宋','宋诗','song-poetry','','[]','少年萬里度關河，老遇秋風感慨多。',32,'全唐诗/poet.song.134000.json','["少年萬里度關河，老遇秋風感慨多。", "草聖詩情元未減，若無明鏡奈君何。"]'),
('b24f5bcf-dcd7-4485-8765-9117e5acbecf','秋懷四首  其二','陸游','宋','宋诗','song-poetry','','[]','園丁傍架摘黄瓜，村女沿籬采碧花。',32,'全唐诗/poet.song.134000.json','["園丁傍架摘黄瓜，村女沿籬采碧花。", "城市尚餘三伏熱，秋光先到野人家。"]'),
('65fffb99-caed-4c9b-8d34-9f8a98a09e01','秋懷四首  其三','陸游','宋','宋诗','song-poetry','','[]','迢迢枕上望明河，帳薄簾疏奈冷何。',32,'全唐诗/poet.song.134000.json','["迢迢枕上望明河，帳薄簾疏奈冷何。", "不惜衣篝重換火，却緣微潤得香多。"]'),
('e47c86b4-1d93-4d8b-b2cf-dea0276ae47c','秋懷四首  其四','陸游','宋','宋诗','song-poetry','','[]','詩如水淡功差進，身似雲孤累轉輕。',32,'全唐诗/poet.song.134000.json','["詩如水淡功差進，身似雲孤累轉輕。", "落葉擁籬門巷晚，一枝藤杖且閑行。"]'),
('e51126d6-74d3-4ec7-bfec-f815afdeef8a','食新','陸游','宋','宋诗','song-poetry','','[]','龍鍾好在夢中身，剩喜今年又食新。',32,'全唐诗/poet.song.134000.json','["龍鍾好在夢中身，剩喜今年又食新。", "不用更煩人祝鯁，輪囷瓜瓠是常珍。"]'),
('d6d74d5e-5534-4460-bb4c-22d7ae4e5f72','予初仕爲寧德縣主簿而朱孝聞景參作尉情好甚篤後十餘年景參下世今又幾四十年忽夢見之若平生覺而感嘆不已','陸游','宋','宋诗','song-poetry','','[]','白鶴峰前試吏時，尉曹詩酒樂新知。',32,'全唐诗/poet.song.134000.json','["白鶴峰前試吏時，尉曹詩酒樂新知。", "傷心忽入西窗夢，同在峬村折荔枝。"]'),
('ed614ba4-6cd8-4b6d-bbc4-33b26ae445b7','讀書','陸游','宋','宋诗','song-poetry','','[]','憶昔年少時，把卷惟引睡。',96,'全唐诗/poet.song.134000.json','["憶昔年少時，把卷惟引睡。", "惰遊過日月，自咎輒涕泗。", "老來百事廢，却覺書多味。", "豈惟時有得，聖域可坐致。", "譬如入武庫，戃怳不暇視。", "淺陋安能名，出門但驚喟。", "天球及河圖，千古所共秘。", "幸今發其藏，雖老敢自棄。"]'),
('279e0da9-993b-4a11-b7f0-887bf607eb04','諭鄰人三首  其一','陸游','宋','宋诗','song-poetry','','[]','鄰曲有米當共舂，何至一旦不相容。',32,'全唐诗/poet.song.134000.json','["鄰曲有米當共舂，何至一旦不相容。", "爲善何嘗分士農，堯民皆當變時雍。"]'),
('18031370-427c-442c-9eb0-c89c67c87833','諭鄰人三首  其二','陸游','宋','宋诗','song-poetry','','[]','相攻本出忿與疑，能不終訟固已奇。',32,'全唐诗/poet.song.134000.json','["相攻本出忿與疑，能不終訟固已奇。", "訟端可窒君試思，歲時鄰里相諧嬉。"]'),
('a6839b53-f605-4cea-97ec-0a9021c807ec','諭鄰人三首  其三','陸游','宋','宋诗','song-poetry','','[]','世通婚姻對門扉，禍福饑飽常相依。',32,'全唐诗/poet.song.134000.json','["世通婚姻對門扉，禍福饑飽常相依。", "忿爭得直義愈非，不如一醉懷牒歸。"]'),
('5c97b1ad-ea5a-474f-b310-bed5ddc4c96b','示小廝二首  其一','陸游','宋','宋诗','song-poetry','','[]','偷閑打睡汝何尤，罵詈榜笞我所羞。',32,'全唐诗/poet.song.134000.json','["偷閑打睡汝何尤，罵詈榜笞我所羞。", "但搢一鞭隨小蹇，不妨村路共閑遊。"]'),
('0c6090a2-36cf-4d77-80ea-de75592473e7','示小廝二首  其二','陸游','宋','宋诗','song-poetry','','[]','晨興略整案頭書，十日庭中始掃除。',32,'全唐诗/poet.song.134000.json','["晨興略整案頭書，十日庭中始掃除。", "未免丁寧惟一事，臨池莫釣放生魚。"]'),
('3312c8be-c52e-4fdc-8d78-d03c436159f0','秋雨','陸游','宋','宋诗','song-poetry','','[]','老火阻餘威，賴此一雨洗。',72,'全唐诗/poet.song.134000.json','["老火阻餘威，賴此一雨洗。", "一雨豈遽凉，凉亦自此始。", "陂湖菱芡熟，小市新酒美。", "行歌多醉人，歡意溢閭里。", "懸知婁豐年，絲穀賤如水。", "呼兒具筆牘，作詩識吾喜。"]'),
('55dafe25-34aa-4d51-bdca-4acf7069b819','江村二首  其一','陸游','宋','宋诗','song-poetry','','[]','江村一雨喜塵清，隱隱雷車意未平。',64,'全唐诗/poet.song.134000.json','["江村一雨喜塵清，隱隱雷車意未平。", "莽蒼郊原來暮色，颼飀林壑起秋聲。", "書希簡古終難近，詩慕雄渾苦未成。", "白首愈悲知我少，從今一技不須名。"]'),
('cdba0478-62aa-4bae-a6f2-fa2b68770d2f','江村二首  其二','陸游','宋','宋诗','song-poetry','','[]','誤著儒冠不更論，白頭且喜卧江村。',64,'全唐诗/poet.song.134000.json','["誤著儒冠不更論，白頭且喜卧江村。", "林深棲鳥逐更噪，埭近過舟終夜喧。", "病起日惟翻斷簡，愁來時亦倒清尊。", "自嫌未絕知聞處，尚有僧敲月下門。"]'),
('5b24756e-8fb4-42f9-ad62-6b6b2aebff60','山行','陸游','宋','宋诗','song-poetry','','[]','南出柴門即是山，青鞋踏破白雲間。',64,'全唐诗/poet.song.134000.json','["南出柴門即是山，青鞋踏破白雲間。", "旋償酒券何時足，罷諾僧碑盡日閑。", "三尺古琴餘爨迹，一枝禪杖带湘斑。", "吾廬北望雲烟裏，又伴紛紛宿鳥還。"]'),
('dcde8204-1eef-47f4-8497-980e208a64e9','天王寺迪上人房五十年前友人王仲信同題名尚在','陸游','宋','宋诗','song-poetry','','[]','綠繞青圍古會稽，城東河上古招提。',64,'全唐诗/poet.song.134000.json','["綠繞青圍古會稽，城東河上古招提。", "巳公茅屋曾遊處，渭北山人半醉題。", "暫憩不妨停畫楫，幽尋還得杖青藜。", "舊人死盡惟殘屋，竹密雲深步步迷。"]'),
('40cd3262-46a3-467b-844b-edc10ec1ba40','東窗偶書二首  其一','陸游','宋','宋诗','song-poetry','','[]','東窗終日靜愔愔，消盡平生幻妄心。',64,'全唐诗/poet.song.134000.json','["東窗終日靜愔愔，消盡平生幻妄心。", "秋氣未催群木脫，者懷先感百蟲吟。", "屏風疊邃思廬阜，冠子峰高憶少林。", "安得吾身且强健，一藤隨處更幽尋。"]'),
('d3f20d14-43b8-4155-9525-23c598a06a74','東窗偶書二首  其二','陸游','宋','宋诗','song-poetry','','[]','萬事何曾有速淹，熊蹯魚腹自難兼。',64,'全唐诗/poet.song.134000.json','["萬事何曾有速淹，熊蹯魚腹自難兼。", "山川置掌猶能取，日月無膠可得黏。", "稚子幸堪持几杖，老生元自慣齏鹽。", "清晨臨鏡還三嘆，雪頷今年無處添。"]'),
('eb543512-067b-4d49-a6e1-55d8c13b9023','乙丑七月二十九日夜分夢一士友風度甚高一見如宿昔出詩文數紙語皆簡淡可愛讀未終而覺作長句記之','陸游','宋','宋诗','song-poetry','','[]','客中得友絕清真，蓋未傾時意已親。',64,'全唐诗/poet.song.134000.json','["客中得友絕清真，蓋未傾時意已親。", "枕冷不知清夜夢，眼明喜見老成人。", "河傾斗落三傳漏，霧散雲歸兩幻身。", "心亦了然知是妄，覺來未免一酸辛。"]'),
('1a861650-9088-4bf8-bf16-7df5dc91fcf9','示子遹','陸游','宋','宋诗','song-poetry','','[]','翁老兒窮不自支，此心幸與古人期。',64,'全唐诗/poet.song.134000.json','["翁老兒窮不自支，此心幸與古人期。", "勞兼薪水奴初去，典到琴書事可知。", "藥杵無聲工忍病，米囷可掃耻言饑。", "餘年有幾須相守，萬里烟霄付異時。"]'),
('407d00fe-9439-4da2-a6fd-66c21e724769','小雨','陸游','宋','宋诗','song-poetry','','[]','赤日炎熇勢未回，川雲忽起亦佳哉。',64,'全唐诗/poet.song.134000.json','["赤日炎熇勢未回，川雲忽起亦佳哉。", "鴨衝細雨橋陰出，蝶弄微風草際來。", "櫸柳不禁朝暮久，芙蕖猶有二三開。", "一年光景煩君看，何怪昆池有劫灰。"]'),
('3cedc965-a95b-4026-ab1d-7c1e01f8bfde','舟中作二首  其一','陸游','宋','宋诗','song-poetry','','[]','籧篨作帆三版船，漁燈夜泊閶門邊。',32,'全唐诗/poet.song.134000.json','["籧篨作帆三版船，漁燈夜泊閶門邊。", "烟波四萬八千頃，造物推排作水仙。"]'),
('c7f41847-523a-4928-86fb-aae297b7f2ac','舟中作二首  其二','陸游','宋','宋诗','song-poetry','','[]','山蔬藥苗滿箸香，超然下視太官羊。',32,'全唐诗/poet.song.134000.json','["山蔬藥苗滿箸香，超然下視太官羊。", "更憑語與劉文叔，豆鬻從來味最長。"]'),
('623270e5-40e5-4fbc-b363-ad08ea33860d','漁父二首  其一','陸游','宋','宋诗','song-poetry','','[]','食簞雖薄尚羹藜，且喜今朝酒價低。',64,'全唐诗/poet.song.134000.json','["食簞雖薄尚羹藜，且喜今朝酒價低。", "一櫂每隨潮上下，數家相望埭東西。", "團團箬笠偏宜雨，策策芒鞋不怕泥。", "應笑漆園多事在，本來無物更誰齊。"]'),
('ab077dee-7349-43a3-8de3-8ae86a85a1b9','漁父二首  其二','陸游','宋','宋诗','song-poetry','','[]','數十年來一短蓑，死期未到且婆娑。',64,'全唐诗/poet.song.134000.json','["數十年來一短蓑，死期未到且婆娑。", "敲門賒酒常酣醉，舉網無魚亦浩歌。", "片月又生紅蓼岸，孤舟常占白鷗波。", "人間各自生涯別，文叔君房愧汝多。"]'),
('53aa37e1-60a2-47c9-9c44-beaf8c0302cf','讀書示子遹','陸游','宋','宋诗','song-poetry','','[]','我生無它營，半世隨宦牒。',144,'全唐诗/poet.song.134000.json','["我生無它營，半世隨宦牒。", "讒波方稽天，憂與愁相接。", "中間稍自覺，萬事付馬曹。", "告歸幸見聽，泊與淡相遭。", "日晏突無烟，垢面有爪痕。", "讀書則未置，可笑習氣存。", "造物哀其窮，畀之大耳兒。", "兒亦好古學，乃不售有司。", "謂當鳶瑟縮，乃如鶴昂藏。", "父子共薄飯，忍饑講虞唐。", "豐兇有常數，藨蔉當自力。", "古言不吾欺，歲晚於汝食。"]'),
('a0d7c930-cf7f-4aeb-badf-e4b6ec597ee3','秋夕','陸游','宋','宋诗','song-poetry','','[]','西山樵路隔重雲，溪水微風起縠紋。',64,'全唐诗/poet.song.134000.json','["西山樵路隔重雲，溪水微風起縠紋。", "暑退忽驚秋漸晚，夜長已與晝中分。", "菰蔣入饌渾家喜，碪𥐭催寒並舍聞。", "新作篝燈學僧樣，與兒同策讀書勳。"]'),
('5bfaaaf5-8cf7-47f4-91b2-a12545698845','醉中錄近詩因題卷後','陸游','宋','宋诗','song-poetry','','[]','鵝兒色淺酒醺人，雞距鋒圜筆絕倫。',32,'全唐诗/poet.song.134000.json','["鵝兒色淺酒醺人，雞距鋒圜筆絕倫。", "滿引一杯書數紙，要知林下有閑身。"]'),
('afdb2890-691f-4f80-b766-a4b4e701d7eb','貧甚戲作絕句八首  其一','陸游','宋','宋诗','song-poetry','','[]','俸祿無餘退即耕，市人指笑太清生。',32,'全唐诗/poet.song.134000.json','["俸祿無餘退即耕，市人指笑太清生。", "從今惜取青鞋底，祗向雲邊水際行。"]'),
('940251b6-2585-400d-b8f5-011932eee876','貧甚戲作絕句八首  其二','陸游','宋','宋诗','song-poetry','','[]','處窮上策更誰如，日晏猶眠爲腹虛。',32,'全唐诗/poet.song.134000.json','["處窮上策更誰如，日晏猶眠爲腹虛。", "尚闕鄰僧分供米，敢煩地主送園蔬。"]'),
('1e9038a6-6102-4c01-8d93-c124b59fcdb9','貧甚戲作絕句八首  其三','陸游','宋','宋诗','song-poetry','','[]','貸米東村待不回，鉢孟過午未曾開。',32,'全唐诗/poet.song.134000.json','["貸米東村待不回，鉢孟過午未曾開。", "饑腸雷動尋常事，但誤生臺兩鵲來。"]'),
('c3e8e953-7b75-4f9c-badf-f60a4972398b','貧甚戲作絕句八首  其四','陸游','宋','宋诗','song-poetry','','[]','北齋孤坐破三更，庭戶無人有月明。',32,'全唐诗/poet.song.134000.json','["北齋孤坐破三更，庭戶無人有月明。", "數種袴襦秋未贖，羨他鄰巷搗衣聲。"]'),
('ac509a90-285f-4d49-a377-1b86d544dcda','貧甚戲作絕句八首  其五','陸游','宋','宋诗','song-poetry','','[]','竈突無烟甑有塵，頹垣破屋越溪濱。',32,'全唐诗/poet.song.134000.json','["竈突無烟甑有塵，頹垣破屋越溪濱。", "老鰥狂怪誰嗔責，日日行歌獨賣薪。"]'),
('48ab8e73-4af3-4286-a70e-fea31c78423c','貧甚戲作絕句八首  其六','陸游','宋','宋诗','song-poetry','','[]','行遍天涯等斷蓬，作詩博得一生窮。',32,'全唐诗/poet.song.134000.json','["行遍天涯等斷蓬，作詩博得一生窮。", "可憐老境蕭蕭夢，常在荒山破驛中。"]'),
('8a1b9cf2-b8c4-495b-998f-b8ffd82974f8','貧甚戲作絕句八首  其七','陸游','宋','宋诗','song-poetry','','[]','讀書但覺慚輪扁，補吏非能去箭張。',32,'全唐诗/poet.song.134000.json','["讀書但覺慚輪扁，補吏非能去箭張。", "白髮歸爲林下叟，固應饑不饜糟糠。"]'),
('93349026-2d8b-4b62-897a-f272fd1d9a50','貧甚戲作絕句八首  其八','陸游','宋','宋诗','song-poetry','','[]','糴米歸遲午未炊，家人竊閔乃翁饑。',32,'全唐诗/poet.song.134000.json','["糴米歸遲午未炊，家人竊閔乃翁饑。", "不知弄筆東窗下，正和淵明乞食詩。"]'),
('5a8aab2f-0bfe-4215-a884-f601ca15b1db','自儆二首  其一','陸游','宋','宋诗','song-poetry','','[]','出仕每辭榮，歸休但力耕。',48,'全唐诗/poet.song.134000.json','["出仕每辭榮，歸休但力耕。", "儉勤貧亦足，戒懼禍終輕。", "學自不欺始，智由無事行。", "書紳及銘座，勉勉盡吾生。"]'),
('d48f82fc-3edd-4851-9fbb-abaa2fd8d7e3','自儆二首  其二','陸游','宋','宋诗','song-poetry','','[]','經術吾家事，躬行更不疑。',48,'全唐诗/poet.song.134000.json','["經術吾家事，躬行更不疑。", "仁常爲己任，清每畏人知。", "古訓必三復，危途仍十思。", "兢兢死方已，寧論迫期頤。"]'),
('937cb2f3-95a6-453b-aa4a-f6a3ace63678','雨後極凉','陸游','宋','宋诗','song-poetry','','[]','金微未壯長，火老尚餘燼。',96,'全唐诗/poet.song.134000.json','["金微未壯長，火老尚餘燼。", "可憐茅舍翁，瞑目困藉躪。", "蕭蕭得一雨，天氣頗清潤。", "豈惟爽襟靈，亦足祛疾疢。", "浮生日月駛，老死纔一瞬。", "聖賢邈不嗣，利欲以身徇。", "孰能痛澡雪，此道庶少進。", "閉門君但學，妙理天豈吝。"]'),
('18d74760-b4f5-4f86-ab43-7d4f65a9d3e5','醉題','陸游','宋','宋诗','song-poetry','','[]','來往人間今幾時，悠悠日月獨心知。',64,'全唐诗/poet.song.134000.json','["來往人間今幾時，悠悠日月獨心知。", "尋僧共理清宵話，掃壁閑尋往歲詩。", "疋馬秋風入條華，孤舟暮雪釣湘漓。", "只愁又踏關河路，荆棘銅駝使我悲。"]'),
('7c0149b1-e531-4325-a944-b22ea2b27315','秋感','陸游','宋','宋诗','song-poetry','','[]','畏塗歷盡百年中，老卧窮閻一禿翁。',64,'全唐诗/poet.song.134000.json','["畏塗歷盡百年中，老卧窮閻一禿翁。", "衣杵凄凉常带月，井桐零落不禁風。", "空文久悔雕蟲技，大學方施習射功。", "萬一死前能少進，九原猶可見先公。"]'),
('82c30b11-1d23-449a-b8fd-a1b40b01f285','鼠敗書','陸游','宋','宋诗','song-poetry','','[]','雲歸雨亦止，鴉起窗既白。',120,'全唐诗/poet.song.134000.json','["雲歸雨亦止，鴉起窗既白。", "秋宵未爲永，不寐如歲隔。", "平明亟下榻，亦未暇冠幘。", "檢校案上書，狼籍鼠嚙迹。", "食簞與果籩，攘取初不責。", "侈然敢四出，乃至暴方冊。", "坐令漢篋亡，不減秦火厄。", "向能畜一貓，狡穴詎弗獲。", "緘縢又蕩然，追咎亦何益。", "惰偷當自戒，鼠輩安足磔。"]'),
('d4ab8be6-d1d3-4bab-ac45-abe721b4fffa','秋望','陸游','宋','宋诗','song-poetry','','[]','千里郊原俯莽蒼，三江烟水接微茫。',64,'全唐诗/poet.song.134000.json','["千里郊原俯莽蒼，三江烟水接微茫。", "橫林蟲鏤無全葉，新雁風驚有斷行。", "神禹祠庭遺劍佩，先秦金石古文章。", "一尊莫恨盤餐薄，終勝登樓憶故鄉。"]'),
('530fb2e2-c0bf-428f-9997-97940a6ab0aa','秋夕','陸游','宋','宋诗','song-poetry','','[]','浴罷紗巾出草堂，一枝瘦杖倚桄榔。',64,'全唐诗/poet.song.134000.json','["浴罷紗巾出草堂，一枝瘦杖倚桄榔。", "蟬吟古柳聲相續，月入幽扉影正方。", "頻約僧棋秋漸健，稍增書課夜初長。", "亦知桑落宜篘酒，太息何時辦一觴。"]'),
('b250cfe7-afeb-4404-a4b2-de212873643a','出遊','陸游','宋','宋诗','song-poetry','','[]','八月石帆秋，聊爲汗漫遊。',96,'全唐诗/poet.song.134000.json','["八月石帆秋，聊爲汗漫遊。", "本因尋友去，却爲看山留。", "小草題僧壁，長吟上驛樓。", "月能從劇飲，天可寄閑愁。", "高下評泉品，縱橫記酒籌。", "花開遇門入，水長信船流。", "骯髒人雖棄，脂韋我自羞。", "此心君不信，試往問沙鷗。"]'),
('51c2cd79-251d-4f45-bbc9-dd5ec09a28c5','病中戲詠','陸游','宋','宋诗','song-poetry','','[]','八十行加二，清秋住故山。',96,'全唐诗/poet.song.134000.json','["八十行加二，清秋住故山。", "新凉足眠睡，舊疾害躋攀。", "雪白紛殘鬢，梔黄染病顔。", "疲牛卧斜日，羸馬噍枯菅。", "貧廢兒孫學，慈生僕妾頑。", "贖衣時已迫，貸米歲方艱。", "齋鉢僧嘲薄，盤餐客笑慳。", "從今謝還往，惟有掩柴關。"]'),
('e2bde00d-9b07-4713-9426-d0c30635aa5a','書喜','陸游','宋','宋诗','song-poetry','','[]','欹斜古屋枕江干，恩賜殘骸許挂冠。',64,'全唐诗/poet.song.134000.json','["欹斜古屋枕江干，恩賜殘骸許挂冠。", "杵臼有聲聊足食，羊牛識路自歸闌。", "不求客恕陶潜醉，肯受人憐范叔寒。", "兒輩漸還家暖熱，預知燈火話團欒。"]'),
('c5b7d058-fd25-4e06-9d75-1a2cb181e222','春耕','陸游','宋','宋诗','song-poetry','','[]','去蜀歸吳會，真成萬里行。',48,'全唐诗/poet.song.134000.json','["去蜀歸吳會，真成萬里行。", "窮通竟安在，恩怨兩皆平。", "文字妨求道，杯觴害養生。", "餘年猶有幾，買犢事春耕。"]'),
('be828b00-00d2-4eff-addd-8baebbfb862f','秋思絕句六首  其一','陸游','宋','宋诗','song-poetry','','[]','烟草茫茫楚澤秋，牧童吹笛喚歸牛。',32,'全唐诗/poet.song.134000.json','["烟草茫茫楚澤秋，牧童吹笛喚歸牛。", "九衢不是風塵少，一點能來此地不。"]'),
('aae2da2d-ff9a-4be8-82f6-b9fe13b614df','秋思絕句六首  其二','陸游','宋','宋诗','song-poetry','','[]','榮悴元知豈有常，紛紛草木占年光。',32,'全唐诗/poet.song.134000.json','["榮悴元知豈有常，紛紛草木占年光。", "霜風一掃知何在，楚客從來枉斷腸。"]'),
('30196f58-836c-47af-ae60-d254b776a521','秋思絕句六首  其三','陸游','宋','宋诗','song-poetry','','[]','一片雲生便作陰，東軒草樹共蕭森。',32,'全唐诗/poet.song.134000.json','["一片雲生便作陰，東軒草樹共蕭森。", "秋風豈必關人事，自是衰翁感慨深。"]'),
('a949f9de-6441-4901-bff2-77963c8b4eec','秋思絕句六首  其四','陸游','宋','宋诗','song-poetry','','[]','枳棘編籬晝掩門，桑麻遮路不知村。',32,'全唐诗/poet.song.134000.json','["枳棘編籬晝掩門，桑麻遮路不知村。", "平生詩句傳天下，白首還家自灌園。"]'),
('01da5de3-7e03-4d52-904f-3265874fefcf','秋思絕句六首  其五','陸游','宋','宋诗','song-poetry','','[]','胸次本來容具區，自私盆盎一何愚。',32,'全唐诗/poet.song.134000.json','["胸次本來容具區，自私盆盎一何愚。", "片帆忽逐秋風起，聊試人間萬里途。"]'),
('5a54975c-528d-46e4-b3d5-3d469f79c3dc','秋思絕句六首  其六','陸游','宋','宋诗','song-poetry','','[]','黄蛺蝶輕停曲檻，紅蜻蜓小過橫塘。',32,'全唐诗/poet.song.134000.json','["黄蛺蝶輕停曲檻，紅蜻蜓小過橫塘。", "老人未肯殺風景，睡起熏籠重炷香。"]'),
('16e15134-3455-4ea8-923c-a97bbc359341','秋興','陸游','宋','宋诗','song-poetry','','[]','節物喜更新，清秋最可人。',72,'全唐诗/poet.song.134000.json','["節物喜更新，清秋最可人。", "徐行曳藤杖，小立岸紗巾。", "烟雨迷衰草，汀洲老白蘋。", "鶴巢時託宿，猿果每分珍。", "羽客期燒藥，毛人約卜鄰。", "蘭亭故不遠，千載見清真。"]'),
('11f4f85b-0d44-4e8d-9b95-01c54235d560','寓嘆','陸游','宋','宋诗','song-poetry','','[]','五畝烟蕪過半生，還山自笑又躬耕。',64,'全唐诗/poet.song.134000.json','["五畝烟蕪過半生，還山自笑又躬耕。", "舂炊不繼兒啼飯，烹飪無方客絮羹。", "遊宦人間身愈困，讀書燈下目幾盲。", "退之已老當更事，猶向時人說善鳴。"]'),
('4672036d-9b45-41eb-866f-359e25c01585','北窗','陸游','宋','宋诗','song-poetry','','[]','垂老乞骸骨，飄然辭聖朝。',72,'全唐诗/poet.song.134000.json','["垂老乞骸骨，飄然辭聖朝。", "竹頭那足用，桐尾不禁焦。", "短褐縫綀布，晨餐采藥苗。", "風霜征雁路，燈火衲僧寮。", "隴客詢安否，狸奴伴寂寥。", "北窗鳴落葉，愁絕夜迢迢。"]'),
('e8a6d991-f36c-44a4-afaf-1cf10ae639cc','閑思','陸游','宋','宋诗','song-poetry','','[]','睡美精神足，心空忿欲輕。',48,'全唐诗/poet.song.134000.json','["睡美精神足，心空忿欲輕。", "讀書無定課，飲酒不成酲。", "日日東軒坐，時時北渚行。", "最奇烏桕下，側帽聽秋鶯。"]'),
('1998487a-2797-402a-a5cf-8d1e4c2334df','秋光','陸游','宋','宋诗','song-poetry','','[]','小圃秋光潑眼來，老人憑几興悠哉。',64,'全唐诗/poet.song.134000.json','["小圃秋光潑眼來，老人憑几興悠哉。", "翩翩蝴蝶成雙過，兩兩蜀葵相背開。", "雨足疏籬引荒蔓，人稀幽徑長新苔。", "貧家竈冷炊烟晚，待得鄰翁賣藥回。"]'),
('2fee90e1-2fb8-4693-8b65-e33052d41a4a','秋夜思南鄭軍中','陸游','宋','宋诗','song-poetry','','[]','五丈原頭刁斗聲，秋風又到亞夫營。',64,'全唐诗/poet.song.134000.json','["五丈原頭刁斗聲，秋風又到亞夫營。", "昔如埋劍常思出，今作閑雲不計程。", "盛事何由觀北伐，後人誰可繼西平。", "眼昏不奈陳編得，挑盡殘燈不肯明。"]'),
('428bde86-a6a6-43a7-89a2-f4799d3ac0a0','湖上','陸游','宋','宋诗','song-poetry','','[]','飄然世外更何求，終日橋邊弄釣舟。',64,'全唐诗/poet.song.134000.json','["飄然世外更何求，終日橋邊弄釣舟。", "回視老身猶長物，縱無炊米莫閑愁。", "烟生墟落垂垂晚，雁下陂湖處處秋。", "欲覓高人竟安在，又聞長笛起滄洲。"]'),
('069402e9-ff9a-44e2-aebf-07ffedb35a6d','讀王摩詰詩愛其散髮晚未簪道書行尚把之句因用爲韵賦古風十首亦皆物外事也  其一','陸游','宋','宋诗','song-poetry','','[]','我生本江湖，歲月不可算。',72,'全唐诗/poet.song.134000.json','["我生本江湖，歲月不可算。", "采藥遊名山，所歷頗蕭散。", "一逢巢居翁，見謂於我館。", "酌泉啖松柏，每得造膝款。", "行道不自力，殘髮日已短。", "海山故不遠，謫限何時滿。"]'),
('6387507d-290a-4b17-a298-e93224623f3b','讀王摩詰詩愛其散髮晚未簪道書行尚把之句因用爲韵賦古風十首亦皆物外事也  其二','陸游','宋','宋诗','song-poetry','','[]','仕宦五十年，所至不黔突。',72,'全唐诗/poet.song.134000.json','["仕宦五十年，所至不黔突。", "取魚固捨熊，挾兔那恨鶻。", "退歸息厭厭，誰敢書咄咄。", "屋穿每茨草，驢瘦可數骨。", "秋風忽已厲，落葉襯殘月。", "脫巾坐中庭，清冷入毛髮。"]'),
('355bef32-35ed-4c82-919f-a5130d5e3a13','讀王摩詰詩愛其散髮晚未簪道書行尚把之句因用爲韵賦古風十首亦皆物外事也  其三','陸游','宋','宋诗','song-poetry','','[]','我愛古竹枝，每歌必三反。',72,'全唐诗/poet.song.134000.json','["我愛古竹枝，每歌必三反。", "孤舟上荆巫，天末未覺遠。", "最奇扇子峽，恨不遂高遯。", "荆棘蜀故宮，烟水楚廢苑。", "至今清夜夢，百丈困牽挽。", "人生如寄爾，勿嘆流年晚。"]'),
('4df35b87-5b93-4011-849c-f776b65197d2','讀王摩詰詩愛其散髮晚未簪道書行尚把之句因用爲韵賦古風十首亦皆物外事也  其四','陸游','宋','宋诗','song-poetry','','[]','往歲著朝衫，晨起事如彙。',72,'全唐诗/poet.song.134000.json','["往歲著朝衫，晨起事如彙。", "告歸卧孤村，枯淡有餘味。", "閉門絕外慕，自謂真富貴。", "蕭然畢吾生，地下亦增氣。", "里翁戀兒女，小疾輒憂畏。", "惟窮可賒死，我在君亦未。"]'),
('a1fc22bc-c1a1-43bf-9063-6dc9cd670bd0','讀王摩詰詩愛其散髮晚未簪道書行尚把之句因用爲韵賦古風十首亦皆物外事也  其五','陸游','宋','宋诗','song-poetry','','[]','萬金筑華堂，千金教新音。',72,'全唐诗/poet.song.134000.json','["萬金筑華堂，千金教新音。", "不知憂患場，著脚日愈深。", "今人喜議古，後亦將議今。", "使汝有子孫，聞之亦何心。", "鄧通擅銅山，死日無一簪。", "未死汝勿喜，五溪多毒淫。"]'),
('40a7dd94-22ca-4f8b-a0fc-c25e7bfe4d8a','讀王摩詰詩愛其散髮晚未簪道書行尚把之句因用爲韵賦古風十首亦皆物外事也  其六','陸游','宋','宋诗','song-poetry','','[]','往者遊青城，猶及二三老。',72,'全唐诗/poet.song.134000.json','["往者遊青城，猶及二三老。", "稽首出世師，數語窮至道。", "妻子真弊屣，棄去恨不早。", "俯仰纔幾時，殘骸日衰槁。", "吾兒有奇骨，亦復至幽討。", "金丹儻可成，白髮何足掃。"]'),
('a1f4be07-f555-4475-8400-8969f2ce6126','讀王摩詰詩愛其散髮晚未簪道書行尚把之句因用爲韵賦古風十首亦皆物外事也  其七','陸游','宋','宋诗','song-poetry','','[]','稚川師鄭君，纔及一卷書。',72,'全唐诗/poet.song.134000.json','["稚川師鄭君，纔及一卷書。", "書大僅如箸，度世蓋有餘。", "想其所論說，妙極軒昊初。", "內篇今雖存，亦復飽蠹魚。", "我欲探其原，蹇步空趑趄。", "安得插兩翅，從公遊太虛。"]'),
('8252c4ec-c330-4e28-ab16-b72054eb925d','讀王摩詰詩愛其散髮晚未簪道書行尚把之句因用爲韵賦古風十首亦皆物外事也  其八','陸游','宋','宋诗','song-poetry','','[]','隱書有三景，字字當力行。',72,'全唐诗/poet.song.134000.json','["隱書有三景，字字當力行。", "寸地與尺宅，可以久汝生。", "泝流歸崑虛，堅守臨長城。", "一旦告成功，河塞黄金成。", "笙鶴適緱山，貂蟬朝玉京。", "即今修行地，千古名還嬰。"]'),
('e67ac435-44c9-4319-979f-35db7b262288','讀王摩詰詩愛其散髮晚未簪道書行尚把之句因用爲韵賦古風十首亦皆物外事也  其九','陸游','宋','宋诗','song-poetry','','[]','行年過八十，形悴神則旺。',72,'全唐诗/poet.song.134000.json','["行年過八十，形悴神則旺。", "往來江湖間，垂老猶疏放。", "滄波浩無津，天遣遂微尚。", "剡溪挂風帆，漁浦理烟榜。", "奇雲出深谷，新月生疊嶂。", "興懷晉諸賢，誰能續遺唱。"]'),
('5a66a46f-f8b8-45b6-a0e1-8535db6a70c9','讀王摩詰詩愛其散髮晚未簪道書行尚把之句因用爲韵賦古風十首亦皆物外事也  其一○','陸游','宋','宋诗','song-poetry','','[]','二十遊名場，最號才智下。',72,'全唐诗/poet.song.134000.json','["二十遊名場，最號才智下。", "蹭蹬六十年，亦有茆一把。", "典衣租黄犢，乘雨耕綠野。", "西成得一飽，敢計泥沒踝。", "住久鄰好深，百事通乞假。", "秋高小甕香，相喚注老瓦。"]'),
('b26c2d8f-c7c7-43a8-93db-5531ffe47131','夢行益昌道中有賦','陸游','宋','宋诗','song-poetry','','[]','朱棧青林小益西，早行遥聽隔村雞。',64,'全唐诗/poet.song.134000.json','["朱棧青林小益西，早行遥聽隔村雞。", "龍門閤畔千尋壁，江月亭前十里堤。", "酒舍胡姬歌折柳，江津洮馬惜障泥。", "倦遊重到曾來處，自拂流塵覓舊題。"]'),
('58c8e6fc-2d8a-4831-aadb-a62a12eb6abb','自規','陸游','宋','宋诗','song-poetry','','[]','忿慾俱生一念中，聖賢本亦與人同。',64,'全唐诗/poet.song.134000.json','["忿慾俱生一念中，聖賢本亦與人同。", "此心少忍便無事，吾道力行方有功。", "碎首寧聞怨飄瓦，關弓固不慕冥鴻。", "老翁已落江湖久，分付餘年一短篷。"]'),
('f67b373b-b684-4b0d-86f0-eccbec5c15db','幽興','陸游','宋','宋诗','song-poetry','','[]','蘭渚前頭湖水清，了無俗事敗幽情。',64,'全唐诗/poet.song.134000.json','["蘭渚前頭湖水清，了無俗事敗幽情。", "雨淋茅屋隨時補，日射油窗特地明。", "庭樹晚鶯窺戶語，鄰園秋筍過籬生。", "芥菘漸美鹽醯足，誰共貧家一釜羹。"]'),
('f565bcfb-6b01-4be9-9607-8051cdf58387','記前輩語','陸游','宋','宋诗','song-poetry','','[]','疇昔見諸老，從容聞至言。',48,'全唐诗/poet.song.134000.json','["疇昔見諸老，從容聞至言。", "馬非求路寢，木豈願犧尊。", "卧起數椽屋，嘯歌三畝園。", "人生正應爾，雲夢不須吞。"]'),
('8c492b94-8462-45b4-8d11-4864dddc9bf4','貧居即事六首  其一','陸游','宋','宋诗','song-poetry','','[]','筮易常逢坎，推星但值箕。',48,'全唐诗/poet.song.134000.json','["筮易常逢坎，推星但值箕。", "老雖齊渭叟，窮不減湘纍。", "巷月鳴衣杵，庖烟爨豆萁。", "秋深病良已，且復强伸眉。"]'),
('28b2e479-b0cc-42cd-9872-6f9661894557','貧居即事六首  其二','陸游','宋','宋诗','song-poetry','','[]','地偏人罕到，秋晚日猶長。',48,'全唐诗/poet.song.134000.json','["地偏人罕到，秋晚日猶長。", "病去筇枝贅，家貧菜粥香。", "流泉通藥壟，積雨潤書囊。", "欲譜幽居事，疏慵久未遑。"]'),
('ccd4e403-00d8-4bd5-b8bd-7e8c117d4f8d','貧居即事六首  其三','陸游','宋','宋诗','song-poetry','','[]','月黑梟鳴樹，燈殘鼠穴牆。',48,'全唐诗/poet.song.134000.json','["月黑梟鳴樹，燈殘鼠穴牆。", "床空圍紙被，室靜爇楓香。", "不恨言傷直，惟憂慾敗剛。", "回頭顧名利，百世永相忘。"]'),
('cde0a55f-9911-42e3-9b4e-0db93f736d1b','貧居即事六首  其四','陸游','宋','宋诗','song-poetry','','[]','米竭炊烟靜，村深客屨稀。',48,'全唐诗/poet.song.134000.json','["米竭炊烟靜，村深客屨稀。", "庭除荒宿莽，籬落带斜暉。", "風惡披書卷，鷗馴傍釣磯。", "鄰家殊耐久，相伴荷鋤歸。"]'),
('10b39b15-74b1-4bdf-9190-3df3ac364879','貧居即事六首  其五','陸游','宋','宋诗','song-poetry','','[]','意緒喪家狗，形骸槁木枝。',48,'全唐诗/poet.song.134000.json','["意緒喪家狗，形骸槁木枝。", "曲肱雖自適，縱理固當饑。", "買絮初寒後，畦蔬小雨時。", "窮途何用卜，吾道即蓍龜。"]'),
('9ca91195-2640-4b1a-8e2c-e6c0c1d78175','貧居即事六首  其六','陸游','宋','宋诗','song-poetry','','[]','守道常違俗，存心不愧天。',48,'全唐诗/poet.song.134000.json','["守道常違俗，存心不愧天。", "終年饑過半，動步謗居前。", "力倦少行立，氣昏多睡眠。", "今宵風月好，扶杖到溪邊。"]'),
('bb9a9cca-2b39-43bc-9fe6-2fbf7a42191b','自詠','陸游','宋','宋诗','song-poetry','','[]','素慕巢居穴處民，久爲釣月卧雲身。',64,'全唐诗/poet.song.134000.json','["素慕巢居穴處民，久爲釣月卧雲身。", "經行山市求靈藥，物色旗亭訪異人。", "高枕靜聽棋剝啄，幽窗閑對石嶙峋。", "吾廬已是桃源境，不爲秦人更問津。"]'),
('0e236735-58ac-496b-a797-3ec8c8ee3872','枕上作','陸游','宋','宋诗','song-poetry','','[]','一室幽幽夢不成，高城傳漏過三更。',64,'全唐诗/poet.song.134000.json','["一室幽幽夢不成，高城傳漏過三更。", "孤燈無焰穴鼠出，枯葉有聲鄰犬行。", "壯日自期如孟博，殘年但欲慕初平。", "不然短楫棄家去，萬頃松江看月明。"]'),
('9cad7824-9080-4187-9aae-d2f519f0e506','秋曉聞禽聲五韵','陸游','宋','宋诗','song-poetry','','[]','秋曉風露佳，天宇曠以清。',60,'全唐诗/poet.song.134000.json','["秋曉風露佳，天宇曠以清。", "鳥雀當此時，意樂有和聲。", "人獨不自喜，乃欲鳴不平。", "世事雖萬端，但可笑絕纓。", "君看郊與島，徒自殘其生。"]'),
('950aeac0-d5ab-49da-813b-c5931e466d5c','對酒二首  其一','陸游','宋','宋诗','song-poetry','','[]','素月度銀漢，紅螺斟玉醪。',48,'全唐诗/poet.song.134000.json','["素月度銀漢，紅螺斟玉醪。", "染丹梨半頰，斫雪蟹雙螯。", "詩就吟逾苦，杯殘興尚豪。", "閑愁翦不斷，剩欲借并刀。"]'),
('a7768b72-1b03-4f4a-bc47-be451ffea234','對酒二首  其二','陸游','宋','宋诗','song-poetry','','[]','密汙持苫屋，寒蘆用織簾。',48,'全唐诗/poet.song.134000.json','["密汙持苫屋，寒蘆用織簾。", "彘肩柴熟罨，蓴菜豉初添。", "黄甲如盤大，紅丁似蜜甜。", "街頭桑葉落，相喚指青帘。"]'),
('3a8cc352-da18-4c41-b901-0fbf73eb90b9','示鄰里','陸游','宋','宋诗','song-poetry','','[]','古學陵夷失本原，讀書萬卷誤元元。',32,'全唐诗/poet.song.134000.json','["古學陵夷失本原，讀書萬卷誤元元。", "從今相勉躬行處，士庶人章數十言。"]'),
('83b3a59a-8ab6-417a-bcc1-476235e5e494','重示','陸游','宋','宋诗','song-poetry','','[]','篤學仁何遠，窮居道亦行。',48,'全唐诗/poet.song.134000.json','["篤學仁何遠，窮居道亦行。", "能充氣剛大，誰蔽性光明。", "家世艱難業，鄉閭宿昔情。", "歲殘相勞苦，惟是語春耕。"]'),
('5e1b945f-d30a-4375-87bf-e470b0cf4b05','雨夜起行室中','陸游','宋','宋诗','song-poetry','','[]','老疾逢秋體自輕，披衣暫起繞床行。',64,'全唐诗/poet.song.134000.json','["老疾逢秋體自輕，披衣暫起繞床行。", "隙風不斷燈將滅，簷雨如傾階欲平。", "鰥叟何嘗愁枕冷，病夫未免待窗明。", "拂書洗硯龜堂上，幽事誰知日有程。"]'),
('bebe958f-4426-49a8-8c4a-85a52a323cc5','閏月辛酉壬戌連日風雨癸亥早晴','陸游','宋','宋诗','song-poetry','','[]','殘雨在簷猶點滴，斷雲銜日正蒼凉。',64,'全唐诗/poet.song.134000.json','["殘雨在簷猶點滴，斷雲銜日正蒼凉。", "清愁偏向暮年覺，少睡不禁秋夜長。", "簾影漸生禽語樂，杵聲初動藥塵香。", "諸兒作吏俱安否，那得乘風至汝傍。"]'),
('1498a9a9-7a80-4f1a-ba8c-77dccfb02175','秋思二首  其一','陸游','宋','宋诗','song-poetry','','[]','少日猖狂不自謀，即今垂死更何求。',64,'全唐诗/poet.song.134000.json','["少日猖狂不自謀，即今垂死更何求。", "簡編不隔聖賢面，夢寐時爲河嶽遊。", "濁酒未傾心已醉，長歌欲發涕先流。", "石帆射的烟嵐晚，過雁聲中又一秋。"]'),
('03ae4964-9f41-448f-9eff-54c9a44c5695','秋思二首  其二','陸游','宋','宋诗','song-poetry','','[]','十日秋陰滿徑苔，蓬門那有客敲推。',64,'全唐诗/poet.song.134000.json','["十日秋陰滿徑苔，蓬門那有客敲推。", "水邊丹葉已如許，籬下黄花猶未開。", "空見遊僧衡嶽去，難逢新雁杜陵來。", "溪雲一片閑舒卷，戀著漁磯不肯回。"]'),
('b19a2b66-e619-4b38-88ee-fa68e544c0a0','閑遊三首  其一','陸游','宋','宋诗','song-poetry','','[]','江邊小市舊經過，歲月真如東逝波。',32,'全唐诗/poet.song.134000.json','["江邊小市舊經過，歲月真如東逝波。", "茶竈酒壚多識面，少留賣藥買漁蓑。"]'),
('c621f147-5b27-42ea-8d82-9edebc87ac13','閑遊三首  其二','陸游','宋','宋诗','song-poetry','','[]','溪橋偶與僧遊話，草市來尋逆旅炊。',32,'全唐诗/poet.song.134000.json','["溪橋偶與僧遊話，草市來尋逆旅炊。", "自笑一生爲客慣，捉驢小豎訴朝饑。"]'),
('067dd715-c151-435e-b0db-74e0c8de0f98','閑遊三首  其三','陸游','宋','宋诗','song-poetry','','[]','祓除情累烟波上，放蕩胸懷詩酒中。',32,'全唐诗/poet.song.134000.json','["祓除情累烟波上，放蕩胸懷詩酒中。", "禹會橋邊潮落處，夕陽幾度繫孤篷。"]'),
('fbbed838-81a8-4a4b-87c4-4964d2672b42','對鏡','陸游','宋','宋诗','song-poetry','','[]','面大如盤七尺身，珥貂自合上麒麟。',32,'全唐诗/poet.song.134000.json','["面大如盤七尺身，珥貂自合上麒麟。", "詩家事業君休問，不獨窮人亦瘦人。"]'),
('8ea0a501-9474-414a-8537-39ebe7656f10','幽居書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','老人初起厭囂喧，塵几從教鼠迹存。',32,'全唐诗/poet.song.134000.json','["老人初起厭囂喧，塵几從教鼠迹存。", "赤脚平頭俱遣去，倚牆危坐咽朝暾。"]'),
('066855f7-3bd5-4604-99cf-f5d417a9eed9','幽居書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','買魚賒酒皆高興，野店溪橋圖畫中。',32,'全唐诗/poet.song.134000.json','["買魚賒酒皆高興，野店溪橋圖畫中。", "從此衰翁自行耳，不須多事喚蠻童。"]'),
('f7cc1a20-381d-4357-a05e-a891d9f3ca7d','偶與客話峽中舊遊','陸游','宋','宋诗','song-poetry','','[]','我昔旅遊秋雨細，建平城東門欲閉。',96,'全唐诗/poet.song.134000.json','["我昔旅遊秋雨細，建平城東門欲閉。", "主人迎勞語蟬聯，小婦舂炊縞衣袂。", "長年三老半醉醒，蜀估峽商工算計。", "須臾燈暗人欲眠，泊船卸馱猶相繼。", "山深水嶮近蠻獠，往往居民雜椎髻。", "即今屈指四十年，懷抱凄凉真隔世。"]'),
('c4744fc8-9066-4721-be73-e6a5fb156879','讀老子次前韵','陸游','宋','宋诗','song-poetry','','[]','平生好大忽瑣細，焚香讀書戶常閉。',96,'全唐诗/poet.song.134000.json','["平生好大忽瑣細，焚香讀書戶常閉。", "少年曾預老聃役，晚歲欲挹浮丘袂。", "力探玄門窮眾妙，肯學陰謀畫奇計。", "言狂不獨人共排，志大仍憂後難繼。", "君看淡掃出繭眉，豈比一尺春風髻。", "著書勿恤飽蠹魚，會有子雲生後世。"]'),
('5bcf4567-a47f-426a-9276-6de6db05728d','作籬','陸游','宋','宋诗','song-poetry','','[]','生世八十餘，日夜迫衰老。',96,'全唐诗/poet.song.134000.json','["生世八十餘，日夜迫衰老。", "中年所筑舍，傾壞當官道。", "每逢風雨夕，性命凜莫保。", "况此蘆竹藩，何恃不摧倒。", "今朝手自葺，不暇避塗潦。", "雞豚有限隔，門巷得鋤掃。", "豈惟禦盜竊，亦足慰懷抱。", "陰雲忽四垂，見事幸差早。"]'),
('516c0394-e901-44b9-b81f-a697b0785b70','寓嘆','陸游','宋','宋诗','song-poetry','','[]','老生讀書百絕編，日晏忘食夜廢眠。',64,'全唐诗/poet.song.134000.json','["老生讀書百絕編，日晏忘食夜廢眠。", "孝經一生行不盡，况有六籍陳吾前。", "華軒玉食非素願，廣厦高墉實郵傳。", "經營歸計笑時人，我老但須書數卷。"]'),
('face733d-d6cc-4291-8116-d700e66fb7db','衡門感舊','陸游','宋','宋诗','song-poetry','','[]','蒼烟屯不散，疋素橫郊原。',96,'全唐诗/poet.song.134000.json','["蒼烟屯不散，疋素橫郊原。", "雨細不溼衣，著水始見痕。", "躊躇意自佳，未遽掩衡門。", "一一送歸鴉，楓林猶未昏。", "念昔壽州歸，紹興初紀元。", "闔門過百口，一身今獨存。", "不死實有命，送老三家村。", "躬耕幸得食，萬事不足論。"]'),
('0aa0c012-2e41-42c8-9c78-0960a3a584a1','客中作','陸游','宋','宋诗','song-poetry','','[]','江天雨霽秋光老，野氣川雲凈如掃。',96,'全唐诗/poet.song.134000.json','["江天雨霽秋光老，野氣川雲凈如掃。", "投空飛鳥雜落葉，極目斜陽襯衰草。", "平沙爭渡人鵠立，長亭下馬障泥溼。", "纍纍紅果絡青篾，未霜先摘猶酸澀。", "客中雖云貪路程，買薪糴米常留行。", "茆簷獨坐待僮僕，不聞人聲聞碓聲。"]'),
('abb897f3-85d4-4dcf-99b3-b7d461705d93','讀書示子遹','陸游','宋','宋诗','song-poetry','','[]','我性苦愛書，未始去几案。',120,'全唐诗/poet.song.134000.json','["我性苦愛書，未始去几案。", "生雖後三代，意尚卑兩漢。", "世衰道術裂，年往朋友散。", "澤居貧至骨，霜冷衣露骭。", "猶能樂其樂，肯發窮苦嘆。", "爾來更可笑，身糴兒炊爨。", "一飽輒欣然，弦誦等雝泮。", "望古雖天淵，視俗亦冰炭。", "阿遹可憐生，相守忘夜旦。", "孤學當世傳，歲月不可玩。"]'),
('84b89c1e-f459-4d6d-813a-de12b8ba0f64','老懷','陸游','宋','宋诗','song-poetry','','[]','老懷常易感，秋雨苦難晴。',48,'全唐诗/poet.song.134000.json','["老懷常易感，秋雨苦難晴。", "羈枕悲歡夢，高城長短更。", "榮枯一蟻垤，成壞幾棋枰。", "抱疾茅簷下，行人肯寄聲。"]'),
('a847c933-fe32-4001-8269-494723af5107','沉綿','陸游','宋','宋诗','song-poetry','','[]','沉綿久未平，寂寞閉柴荆。',48,'全唐诗/poet.song.134000.json','["沉綿久未平，寂寞閉柴荆。", "危葉先霜墜，殘螢冒雨明。", "記書由默誦，得食出躬耕。", "此事吾親驗，方當告後生。"]'),
('f6918e31-4f30-4b79-82ff-a418e323cba1','遊近村二首  其一','陸游','宋','宋诗','song-poetry','','[]','行歷茶岡到藥園，却從釣瀨入樵村。',64,'全唐诗/poet.song.134000.json','["行歷茶岡到藥園，却從釣瀨入樵村。", "半衰半健意蕭散，不雨不晴天晏溫。", "薯蕷傍籬寒引蔓，菖蒲絡石瘦生根。", "參差燈火茆簷晚，童稚相呼正候門。"]'),
('d9374494-c80d-4034-bf7d-91212300ed3c','遊近村二首  其二','陸游','宋','宋诗','song-poetry','','[]','被髮行歌雪滿膺，夕陽顧影亂鬅鬙。',64,'全唐诗/poet.song.134000.json','["被髮行歌雪滿膺，夕陽顧影亂鬅鬙。", "乞漿得酒人情好，賣劍買牛農事興。", "社鼓賽秋聞坎坎，塔燈照夜望層層。", "歸來閑指烏藤說，箇是人間耐久朋。"]'),
('37b90a48-9433-49f3-8c21-e0400485a47f','小亭','陸游','宋','宋诗','song-poetry','','[]','除地編茅作小亭，一川風露對青冥。',64,'全唐诗/poet.song.134000.json','["除地編茅作小亭，一川風露對青冥。", "殘螢欲盡猶穿戶，落葉初飛已滿庭。", "櫟老無心求匠石，鬼靈有說拒奴星。", "餘年默數能多少，盡付黄庭兩卷經。"]'),
('715e0f20-a5e5-4fd4-af0d-645bb3eb9084','記夢二首  其一','陸游','宋','宋诗','song-poetry','','[]','少日飛揚翰墨場，憶曾上疏動高皇。',32,'全唐诗/poet.song.134000.json','["少日飛揚翰墨場，憶曾上疏動高皇。", "寧知老作功名夢，十萬全裝入晉陽。"]'),
('633a7fe8-ba5a-4f3e-b369-d62b242f41d3','記夢二首  其二','陸游','宋','宋诗','song-poetry','','[]','老來百事不關身，北陌東阡一幅巾。',32,'全唐诗/poet.song.134000.json','["老來百事不關身，北陌東阡一幅巾。", "忽夢行軍太行路，不惟無想亦無因。"]'),
('01e9d382-c629-4977-b342-eb3889ccfd75','養疾','陸游','宋','宋诗','song-poetry','','[]','齒耄嬰新疾，才衰減舊名。',96,'全唐诗/poet.song.134000.json','["齒耄嬰新疾，才衰減舊名。", "短筇扶蹇步，小院愜幽情。", "卜叟言災退，醫翁賀脈平。", "飯香炊䆉䅉，羹美馣蕪菁。", "菊穎寒猶小，楓林曉漸頳。", "清詩披客贄，佳著指僧枰。", "家塾燈前課，村陂雨外耕。", "從今尚何事，賴此遣浮生。"]'),
('7f1fcbe0-3017-46de-8926-e715f4bb7a0f','客從城中來','陸游','宋','宋诗','song-poetry','','[]','客從城中來，相視慘不悅。',72,'全唐诗/poet.song.134000.json','["客從城中來，相視慘不悅。", "引杯撫長劍，慨嘆胡未滅。", "我亦爲悲憤，共論到明發。", "向來酣鬭時，人情願少歇。", "及今數十秋，復謂須歲月。", "諸將爾何心，安坐望旄節。"]'),
('1835b58a-899b-48f3-b344-5b6911ddce26','暮秋中夜起坐次前韵','陸游','宋','宋诗','song-poetry','','[]','東吳秋令遲，得雨亦良悅。',72,'全唐诗/poet.song.134000.json','["東吳秋令遲，得雨亦良悅。", "中庭有流螢，烈風吹不滅。", "披衣起坐久，鼓角參差發。", "西成雖作勞，農事亦漸歇。", "老怯歲律殘，俯仰忽九月。", "蟋蟀鳴壁間，愧汝知時節。"]'),
('d272b572-77a1-48e3-bf7a-0b8e1252bcbd','閑遊','陸游','宋','宋诗','song-poetry','','[]','白石床平偶小留，青芒屨穩復閑遊。',64,'全唐诗/poet.song.134000.json','["白石床平偶小留，青芒屨穩復閑遊。", "微丹點破一林綠，淡墨寫成千嶂秋。", "竹院頻分齋鉢飯，苔磯時把釣魚鈎。", "要知此老神通否，二十年來不識愁。"]'),
('36db6819-0547-4455-b701-f32bd4f8db42','自規','陸游','宋','宋诗','song-poetry','','[]','老疾今俱至，艱難亦備更。',48,'全唐诗/poet.song.134000.json','["老疾今俱至，艱難亦備更。", "箇中無障蔽，何處欠光明。", "一日能用力，三年亦有成。", "修身在我爾，勉勉盡餘生。"]'),
('34792cf9-be58-431d-94d1-4ba4cb2f3a97','自笑','陸游','宋','宋诗','song-poetry','','[]','學道功賒歲月馳，平居自笑著鞭遲。',64,'全唐诗/poet.song.134000.json','["學道功賒歲月馳，平居自笑著鞭遲。", "安心未竟夜饒夢，與世雖疏秋尚悲。", "藥圃幽尋芒屨溼，棋枰憨戰角巾欹。", "只愁今夕西窗夢，又買長筒到古郫。"]'),
('5f34d075-0152-48c4-a9f6-9b1da501b4d8','泛舟至鏡湖旁小市','陸游','宋','宋诗','song-poetry','','[]','久著朝衫負此湖，扁舟剩喜補東隅。',64,'全唐诗/poet.song.134000.json','["久著朝衫負此湖，扁舟剩喜補東隅。", "市樓合樂醅新熟，寺壁殘詩字欲無。", "常日不堪愁宛轉，此行猶得笑須臾。", "夕陽鷗鷺皆相識，更覺人間是畏塗。"]'),
('85eecd04-0be0-4693-a7fe-456132464907','懷舊','陸游','宋','宋诗','song-poetry','','[]','身是人間一斷蓬，半生南北任秋風。',64,'全唐诗/poet.song.134000.json','["身是人間一斷蓬，半生南北任秋風。", "琴書昔作天涯客，蓑笠今成澤畔翁。", "夢破江亭山驛外，詩成燈影雨聲中。", "不須强覓前人比，道似香山實不同。"]'),
('6d589e1a-e383-4264-a14e-867d3828344e','道院述懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','學道已非生死流，極知心外更何求。',64,'全唐诗/poet.song.134000.json','["學道已非生死流，極知心外更何求。", "理窮性盡命亦至，氣住神全形自留。", "大藥一爐真度世，孤桐三尺可忘憂。", "故人怪我歸來晚，太華峰頭又素秋。"]'),
('d3928599-dad5-4910-a6a0-647218a9f0ae','道院述懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','八十年前一炷香，依然餘習未全忘。',64,'全唐诗/poet.song.134000.json','["八十年前一炷香，依然餘習未全忘。", "舊緣入靜多扃戶，近爲精思別置床。", "篝火古鐺煎檜蜜，汲泉小甕釀松肪。", "老翁正似遼天鶴，更覺人間歲月長。"]'),
('35970f9b-5595-402d-b373-c6489969f575','秋雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','雨滴何由止，人眠不復成。',48,'全唐诗/poet.song.134000.json','["雨滴何由止，人眠不復成。", "雲深無雁影，村近有砧聲。", "草草殘年夢，寥寥後世名。", "太山并蟻垤，俱向酒中平。"]'),
('db588e7b-1f47-479d-96c0-8bd3894aea85','秋雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','秋晚兼旬雨，雨晴當有霜。',48,'全唐诗/poet.song.134000.json','["秋晚兼旬雨，雨晴當有霜。", "頗思遊近縣，亦已戒輕裝。", "珍𩺃披綿美，寒醅撥雪香。", "菊花常歲有，所喜及重陽。"]'),
('f03f526e-cf6e-48fb-96ef-b2dbf86667ff','聽雨','陸游','宋','宋诗','song-poetry','','[]','髮已成絲齒半摇，燈殘香盡夜迢迢。',32,'全唐诗/poet.song.134000.json','["髮已成絲齒半摇，燈殘香盡夜迢迢。", "天河不洗胸中恨，却賴簷頭雨滴消。"]'),
('0e05aa23-6156-4ee0-b46e-36527087e658','畏事','陸游','宋','宋诗','song-poetry','','[]','畏事偷安百不能，飯蔬聊得曲吾肱。',64,'全唐诗/poet.song.134000.json','["畏事偷安百不能，飯蔬聊得曲吾肱。", "舊交夢裏時時見，宿疾秋來日日增。", "遣悶自鉏幽圃藥，扶衰猶賴故溪藤。", "不因顧見鬅鬙影，全是深山退院僧。"]'),
('52f8eb68-b7c3-4f17-a55c-31756b16d9ce','刈穫後書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','鄰里西成例少蘇，貧家生業得徐圖。',64,'全唐诗/poet.song.134000.json','["鄰里西成例少蘇，貧家生業得徐圖。", "雖非五鼎豈無食，未辦複褌猶著襦。", "牢彘漸肥堪奉祭，耕牛已買不求租。", "却思流落天涯日，要是家居勝道途。"]'),
('6e396e5c-df08-497c-9874-3dac61e024df','刈穫後書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','耄歲誰知困不蘇，每虞黠鬼笑狂圖。',64,'全唐诗/poet.song.134000.json','["耄歲誰知困不蘇，每虞黠鬼笑狂圖。", "陶公老去但濁酒，管老歸來惟白襦。", "不逐兒童覓兼味，且隨鄰曲了殘租。", "細思自有欣然處，高謝人間九折途。"]'),
('19e218c7-fbb6-4e22-908c-db05987b43f7','秋夜五鼓初起坐堂上至旦','陸游','宋','宋诗','song-poetry','','[]','蒸鬰不可過，開門星滿天。',48,'全唐诗/poet.song.134000.json','["蒸鬰不可過，開門星滿天。", "身還倚藤杖，手自酌巖泉。", "雞唱猶相續，鴉飛忽已翩。", "事隨朝日出，佳思復茫然。"]'),
('0d444769-6520-437c-8a0e-7e7b599259a5','習懶自咎','陸游','宋','宋诗','song-poetry','','[]','習懶多遺事，時能害睡眠。',48,'全唐诗/poet.song.134000.json','["習懶多遺事，時能害睡眠。", "獾驕殘竹筍，鼠橫嚙床氈。", "猧子巡籬落，狸奴護簡編。", "人間有俊物，求買敢論錢。"]'),
('a201697a-3207-4ed4-9106-4435584be816','雨夜枕上作','陸游','宋','宋诗','song-poetry','','[]','雨點滴我心，雨氣傷我魂。',48,'全唐诗/poet.song.134000.json','["雨點滴我心，雨氣傷我魂。", "但憂草廬破，敢思布被溫。", "市壚酒如山，不溼老瓦盆。", "天其遂吾心，窮死三家村。"]'),
('4f966285-0304-4fdd-bef1-a1bcfa2fc41c','晚飯後步至門外並溪而歸','陸游','宋','宋诗','song-poetry','','[]','徐行摩腹出荆扉，掠面風尖酒力微。',64,'全唐诗/poet.song.134000.json','["徐行摩腹出荆扉，掠面風尖酒力微。", "市步空船迎荻去，湖堤輕擔賣魚歸。", "潺潺沙竇鳴殘水，莽莽平蕪襯落暉。", "商略最關詩思處，滿村砧杵搗秋衣。"]'),
('eb48c597-e52d-4aa2-bcd6-23704109773b','文章','陸游','宋','宋诗','song-poetry','','[]','文章如弈棋，分量固有極。',72,'全唐诗/poet.song.134000.json','["文章如弈棋，分量固有極。", "學不盡其才，識者爲太息。", "古來名世士，亦或墮此域。", "至今讀其文，曷嘗不追惜。", "士生千載後，夙慕當自力。", "如其不能然，歸哉事耕織。"]'),
('1bae40c9-fc2c-430c-87b3-7b47bf6605f8','枕上口占','陸游','宋','宋诗','song-poetry','','[]','白首區區道未明，故山悔不蚤歸耕。',64,'全唐诗/poet.song.134000.json','["白首區區道未明，故山悔不蚤歸耕。", "勇如搏虎但堪笑，學似累棋那易成。", "殘雨墮簷時一滴，老雞棲樹已三鳴。", "村居孤寂知何憾，兩耳猶勝聽市聲。"]'),
('c4b8ed98-32b5-4928-9c78-4d953369a9bd','乙丑九月三日晚久雨驟晴西南新月如玉鈎重陽以八月置閏菊花粲然滿園喜甚作一絕記之','陸游','宋','宋诗','song-poetry','','[]','初三新月見如期，重九黄花又及時。',32,'全唐诗/poet.song.134000.json','["初三新月見如期，重九黄花又及時。", "俱是人間稱心事，典衣一醉更何疑。"]'),
('c05732a1-eca3-431c-a30a-6d221eda3e76','寓嘆','陸游','宋','宋诗','song-poetry','','[]','蕭疏殘髮數莖絲，勝負渾如未算棋。',64,'全唐诗/poet.song.134000.json','["蕭疏殘髮數莖絲，勝負渾如未算棋。", "萬里旌旗無昨夢，一蓑烟雨有新詩。", "潜消暗換人誰在，小醉閑眠我自奇。", "二十四年能幾許，汾陽回首亦成癡。"]'),
('e1cd29ef-7907-4bae-a449-aaa352b9ba2b','村興','陸游','宋','宋诗','song-poetry','','[]','結宇楓林下，久窮吾所安。',48,'全唐诗/poet.song.134000.json','["結宇楓林下，久窮吾所安。", "村深事自簡，累少食差寬。", "雨暗牛眠屋，泥深鴨滿闌。", "呼兒擣粉餌，準擬賽鄱官。"]'),
('4445e6ef-e971-435a-83b2-9039c4b7f4de','夜聞埭東賣酒鼓聲譁甚','陸游','宋','宋诗','song-poetry','','[]','烏桕森疏照溪赤，寒鴉翩翻蔽天黑。',96,'全唐诗/poet.song.134000.json','["烏桕森疏照溪赤，寒鴉翩翻蔽天黑。", "鮮鱸出網重兼斤，新蟹登盤大盈尺。", "年年此際清霜夜，飯罷讀書聲滿舍。", "豈惟父子講家學，亦有朋儕結經社。", "誰令屠沽聚里中，鼓聲終夜聒老翁。", "嗚呼安得寐無聰，不但杜老左耳聾。"]'),
('a55d55cb-2e0f-485f-899f-0563c7ac2d98','燈下晚餐示子遹','陸游','宋','宋诗','song-poetry','','[]','家貧短衣不掩骭，空庖凄凄竈不爨。',96,'全唐诗/poet.song.134000.json','["家貧短衣不掩骭，空庖凄凄竈不爨。", "老翁八十忍饑熟，兀坐空堂日常旰。", "今年閏餘九月寒，那敢遽議南山炭。", "艱難幸復致一餐，餔啜燈前百憂散。", "遹子挾冊于于來，時與乃翁相論難。", "但令歆向竟同歸，門前籍湜何憂畔。"]'),
('4b4d86cf-ac80-40b1-81f3-6fcb8bba26d5','秋晚書懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','七澤三巴日月長，即今萬事付茫茫。',64,'全唐诗/poet.song.134000.json','["七澤三巴日月長，即今萬事付茫茫。", "結廬窮僻新知少，屬疾沉綿舊學荒。", "中夜飯牛初上阪，千年化鶴復還鄉。", "自憐尚覺身爲累，剩蓄荆薪待雪霜。"]'),
('2d8323fc-d6f4-4f25-9754-375867c54260','秋晚書懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','頹然兀兀復騰騰，萬事惟除死未曾。',64,'全唐诗/poet.song.134000.json','["頹然兀兀復騰騰，萬事惟除死未曾。", "無奈喜歡閑弄水，不勝頑健遠尋僧。", "喚船野岸橫斜渡，問路雲山曲折登。", "却笑吾兒多事在，夜分未滅讀書燈。"]'),
('2bbb0e8c-f43b-4d65-9226-1f3decf041ac','初寒','陸游','宋','宋诗','song-poetry','','[]','久雨重陽後，清寒小雪前。',48,'全唐诗/poet.song.134000.json','["久雨重陽後，清寒小雪前。", "拾薪椎髻僕，賣菜掘頭船。", "薄米全家粥，空床故物氈。", "身猶付一歃，名字更須傳。"]'),
('7bd77f9c-fe60-4881-9943-ee17c33f87c7','黄昏小雨中暫憩蒼頭在傍云初未嘗得瞑予乃甚適若熟寐者作五字記之','陸游','宋','宋诗','song-poetry','','[]','人看初無寐，形勞幸少休。',48,'全唐诗/poet.song.134000.json','["人看初無寐，形勞幸少休。", "夢魂雖栩栩，鼻息未齁齁。", "輕若風中絮，浮如水上漚。", "死生君了否，試向此中求。"]'),
('5df0df3c-ee2c-4efd-83e2-44332c51c2a6','乾道之初卜居三山今四十年八十有一感事抒懷','陸游','宋','宋诗','song-poetry','','[]','乾道之初結草廬，三朝六見紀元初。',64,'全唐诗/poet.song.134000.json','["乾道之初結草廬，三朝六見紀元初。", "年光拋擲雖加倍，生計蕭條愈不如。", "目暗欲盲停夜課，髮殘無幾怯晨梳。", "市聲風便猶關耳，未死終當更徙居。"]'),
('5fd8dde3-99b9-475e-b5de-6649229f3642','視東皋歸小酌二首  其一','陸游','宋','宋诗','song-poetry','','[]','筑陂下麥晚歸來，圍火烘衣始此回。',64,'全唐诗/poet.song.134000.json','["筑陂下麥晚歸來，圍火烘衣始此回。", "但得諸孫傳素業，真無一事挂靈臺。", "井桐葉落垂垂盡，籬菊花殘續續開。", "不負初寒蟹螯手，床頭小甕撥新醅。"]'),
('b1c9fe48-6ad9-4869-98ca-7d6fbe8bcb4c','視東皋歸小酌二首  其二','陸游','宋','宋诗','song-poetry','','[]','少年誤計慕浮名，更事方知外物輕。',64,'全唐诗/poet.song.134000.json','["少年誤計慕浮名，更事方知外物輕。", "身誓生生辭祿食，家當世世守農耕。", "授時堯典先精讀，陳業豳詩更力行。", "最好水村風雪夜，地爐烟暖歲豬鳴。"]'),
('356cd699-ba87-4591-9965-636cf09773f2','梅市道中二首  其一','陸游','宋','宋诗','song-poetry','','[]','去去浮官浦，悠悠數客檣。',48,'全唐诗/poet.song.134000.json','["去去浮官浦，悠悠數客檣。", "蓼花低蘸水，楓樹老經霜。", "簫鼓迎神鬧，鉏耰下麥忙。", "城西小市散，歸艇滿斜陽。"]'),
('0351c3a4-01d7-4389-b554-c90d8876f767','梅市道中二首  其二','陸游','宋','宋诗','song-poetry','','[]','雨暗山陂路，人喧古渡頭。',48,'全唐诗/poet.song.134000.json','["雨暗山陂路，人喧古渡頭。", "廟垣新畫馬，村笛遠呼牛。", "買飯諳爭席，迎潮競解舟。", "平生苦吟處，又送一年秋。"]'),
('4a658a36-6ce0-4f55-a366-77eccc32b3a1','古寺','陸游','宋','宋诗','song-poetry','','[]','秋草荒無路，來遊感廢興。',48,'全唐诗/poet.song.134000.json','["秋草荒無路，來遊感廢興。", "殘僧僅粥飯，古像冷香燈。", "扶病驚重到，題名記昔曾。", "自量難笑汝，一嘆倚枯藤。"]'),
('852e7d16-5827-4348-82ed-bb0d5cc2b3d0','夢中作二首  其一','陸游','宋','宋诗','song-poetry','','[]','繫馬朱橋上酒樓，樓前敷水拍堤流。',32,'全唐诗/poet.song.134000.json','["繫馬朱橋上酒樓，樓前敷水拍堤流。", "春風又作無情計，滿路楊花輥雪球。"]'),
('48689798-4be5-4cb3-9076-179626f0f808','夢中作二首  其二','陸游','宋','宋诗','song-poetry','','[]','大慶橋頭春雨晴，行人馬上聽鶯聲。',32,'全唐诗/poet.song.134000.json','["大慶橋頭春雨晴，行人馬上聽鶯聲。", "祥符西祀曾迎駕，惆悵無人說太平。"]'),
('97c91d06-2359-4c71-841b-34ca63787362','舟行魯墟梅市之間偶賦','陸游','宋','宋诗','song-poetry','','[]','短髮蕭蕭久挂冠，江湖到處著身寬。',64,'全唐诗/poet.song.134000.json','["短髮蕭蕭久挂冠，江湖到處著身寬。", "蓼花不逐蘋花老，桐葉常先槲葉殘。", "未卜柴荆臨峭絕，且謀蓑笠釣荒寒。", "閑人尚愧沙鷗在，始信烟波得意難。"]'),
('4446473e-c362-4dcc-ae6b-e7a1d37de52a','衰疾','陸游','宋','宋诗','song-poetry','','[]','衰疾支離負聖時，猶能采菊傍東籬。',64,'全唐诗/poet.song.134000.json','["衰疾支離負聖時，猶能采菊傍東籬。", "捉衿見肘貧無敵，聳膊成山瘦可知。", "百歲光陰半歸酒，一生事業略存詩。", "不妨舉世無同志，會有方來可與期。"]'),
('9e2fc028-663b-432f-af31-1d56eddabd3b','憶昔偶見張安國周子充劉韶美王景文陳德召任元受遺集爲之感愴作長句紓悲不知涕泗之集也','陸游','宋','宋诗','song-poetry','','[]','憶昔高皇絀柄臣，招徠賢雋聚朝紳。',64,'全唐诗/poet.song.134000.json','["憶昔高皇絀柄臣，招徠賢雋聚朝紳。", "寧知遺恨忽千載，追數同時無一人。", "薶骨九原應已朽，殘書數帙尚如新。", "此身露電那堪說，也復燈前默愴神。"]'),
('de014038-2695-4012-848a-d0d893370e25','雨後寒甚','陸游','宋','宋诗','song-poetry','','[]','陂澤連山脚，風烟接海濱。',48,'全唐诗/poet.song.134000.json','["陂澤連山脚，風烟接海濱。", "孤鴻悲遠客，殘菊伴陳人。", "酒盡瓶枵腹，爐寒客曲身。", "老翁殊耐事，一笑自回春。"]'),
('01f4770a-af7f-41b4-9bf4-04b24ad1d6c0','入冬病體差健而貧彌甚戲作','陸游','宋','宋诗','song-poetry','','[]','乞骸自喜脫風塵，北陌東阡負耒身。',64,'全唐诗/poet.song.134000.json','["乞骸自喜脫風塵，北陌東阡負耒身。", "夢裏相逢無豎子，面間時出有真人。", "閑憑曲几還終日，不出衡門動過旬。", "送老齏鹽君勿笑，天教成就一生貧。"]'),
('24a41d70-8813-4ec9-be84-91ad202ea295','蜀漢','陸游','宋','宋诗','song-poetry','','[]','憶昔遨遊蜀漢間，駸駸五十尚朱顔。',64,'全唐诗/poet.song.134000.json','["憶昔遨遊蜀漢間，駸駸五十尚朱顔。", "呼鷹雪暗天回路，采藥雲迷御愛山。", "舊事已無人共說，征途猶與夢相關。", "夕陽不覺憑闌久，待得林鴉接翅還。"]'),
('fb924e03-4763-4355-847d-a58ce3c0a5c9','新開小室','陸游','宋','宋诗','song-poetry','','[]','並簷開小室，僅可容一几。',72,'全唐诗/poet.song.134000.json','["並簷開小室，僅可容一几。", "東爲讀書窗，初日滿窗紙。", "衰眸頓清澈，不畏字如蟻。", "琅然弦誦聲，和答有稚子。", "餘年猶幾何，此事殊可喜。", "山童報炊熟，束卷可以起。"]'),
('b8183e32-fc18-4089-a7ab-7d8268681a17','初冬絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','鱸肥菰脆調羹美，蕎熟油新作餅香。',32,'全唐诗/poet.song.134000.json','["鱸肥菰脆調羹美，蕎熟油新作餅香。", "自古達人輕富貴，例緣鄉味憶還鄉。"]'),
('0dcf978c-a006-42c8-bfb2-54403c60e7d0','初冬絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','道途冬暖衣裘省，村落年豐鼓吹喧。',32,'全唐诗/poet.song.134000.json','["道途冬暖衣裘省，村落年豐鼓吹喧。", "下麥種蕎無曠土，壓桑接果有新園。"]'),
('017e1e94-2c7e-4c33-ac7f-7d91aba99791','即事六首  其一','陸游','宋','宋诗','song-poetry','','[]','雲起山容改，潮生浦面寬。',48,'全唐诗/poet.song.134000.json','["雲起山容改，潮生浦面寬。", "寒鴉先雁到，烏桕後楓丹。", "年邁狐裝帽，時新豆搗糰。", "非關嗜溫飽，更事耐悲歡。"]'),
('f18b89e1-8afc-4fa3-a723-1f1bccc993c7','即事六首  其二','陸游','宋','宋诗','song-poetry','','[]','遯居無外事，白日不勝長。',48,'全唐诗/poet.song.134000.json','["遯居無外事，白日不勝長。", "詩爲窮差進，琴雖老未忘。", "映窗精試墨，閉閤苦留香。", "年少無相誚，功名事更狂。"]'),
('5a9dd583-1fb2-4b53-ba36-76a987ae6e06','即事六首  其三','陸游','宋','宋诗','song-poetry','','[]','日上小窗東，禽鳴高樹中。',48,'全唐诗/poet.song.134000.json','["日上小窗東，禽鳴高樹中。", "樂哉容膝地，著此曲肱翁。", "香迮常遲散，兒來亦旋通。", "所慚貪坐睡，鉛槧少新功。"]'),
('5d31c2eb-37a4-4e66-a1f1-d618411f2326','即事六首  其四','陸游','宋','宋诗','song-poetry','','[]','紙潔晴窗暖，粳新午飯香。',48,'全唐诗/poet.song.134000.json','["紙潔晴窗暖，粳新午飯香。", "嗜眠爲至樂，省事是奇方。", "孤蝶弄秋色，亂鴉啼夕陽。", "詩情隨處有，信筆自成章。"]'),
('c8cf3a1e-256e-4801-9a57-1bfc473f0a02','即事六首  其五','陸游','宋','宋诗','song-poetry','','[]','井稅無餘負，川原已飽犁。',48,'全唐诗/poet.song.134000.json','["井稅無餘負，川原已飽犁。", "樵歌歸市步，帆影過河堤。", "野實丹兼漆，村醪蜜與齏。", "雖云有豐約，不廢醉如泥。"]'),
('672095fc-5e79-4c2a-a1b0-94ad4d7e5d10','即事六首  其六','陸游','宋','宋诗','song-poetry','','[]','還鄉吳語熟，伏枕越吟悲。',48,'全唐诗/poet.song.134000.json','["還鄉吳語熟，伏枕越吟悲。", "接客寒溫簡，過鄰几杖隨。", "獨嗟親舊少，不覺歲時移。", "陌上人爭看，風欹白接䍦。"]'),
('e0c441bf-0cda-4d67-a188-2e2485424cc5','閑吟','陸游','宋','宋诗','song-poetry','','[]','閑吟可是治愁藥，一展吳箋萬事忘。',32,'全唐诗/poet.song.134000.json','["閑吟可是治愁藥，一展吳箋萬事忘。", "不惜暮年酬倡絕，猶能作意答秋光。"]'),
('58cb0e2a-1615-4688-bd33-d69f18e8b72a','自遣','陸游','宋','宋诗','song-poetry','','[]','衣冠尚作閑身祟，粱肉終非退士宜。',32,'全唐诗/poet.song.134000.json','["衣冠尚作閑身祟，粱肉終非退士宜。", "惟有褐裘并豆飯，尚能相伴到期頤。"]'),
('c25b89f6-8719-4ead-b365-7b9c4baa0ef9','記乙丑十月一日夜夢二首  其一','陸游','宋','宋诗','song-poetry','','[]','夢裏江淮道上行，解裝掃榻喜新晴。',32,'全唐诗/poet.song.134000.json','["夢裏江淮道上行，解裝掃榻喜新晴。", "店門邂逅綈袍客，共把茶甌說養生。"]'),
('874c4f61-3015-43a8-92bf-54ee0b4b97ad','記乙丑十月一日夜夢二首  其二','陸游','宋','宋诗','song-poetry','','[]','旋糴街頭米數升，黄昏看上店身燈。',32,'全唐诗/poet.song.134000.json','["旋糴街頭米數升，黄昏看上店身燈。", "明朝山路聞饒石，買得烏騾喜不勝。"]'),
('aaeedaaa-fac2-4a7f-924a-7a05d55f5494','縱遊','陸游','宋','宋诗','song-poetry','','[]','人事元知不可諧，名山踏破幾青鞋。',64,'全唐诗/poet.song.134000.json','["人事元知不可諧，名山踏破幾青鞋。", "百錢挂杖無時醉，一鍤隨身到處埋。", "驛壁讀詩摩病眼，僧窗看竹散幽懷。", "亦知詩料無窮盡，燈火蕭疏過縣街。"]'),
('e00eed1f-e52b-4ee1-9218-161dd96324a6','村居書事六首  其一','陸游','宋','宋诗','song-poetry','','[]','過門車馬誰曾入，塞路蓬蒿不復鋤。',32,'全唐诗/poet.song.134000.json','["過門車馬誰曾入，塞路蓬蒿不復鋤。", "雨漏日惟支敗屋，鼠餘時自緝殘書。"]'),
('8a73b08b-d83d-41e4-a417-771b41f74ca1','村居書事六首  其二','陸游','宋','宋诗','song-poetry','','[]','矮瓶煮粥猶難繼，小甑蒸糕豈解常。',32,'全唐诗/poet.song.134000.json','["矮瓶煮粥猶難繼，小甑蒸糕豈解常。", "偶得鹽醯便豪侈，晨餐滿舍野蔬香。"]'),
('9d56f661-5295-4925-ba4f-17a8883e98ff','村居書事六首  其三','陸游','宋','宋诗','song-poetry','','[]','架橋筑路村翁事，裂網伸鈎老嫗心。',32,'全唐诗/poet.song.134000.json','["架橋筑路村翁事，裂網伸鈎老嫗心。", "自笑年來足衰態，軒昂故步懶重尋。"]'),
('272d4e06-359a-45c7-b6bb-749c2e8acbf4','村居書事六首  其四','陸游','宋','宋诗','song-poetry','','[]','書收鼠嚙猶堪讀，柿拾鴉殘亦自甜。',32,'全唐诗/poet.song.134000.json','["書收鼠嚙猶堪讀，柿拾鴉殘亦自甜。", "動念不如姑省事，智謀老健恐難兼。"]'),
('3bf5e43a-e117-4175-a471-faf1d11eda79','村居書事六首  其五','陸游','宋','宋诗','song-poetry','','[]','修身世世詩書業，營利明明市井人。',32,'全唐诗/poet.song.134000.json','["修身世世詩書業，營利明明市井人。", "安得後生俱自好，百年門戶本來貧。"]'),
('cb3798fa-2aa3-4ac2-9e08-0118fb857484','村居書事六首  其六','陸游','宋','宋诗','song-poetry','','[]','文辭苦思徒妨睡，官職虛名不療饑。',32,'全唐诗/poet.song.134000.json','["文辭苦思徒妨睡，官職虛名不療饑。", "垂老始知安樂法，紙鳶竹馬伴兒嬉。"]'),
('6a720762-b542-42d1-8ab4-6f8c26ae8c5b','湖堤暮歸','陸游','宋','宋诗','song-poetry','','[]','出郭並湖無十里，我歸蟹舍過魚梁。',64,'全唐诗/poet.song.134000.json','["出郭並湖無十里，我歸蟹舍過魚梁。", "川雲蒼白不成雨，汀樹青紅初著霜。", "俗孝家家供菽水，農勤處處筑陂塘。", "樂哉追逐鄉三老，半醉行歌詠歲穰。"]'),
('852077a7-fbb1-4d0a-8cf8-ffc08bbd57c5','題搨本姜楚公鷹二首  其一','陸游','宋','宋诗','song-poetry','','[]','憶昔呼鷹塞草枯，妖狐狡兔笑談無。',32,'全唐诗/poet.song.134000.json','["憶昔呼鷹塞草枯，妖狐狡兔笑談無。", "明窗見畫空三嘆，恍若霜郊遇獵徒。"]'),
('2ac82ec7-0e86-43cd-af36-a18cbab279ba','題搨本姜楚公鷹二首  其二','陸游','宋','宋诗','song-poetry','','[]','弓面霜寒斗力增，坐思鐵馬蹴河冰。',32,'全唐诗/poet.song.134000.json','["弓面霜寒斗力增，坐思鐵馬蹴河冰。", "海東俊鶻何由得，空看綿州舊畫鷹。"]'),
('d6c2ef88-2f4c-49ad-b7de-64788f35c0b8','書巢五詠 硯滴','陸游','宋','宋诗','song-poetry','','[]','銅之在人間，細大各有境。',48,'全唐诗/poet.song.134000.json','["銅之在人間，細大各有境。", "散爲五銖貨，聚作九牧鼎。", "天祿與辟邪，乃復參泓穎。", "致用孰相須，寒泉出金井。"]'),
('b7539cda-7d02-48a1-8cfe-dadeca086987','書巢五詠 砑蠡','陸游','宋','宋诗','song-poetry','','[]','古者貝爲貨，庶物賴以通。',48,'全唐诗/poet.song.134000.json','["古者貝爲貨，庶物賴以通。", "後世貴銅臭，退處書几中。", "楮生借光輝，文字傳亡窮。", "言利古所羞，孰謂汝不逢。"]'),
('87ad2bd1-9760-4835-a41b-3bf53e13d3de','書巢五詠 故紙','陸游','宋','宋诗','song-poetry','','[]','時來偶見收，過時自當退。',48,'全唐诗/poet.song.134000.json','["時來偶見收，過時自當退。", "豈惟裁紙尾，亦或用牘背。", "人情有貴賤，志士感興廢。", "庫中九萬張，視我猶前輩。"]'),
('d4fcf045-81dc-4de2-861c-6a7b297f12f7','書巢五詠 折墨','陸游','宋','宋诗','song-poetry','','[]','鸞膠擣松烟，成此金石姿。',48,'全唐诗/poet.song.134000.json','["鸞膠擣松烟，成此金石姿。", "雖以剛故折，挺特終不移。", "微功在簡冊，敢惜身蹈危。", "雖非破硯文，永世亦有辭。"]'),
('23a4eac7-790e-4bcc-b23b-ad340d661a8f','書巢五詠 空酒壺','陸游','宋','宋诗','song-poetry','','[]','銅壺受五升，中貯太古醇。',48,'全唐诗/poet.song.134000.json','["銅壺受五升，中貯太古醇。", "相從亦已久，一朝委流塵。", "我豈少恩哉，白頭乃如新。", "誰知矮道士，亦作斥仙人。"]'),
('560e0b6f-9691-4d17-bc65-aa872439b8fb','感遇六首  其一','陸游','宋','宋诗','song-poetry','','[]','仕宦五十年，終不慕熱官。',72,'全唐诗/poet.song.134000.json','["仕宦五十年，終不慕熱官。", "年齡過八十，久已辦一棺。", "結廬十餘間，著身如海寬。", "此外皆長物，簡去心始安。", "稱意多怒嗔，易可出艱難。", "我無狐白裘，短褐亦禦寒。"]'),
('38c9605f-edfb-42e1-b9e1-eccc5ffe3a2f','感遇六首  其二','陸游','宋','宋诗','song-poetry','','[]','士方貧賤時，藜藿苦不足。',72,'全唐诗/poet.song.134000.json','["士方貧賤時，藜藿苦不足。", "一朝得富貴，奴僕饜粱肉。", "大胾食亞夫，空器饋荀彧。", "何如茆簷下，父子共饘粥。", "我生有至願，世世謝寸祿。", "有子復有孫，無榮亦無辱。"]'),
('cefefafb-73ea-4acc-9f56-6d4f98e3fee4','感遇六首  其三','陸游','宋','宋诗','song-poetry','','[]','人之所甚患，饑渴與寒暑。',72,'全唐诗/poet.song.134000.json','["人之所甚患，饑渴與寒暑。", "粗免則已矣，過計安用許。", "自奉非其分，三彭將嫉汝。", "寓形天壤間，大抵皆逆旅。", "但能飽菜根，何地不可處。", "堂堂七尺軀，切勿效兒女。"]'),
('73011173-5343-4d6b-ab21-a75b50bd9d74','感遇六首  其四','陸游','宋','宋诗','song-poetry','','[]','我以善勉汝，汝謂出訾毀。',72,'全唐诗/poet.song.134000.json','["我以善勉汝，汝謂出訾毀。", "置之不復言，意又不能已。", "爲善如筑臺，成功由積累。", "中休猶不可，况本無基址。", "未言破萬卷，日且讀十紙。", "學雖在力行，要是從此始。"]'),
('6e57fa5f-3622-4fa0-b5dc-813a428700d4','感遇六首  其五','陸游','宋','宋诗','song-poetry','','[]','我初居三山，同里數十人。',84,'全唐诗/poet.song.134000.json','["我初居三山，同里數十人。", "尊酒相勞苦，言辭亦諄諄。", "去來四十年，皆成冢中塵。", "子孫雖或存，敗屋賣作薪。", "此亦何罪哉，不過坐一貧。", "我幸未至此，亦復拙謀身。", "無飯可哺汝，觸目成悲辛。"]'),
('8a36de6e-4fea-4a0f-9503-f40caaf0ebd6','感遇六首  其六','陸游','宋','宋诗','song-poetry','','[]','人與人爲徒，事我蓋有緣。',72,'全唐诗/poet.song.134000.json','["人與人爲徒，事我蓋有緣。", "司晨與警夜，異類亦可憐。", "舐糠啄遺粒，要使全其天。", "人則當教誨，見善或能遷。", "盛怒姑小忍，雖蒲豈非鞭。", "事過我亦喜，陶然送流年。"]'),
('f665bcf1-c78c-4518-ba38-a034b4814a7a','幽興','陸游','宋','宋诗','song-poetry','','[]','老向浮生意漸闌，飄然俟死水雲間。',64,'全唐诗/poet.song.134000.json','["老向浮生意漸闌，飄然俟死水雲間。", "龜支床穩新寒夜，鶴附書歸舊隱山。", "無意詩方近平淡，絕交夢亦覺清閑。", "一端更出淵明上，寂寂柴門本不關。"]'),
('abd6eb95-cde7-4182-a87d-98080578a53b','題詹仲信所藏米元暉雲山小幅二首  其一','陸游','宋','宋诗','song-poetry','','[]','俗韵凡情一點無，開元以上立規模。',32,'全唐诗/poet.song.134000.json','["俗韵凡情一點無，開元以上立規模。", "鏡湖老監空揮泪，想見楚江清曉圖。"]'),
('11218dde-262e-4883-93f0-63cb301f23d5','題詹仲信所藏米元暉雲山小幅二首  其二','陸游','宋','宋诗','song-poetry','','[]','一棹朝南暮北風，奇峰倒影綠波中。',32,'全唐诗/poet.song.134000.json','["一棹朝南暮北風，奇峰倒影綠波中。", "定知漸近三山路，認得漁翁是放翁。"]'),
('4b881806-de4a-4a9b-b713-a00e79926ea0','詹仲信以山水二軸爲壽固辭不可乃各作一絕句謝之 春山','陸游','宋','宋诗','song-poetry','','[]','策蹇渡橋春雨餘，亂山缺處草亭孤。',32,'全唐诗/poet.song.134000.json','["策蹇渡橋春雨餘，亂山缺處草亭孤。", "不知何許丹青手，畫我當年入蜀圖。"]'),
('83de9a7f-3e28-4090-8447-c8604e829b42','詹仲信以山水二軸爲壽固辭不可乃各作一絕句謝之 雪山','陸游','宋','宋诗','song-poetry','','[]','雪崦梅村一徑斜，茆簷烟火兩三家。',32,'全唐诗/poet.song.134000.json','["雪崦梅村一徑斜，茆簷烟火兩三家。", "眼明見此幽栖地，却恨吾廬已太奢。"]'),
('e3eaff18-4947-4e76-a854-3fb46b398e42','有所懷','陸游','宋','宋诗','song-poetry','','[]','鏡裏形模日夜衰，三峰師友久睽離。',64,'全唐诗/poet.song.134000.json','["鏡裏形模日夜衰，三峰師友久睽離。", "芝房又失耘鋤候，丹劑常思沐浴時。", "雷雨未成龍起晚，海天無際鶴歸遲。", "午窗一鉢青精飯，揀得香薪手自炊。"]'),
('bebbe11e-b960-47be-b996-3f7ba2f62e3a','自嘲老態','陸游','宋','宋诗','song-poetry','','[]','世念秋毫盡，渾如學語兒。',48,'全唐诗/poet.song.134000.json','["世念秋毫盡，渾如學語兒。", "得床眠易熟，有飯食無時。", "紗帽簪花舞，盆池弄水嬉。", "從今轉無事，靜坐不吟詩。"]'),
('7aba1c01-2828-44a7-8170-10efac95ca0c','十月十四夜夢與客分題得早行','陸游','宋','宋诗','song-poetry','','[]','蓐食寒燈下，脂車小市傍。',48,'全唐诗/poet.song.134000.json','["蓐食寒燈下，脂車小市傍。", "驛門猶淡月，街樹正清霜。", "觸目關河異，興懷道路長。", "丈夫當自力，雙鬢易蒼蒼。"]'),
('28cf2c79-1b36-47f0-90c0-d3ca0cb3f2ba','紹興中予初仕爲寧德主簿與同官飲酒食蠣房甚樂後五十年有餉此味者感嘆有賦酒海者大勸杯容一升當時所尚也','陸游','宋','宋诗','song-poetry','','[]','昔仕閩江日，民淳簿領閑。',48,'全唐诗/poet.song.134000.json','["昔仕閩江日，民淳簿領閑。", "同寮飛酒海，小吏擘蠔山。", "夢境悠然逝，羸軀獨爾頑。", "所嗟晨鏡裏，非復舊朱顔。"]'),
('94c9b469-67a1-4b5b-82b2-8d1281943cb5','病中雨夜','陸游','宋','宋诗','song-poetry','','[]','蹭蹬今如此，沉綿不復支。',48,'全唐诗/poet.song.134000.json','["蹭蹬今如此，沉綿不復支。", "心隨形共顇，年與智俱衰。", "雨急孤燈暗，雲深斷雁悲。", "舊書空滿架，惆悵負明時。"]'),
('4e2965d2-7b15-40e0-825c-a99d56f69766','讀呂舍人詩追次其韵五首  其一','陸游','宋','宋诗','song-poetry','','[]','士生始從學，取友實先務。',48,'全唐诗/poet.song.134000.json','["士生始從學，取友實先務。", "吾聞諸古人，傾蓋有如故。", "漢宮長生藥，至取雲表露。", "治身當何如，而受一塵污。"]'),
('918c3411-3f52-43fe-9f9c-914226999600','讀呂舍人詩追次其韵五首  其二','陸游','宋','宋诗','song-poetry','','[]','有過當相規，有善當相告。',48,'全唐诗/poet.song.134000.json','["有過當相規，有善當相告。", "豈惟定新交，亦以篤舊好。", "勢利古所羞，置之勿復道。", "霜霣萬木凋，孰秉歲寒操。"]'),
('e37fe38b-0cdf-4cfb-90b2-88520117b0b7','讀呂舍人詩追次其韵五首  其三','陸游','宋','宋诗','song-poetry','','[]','少壯如昨日，忽已及耄期。',48,'全唐诗/poet.song.134000.json','["少壯如昨日，忽已及耄期。", "舊友散莫收，亦復少新知。", "言歸鏡湖上，日日醉東籬。", "自笑如寒蝶，裴回殘菊枝。"]'),
('3b52c3bd-cc86-4e50-ac42-0d3ee9029281','讀呂舍人詩追次其韵五首  其四','陸游','宋','宋诗','song-poetry','','[]','道士成金丹，青雲可接翼。',48,'全唐诗/poet.song.134000.json','["道士成金丹，青雲可接翼。", "小夫豈知此，危坐學數息。", "如持一畚土，自謂河可塞。", "生不遇碩師，幾何不自賊。"]'),
('079eae51-2c12-4e8e-9289-cf6b7be05282','讀呂舍人詩追次其韵五首  其五','陸游','宋','宋诗','song-poetry','','[]','三沐復三熏，佩玉懷明珠。',48,'全唐诗/poet.song.134000.json','["三沐復三熏，佩玉懷明珠。", "何至不自珍，欲效豕負塗。", "傳呼雖甚寵，正可誇群奴。", "君看魏徵孫，世世爲農夫。"]'),
('c7dbef75-6d1a-4f78-b9c0-a91464e2bf4e','庵中晚思','陸游','宋','宋诗','song-poetry','','[]','小庵摩腹獨彷徉，俗事紛紛有底忙。',64,'全唐诗/poet.song.134000.json','["小庵摩腹獨彷徉，俗事紛紛有底忙。", "雲影忽生鴉蔽日，雨聲不斷葉飛霜。", "經綸正復慚伊傅，雜駁猶能陋漢唐。", "卷盡殘書窗已晚，笑呼童子換爐香。"]'),
('cba2391f-b8fc-4bf3-8cf8-eae11a7ff56d','枕上','陸游','宋','宋诗','song-poetry','','[]','熒熒地爐火，煮藥土床前。',48,'全唐诗/poet.song.134000.json','["熒熒地爐火，煮藥土床前。", "高帝老朝士，長安舊少年。", "松高露時滴，城遠鼓猶傳。", "拋擲百年事，且安殘夜眠。"]'),
('b43d937d-2e06-48eb-94bb-72326f62cd3b','冬夜','陸游','宋','宋诗','song-poetry','','[]','杞菊家風有自來，充饑藜糝不盈杯。',64,'全唐诗/poet.song.134000.json','["杞菊家風有自來，充饑藜糝不盈杯。", "雲迷野渡一聲雁，雪暗山村千樹梅。", "宴坐何妨面庵壁，長吟且復畫爐灰。", "歲殘尚恨新春遠，欲挽天邊斗柄回。"]'),
('ec048123-b70e-4437-9338-1f527beaa82d','雜興二首  其一','陸游','宋','宋诗','song-poetry','','[]','陋巷無心長草萊，柴門偶自不曾開。',64,'全唐诗/poet.song.134000.json','["陋巷無心長草萊，柴門偶自不曾開。", "餘齡漸迫諸孫長，徂歲將窮積雪來。", "旦欲燎衣無宿燼，暮思頳頰但空罍。", "孰知自有忘憂處，繞坐新書正作堆。"]'),
('28fbbde2-e73d-4849-8d1a-498f4c36f2fa','雜興二首  其二','陸游','宋','宋诗','song-poetry','','[]','此身漂蕩等流槎，又向江村送歲華。',64,'全唐诗/poet.song.134000.json','["此身漂蕩等流槎，又向江村送歲華。", "急雨遇寒凝作雪，明燈無灺結成花。", "座懸鏡古森毛髮，甌聚茶香爽齒牙。", "况是貧家多樂事，阿開漸學手吒叉。"]'),
('03682b6f-97f3-443d-92ec-7c25d67bea5d','稽山行','陸游','宋','宋诗','song-poetry','','[]','稽山何巍巍，浙江水湯湯。',240,'全唐诗/poet.song.134000.json','["稽山何巍巍，浙江水湯湯。", "千里亙大野，勾踐之所荒。", "春雨桑柘綠，秋風秔稻香。", "村村作蟹椴，處處起魚梁。", "陂放萬頭鴨，園覆千畦薑。", "舂碓聲如雷，私債逾官倉。", "禹廟爭奉牲，蘭亭共流觴。", "空巷看競渡，倒社觀戲埸。", "項里楊梅熟，采摘日夜忙。", "翠籃滿山路，不數荔枝筐。", "星馳入侯家，那惜黄金償。", "湘湖蓴菜出，賣者環三鄉。", "何以共烹煮，鱸魚三尺長。", "芳鮮初上市，羊酪何足當。", "鏡湖滀眾水，自漢無旱蝗。", "重樓與曲檻，瀲灧浮湖光。", "舟行以當車，小繖遮新粧。", "淺坊小陌間，深夜理絲簧。", "我老述此詩，妄繼古樂章。", "恨無季札聽，大國風泱泱。"]'),
('82b66fa8-537f-4b38-9d63-08ad063b2d9b','贈論命周雲秀才','陸游','宋','宋诗','song-poetry','','[]','周郎頎然市中隱，精神卓犖秋天隼。',96,'全唐诗/poet.song.134000.json','["周郎頎然市中隱，精神卓犖秋天隼。", "忽來過我論五行，袖出詩卷如束筍。", "人生一息不自保，况我耄期真待盡。", "君今盛爲談未來，我亦聽之俱可囅。", "雖然此心猶未泯，何至死去同蠢蠢。", "地下不作修文郎，天上亦爲京兆尹。"]'),
('a910fc01-a7f0-4e84-97af-ed7e1bca9384','自嘲','陸游','宋','宋诗','song-poetry','','[]','受福元無一羽輕，豈知造物假餘生。',64,'全唐诗/poet.song.134000.json','["受福元無一羽輕，豈知造物假餘生。", "抱痾不死躋高壽，遇亂能全見太平。", "投渚斷鴻常自閔，營巢倦鵲固難成。", "乘除亦有堪慚處，記誦文辭誤得名。"]'),
('0ab4da49-cb26-4b37-a98c-94db0d6bb018','自寬','陸游','宋','宋诗','song-poetry','','[]','兀兀空齋靜掩扉，篝爐香細著秋衣。',64,'全唐诗/poet.song.134000.json','["兀兀空齋靜掩扉，篝爐香細著秋衣。", "簷頭殘雨晴猶滴，欄角羈雲晚未歸。", "支枕口和心共語，挑燈形與影相依。", "卷書未覺唐虞遠，知我何妨舉世稀。"]'),
('8174e1a4-b695-4b96-b2db-0139c7b29c65','唐虞','陸游','宋','宋诗','song-poetry','','[]','唐虞雖遠愈巍巍，孔氏如天孰得違。',64,'全唐诗/poet.song.134000.json','["唐虞雖遠愈巍巍，孔氏如天孰得違。", "大道豈容私學裂，專門常怪世儒非。", "少林尚忌隨人轉，老氏亦尊知我稀。", "能盡此心方有得，勿持糟粕議精微。"]'),
('f41c3f72-1485-476d-967d-2b2dbfff850e','幽事絕句六首  其一','陸游','宋','宋诗','song-poetry','','[]','死生歸有命，榮悴出無心。',24,'全唐诗/poet.song.134000.json','["死生歸有命，榮悴出無心。", "苔井閑磨劍，松窗自斲琴。"]'),
('d74955cc-ea06-499a-9fa7-6cca7d8a4d62','幽事絕句六首  其二','陸游','宋','宋诗','song-poetry','','[]','矮紙來吳下，長毫出宛陵。',24,'全唐诗/poet.song.134000.json','["矮紙來吳下，長毫出宛陵。", "自書霜夜句，持寄剡中僧。"]'),
('a67147dd-4088-4322-bfad-053f7ef69c60','幽事絕句六首  其三','陸游','宋','宋诗','song-poetry','','[]','昨日風掀屋，今朝雨壞牆。',24,'全唐诗/poet.song.134000.json','["昨日風掀屋，今朝雨壞牆。", "雖知炊米盡，不廢野歌長。"]'),
('90191694-3d38-462f-801a-39f30a2b6578','幽事絕句六首  其四','陸游','宋','宋诗','song-poetry','','[]','烟畦朝斸藥，雪澗夜淘丹。',24,'全唐诗/poet.song.134000.json','["烟畦朝斸藥，雪澗夜淘丹。", "仄徑何曾嶮，單袍不覺寒。"]'),
('d3cf7abd-ef47-41f2-8d6b-3e0a12d072af','幽事絕句六首  其五','陸游','宋','宋诗','song-poetry','','[]','新傳服氣訣，舊喜步虛吟。',24,'全唐诗/poet.song.134000.json','["新傳服氣訣，舊喜步虛吟。", "兒女不難棄，雲山何處深。"]'),
('f1820073-ebf8-45ca-8331-88598f3ff905','幽事絕句六首  其六','陸游','宋','宋诗','song-poetry','','[]','客生聞吠犬，草茂有鳴蛙。',24,'全唐诗/poet.song.134000.json','["客生聞吠犬，草茂有鳴蛙。", "日昳方炊飯，秋深始采茶。"]'),
('5f1924ee-7805-48a9-b726-422248ba641c','寄題廬陵王晉輔先輩桂堂','陸游','宋','宋诗','song-poetry','','[]','楚人記草木，桂在椒蘭中。',96,'全唐诗/poet.song.134000.json','["楚人記草木，桂在椒蘭中。", "我懷小山句，妙絕窮化工。", "唐人作山水，亦以桂配松。", "丹葩間綠葉，錦繡相疊重。", "不知始何時，巖桂開秋風。", "楚人所稱者，委棄等蒿蓬。", "嗚呼各有時，士豈怨不逢。", "我作桂堂詩，廣子雲夢胸。"]'),
('e71c46d1-6c05-4624-b928-aa7d43e6827f','寄題王晉輔專春堂','陸游','宋','宋诗','song-poetry','','[]','三月風光不貸人，千紅百紫已成塵。',32,'全唐诗/poet.song.134000.json','["三月風光不貸人，千紅百紫已成塵。", "牡丹底事開偏晚，本自無心獨占春。"]'),
('0491fde9-3b37-4d54-841c-967e80641f22','鼠屢敗吾書偶得狸奴捕殺無虛日群鼠幾空爲賦此詩','陸游','宋','宋诗','song-poetry','','[]','服役無人自炷香，狸奴乃肯伴禪房。',64,'全唐诗/poet.song.134000.json','["服役無人自炷香，狸奴乃肯伴禪房。", "晝眠共藉床敷暖，夜坐同聞漏鼓長。", "賈勇遂能空鼠穴，策勛何止履胡腸。", "魚餐雖薄真無愧，不向花間捕蝶忙。"]'),
('675fbea1-c31f-4faa-b697-27a9379265ec','讀唐書忠義傳','陸游','宋','宋诗','song-poetry','','[]','志士慕古人，忠臣挺奇節。',48,'全唐诗/poet.song.134000.json','["志士慕古人，忠臣挺奇節。", "就死有處所，天日爲無色。", "大義孰不知，臨難欠健决。", "我思杲卿髮，可配嵇紹血。"]'),
('3f2fd1db-d108-46f6-80db-e5a682e5762b','病後作','陸游','宋','宋诗','song-poetry','','[]','骨相坐一寒，仕宦經百謫。',144,'全唐诗/poet.song.134000.json','["骨相坐一寒，仕宦經百謫。", "晚入文昌省，又坐煩言嘖。", "詔書復收召，付以大典冊。", "期年甫奏篇，皇恐亟自劾。", "歸來稽山下，三食新穫麥。", "草屨布裙襦，徒步老阡陌。", "今年疾屢作，怳若將歸客。", "道士言犯土，拜章安舍宅。", "巫言神去幹，翦紙招魂魄。", "把臂忽自悟，此豈屋漏脈。", "盡去囊中藥，默觀鼻端白。", "正氣徐自還，鬼子何足磔。"]'),
('bd9e6646-40b4-403b-b279-19e15af1ceb6','山中','陸游','宋','宋诗','song-poetry','','[]','草閣留雲宿，溪橋引鶴行。',48,'全唐诗/poet.song.134000.json','["草閣留雲宿，溪橋引鶴行。", "身閑詩曠逸，心靜夢和平。", "石乳無時滴，松肪徹夜明。", "山中足幽趣，不是傲公卿。"]'),
('5cb22147-5358-4a39-9c19-1a0b57d88ad6','夜思','陸游','宋','宋诗','song-poetry','','[]','風掃浮雲作快晴，窗聲終夜雜簾聲。',64,'全唐诗/poet.song.134000.json','["風掃浮雲作快晴，窗聲終夜雜簾聲。", "月明滿院鵲驚起，霜冷壓栖雞懶鳴。", "名字虛稱舊朝士，門庭元是老書生。", "尚餘一事猶堪喜，北陌東阡醉太平。"]'),
('3c8721b3-9e46-4254-9a04-b6ad5e0fd5bf','晨起','陸游','宋','宋诗','song-poetry','','[]','晨起梳頭雪滿膺，可憐衰與病相乘。',64,'全唐诗/poet.song.134000.json','["晨起梳頭雪滿膺，可憐衰與病相乘。", "浮名何足欺橫目，真樂聊須付曲肱。", "仕有俸錢渠亦好，退無耕壟我何憑。", "具牛力盡殊堪閔，買犢東村恨未能。"]'),
('e2f1928e-5cb7-47d8-bbf0-f0886cff93f7','老態二首  其一','陸游','宋','宋诗','song-poetry','','[]','破榼愁春近，空囷畏日長。',48,'全唐诗/poet.song.134000.json','["破榼愁春近，空囷畏日長。", "頭風便菊枕，足痹倚藜床。", "冉冉殘年逼，悠悠萬事忘。", "有兒堪晤語，無客亦何妨。"]'),
('2bbba6fb-0407-4b62-bed0-01249e95465c','老態二首  其二','陸游','宋','宋诗','song-poetry','','[]','寡欲貧何損，無才老更宜。',48,'全唐诗/poet.song.134000.json','["寡欲貧何損，無才老更宜。", "挂牆多漢刻，插架半唐詩。", "飯已頻摩腹，兒來暫解頤。", "尚悲吳蜀遠，未免故人思。"]'),
('0431d66b-8ea6-44f9-8634-e96d22e339dc','枕上','陸游','宋','宋诗','song-poetry','','[]','夜雨一再作，燈前獨詠詩。',48,'全唐诗/poet.song.134000.json','["夜雨一再作，燈前獨詠詩。", "影看孤鶴瘦，吟答斷蛩悲。", "幽夢悠然覺，清笳何足吹。", "殘年猶幾日，已矣愧明時。"]'),
('b9277abc-3fcc-4387-8857-6bc16026bb46','贈過門道人','陸游','宋','宋诗','song-poetry','','[]','朝行市塵中，奔馬不可及。',72,'全唐诗/poet.song.134000.json','["朝行市塵中，奔馬不可及。", "暮涉清溪流，芒屨了不溼。", "巖扉一丹竈，山路兩書笈。", "白驢可置掌，童子亦絕粒。", "邂逅安期生，電逝不暇揖。", "太華獨嶷然，萬仞道傍立。"]'),
('28399630-7d89-4ef4-9223-4c0281cf6cf6','道院雜興四首  其一','陸游','宋','宋诗','song-poetry','','[]','江上霜風吹角巾，東歸不獨爲吳蓴。',64,'全唐诗/poet.song.134000.json','["江上霜風吹角巾，東歸不獨爲吳蓴。", "掃除長劍華纓夢，收拾孤颿短棹身。", "勾漏丹砂開竈晚，商顔芝草滿山春。", "東封敢擬迎鑾仗，且作行歌陌上人。"]'),
('58227038-32ca-4a6b-a85b-2553f78ddd19','道院雜興四首  其二','陸游','宋','宋诗','song-poetry','','[]','征途暗盡舊貂裘，歸卧林間喜自由。',64,'全唐诗/poet.song.134000.json','["征途暗盡舊貂裘，歸卧林間喜自由。", "體倦尚憑書引睡，心安不假酒攻愁。", "丹爐弄火經年熟，竹院聽琴竟日留。", "今旦理髯還一笑，白間時有黑絲抽。"]'),
('b05dc8c5-ae9b-4ea0-a5a4-c304b1687ef6','道院雜興四首  其三','陸游','宋','宋诗','song-poetry','','[]','早歲知聞久已空，巋然猶有灞城翁。',64,'全唐诗/poet.song.134000.json','["早歲知聞久已空，巋然猶有灞城翁。", "東樓誰記傾春碧，北嶺空思擘晚紅。", "冉冉流年霜鬢外，纍纍荒冢綠蕪中。", "琳房何日金丹熟，老鶴猶堪萬里風。"]'),
('26c6211a-6506-4790-bf1f-f1e71065f9fd','道院雜興四首  其四','陸游','宋','宋诗','song-poetry','','[]','龜堂有叟富神通，白髮何妨兩頰紅。',64,'全唐诗/poet.song.134000.json','["龜堂有叟富神通，白髮何妨兩頰紅。", "先取山川來掌上，却移天地入壺中。", "鶯花不老非塵世，風月常新奪化工。", "近作東籬君未見，一尊少住莫匆匆。"]'),
('2a133290-d707-4e47-889a-f1ef569d4109','山村經行因施藥五首  其一','陸游','宋','宋诗','song-poetry','','[]','閑行偶復到山村，父老遮留共一尊。',32,'全唐诗/poet.song.134000.json','["閑行偶復到山村，父老遮留共一尊。", "曩日見公孫未晬，如今已解牧雞豚。"]'),
('479d441f-626d-44e4-8939-91dd8ab9de5f','山村經行因施藥五首  其二','陸游','宋','宋诗','song-poetry','','[]','耕傭蠶婦共欣然，得見先生定有年。',32,'全唐诗/poet.song.134000.json','["耕傭蠶婦共欣然，得見先生定有年。", "掃灑門庭拂床几，瓦盆盛酒薦豚肩。"]'),
('1a3bb6fb-73b2-4642-b656-1cf93066e56a','山村經行因施藥五首  其三','陸游','宋','宋诗','song-poetry','','[]','兒扶一老候溪邊，來告頭風久未痊。',32,'全唐诗/poet.song.134000.json','["兒扶一老候溪邊，來告頭風久未痊。", "不用更求芎芷輩，吾詩讀罷自醒然。"]'),
('7882ee4f-e1d5-44be-a9c7-e895d13153ea','山村經行因施藥五首  其四','陸游','宋','宋诗','song-poetry','','[]','驢肩每带藥囊行，村巷歡欣夾道迎。',32,'全唐诗/poet.song.134000.json','["驢肩每带藥囊行，村巷歡欣夾道迎。", "共說向來曾活我，生兒多以陸爲名。"]'),
('89fe4e4f-92f7-4bad-8b90-8e912cb94df9','山村經行因施藥五首  其五','陸游','宋','宋诗','song-poetry','','[]','逆旅人家近野橋，偶因秣蹇暫消摇。',32,'全唐诗/poet.song.134000.json','["逆旅人家近野橋，偶因秣蹇暫消摇。", "村翁不解讀本草，爭就先生辨藥苗。"]'),
('0e802b3f-0410-481d-a232-13a65bd0f381','嘆老','陸游','宋','宋诗','song-poetry','','[]','身歷邅回事萬端，天教林下養衰殘。',64,'全唐诗/poet.song.134000.json','["身歷邅回事萬端，天教林下養衰殘。", "文編似是他人作，書卷如曾隔世觀。", "久已悠悠置恩怨，况能一一記悲歡。", "床頭周易真良藥，不是書生强自寬。"]'),
('07a687cc-e870-411d-97b8-ce0f53f00734','即事二首  其一','陸游','宋','宋诗','song-poetry','','[]','禿尾驢嘶小市門，側篷帆過古城村。',32,'全唐诗/poet.song.134000.json','["禿尾驢嘶小市門，側篷帆過古城村。", "此生感慨知何限，斗酒新豐不足論。"]'),
('0a8a48c5-29ad-4c73-935f-8241c2636dbe','即事二首  其二','陸游','宋','宋诗','song-poetry','','[]','草衣木食更何求，穴處巢居過即休。',32,'全唐诗/poet.song.134000.json','["草衣木食更何求，穴處巢居過即休。", "尚恨未能全省事，一竿風月釣滄洲。"]'),
('4c1c920f-516b-4524-999e-214db0514f73','自賀','陸游','宋','宋诗','song-poetry','','[]','胎髮茸茸綠映巾，歸耕猶是太平民。',64,'全唐诗/poet.song.134000.json','["胎髮茸茸綠映巾，歸耕猶是太平民。", "流觴內史招同社，扛鼎將軍與卜鄰。", "曾冠六鰲非俗吏，已開九秩是陳人。", "一杯剩約梅花醉，又見開禧第二春。"]'),
('caa91b3a-c871-4442-b0bb-734c5e0ef337','天氣作雪戲作','陸游','宋','宋诗','song-poetry','','[]','八十又過二，與人風馬牛。',48,'全唐诗/poet.song.134000.json','["八十又過二，與人風馬牛。", "深知老當逸，孰謂死方休。", "細衲兜羅襪，奇溫吉貝裘。", "閉門薪炭足，雪夜可無憂。"]'),
('f0afa992-288f-4f05-a976-a0a800383127','家風','陸游','宋','宋诗','song-poetry','','[]','春耕秋釣舊家風，門巷荒寒屋壁空。',64,'全唐诗/poet.song.134000.json','["春耕秋釣舊家風，門巷荒寒屋壁空。", "四海交情殘夢裏，一生心事斷編中。", "買魚日待携籃女，裹藥時從挾簏翁。", "便廢閑吟亦未可，吾徒豈獨坐詩窮。"]'),
('6678e799-2c83-4657-a3df-d0179b0a1c04','十二月二日夜夢遊沈氏園亭二首  其一','陸游','宋','宋诗','song-poetry','','[]','路近城南已怕行，沈家園裏更傷情。',32,'全唐诗/poet.song.134000.json','["路近城南已怕行，沈家園裏更傷情。", "香穿客袖梅花在，綠蘸寺橋春水生。"]'),
('4beadd5f-cad1-4ede-8769-35cbe174041d','十二月二日夜夢遊沈氏園亭二首  其二','陸游','宋','宋诗','song-poetry','','[]','城南小陌又逢春，只見梅花不見人。',32,'全唐诗/poet.song.134000.json','["城南小陌又逢春，只見梅花不見人。", "玉骨久成泉下土，墨痕猶鎖壁間塵。"]'),
('f8a71d9d-d7bf-459e-835f-628e7f7e51e6','江干','陸游','宋','宋诗','song-poetry','','[]','霜晴忽念到江干，小蹇羸童路已乾。',64,'全唐诗/poet.song.134000.json','["霜晴忽念到江干，小蹇羸童路已乾。", "骨相豈能當富貴，鬢毛聊喜耐悲歡。", "客途冬暖衣裘薄，村市年豐酒盞寬。", "殘臘即今無十日，剩求芹蓼助春盤。"]'),
('a5c66c74-f97e-45fd-96d5-34fb10e84760','獨行過柳橋而歸','陸游','宋','宋诗','song-poetry','','[]','寒雲覆江干，慘慘雪欲作。',120,'全唐诗/poet.song.134000.json','["寒雲覆江干，慘慘雪欲作。", "草枯狐兔見，鷹隼方縱搏。", "老翁卧蓬戶，疾痛在腰脚。", "忽覺意稍佳，快若解束縛。", "呼童扶下堂，西出度略彴。", "浮波見鳧雁，决起驚烏鵲。", "籬根犬迎吠，碓下雞俛啄。", "霜餘桑葉積，春近柳枝弱。", "徐行過傍舍，醉笑盛酬酢。", "歲暮農事休，羨爾群飲樂。"]'),
('a57d712c-d03b-47de-8676-2db6bb448626','戲遣老懷五首  其一','陸游','宋','宋诗','song-poetry','','[]','平生碌碌本無奇，况是年垂九十時。',64,'全唐诗/poet.song.134000.json','["平生碌碌本無奇，况是年垂九十時。", "阿囝略如郎罷老，稚孫能伴太翁嬉。", "花前騎竹强名馬，階下埋盆便作池。", "一笑不妨閑過日，嘆衰憂死却成癡。"]'),
('ae05898f-ece9-42ad-bf8c-3ea79c12eb4e','戲遣老懷五首  其二','陸游','宋','宋诗','song-poetry','','[]','清羸正怯倚闌干，紗帽還驚半指寬。',64,'全唐诗/poet.song.134000.json','["清羸正怯倚闌干，紗帽還驚半指寬。", "日漏雲端纔欲暖，風催梅信又成寒。", "尋僧竹院逢茶熟，引鶴溪橋及雪殘。", "只道捐書差似達，庖丁數紙尚須看。"]'),
('c427d5ea-1e73-4ae2-b26e-55173865d47b','戲遣老懷五首  其三','陸游','宋','宋诗','song-poetry','','[]','兒時萬死避胡兵，敢料時清畢此生。',64,'全唐诗/poet.song.134000.json','["兒時萬死避胡兵，敢料時清畢此生。", "已迫九齡身愈健，熟觀萬卷眼猶明。", "深深小塢梅初動，瀲瀲清溪水欲平。", "安得飄然從此逝，緱山風月聽吹笙。"]'),
('6896d572-1ec0-4cf5-af68-b39dcabb7e2a','戲遣老懷五首  其四','陸游','宋','宋诗','song-poetry','','[]','舊襲家風號散人，晚承恩詔賜閑身。',64,'全唐诗/poet.song.134000.json','["舊襲家風號散人，晚承恩詔賜閑身。", "放狂泥酒都忘老，厚價收書不似貧。", "霜曉方驚群木脫，春晴又喜一花新。", "先生偶出人難遇，陌上爭先看角巾。"]'),
('ae3e6759-a73a-4b86-a4d0-5c97e036f700','戲遣老懷五首  其五','陸游','宋','宋诗','song-poetry','','[]','本意歸來老故丘，閉門飯足尚何求。',64,'全唐诗/poet.song.134000.json','["本意歸來老故丘，閉門飯足尚何求。", "閑雲一片自舒卷，幽鳥數聲相應酬。", "但得有書時到眼，正令無酒亦忘憂。", "東籬偪仄纔尋丈，已敵征西萬戶侯。"]'),
('ddafbf51-7502-4127-b831-f63a9c0ee4b1','對鏡','陸游','宋','宋诗','song-poetry','','[]','歲月雖遄邁，形容未苦癯。',48,'全唐诗/poet.song.134000.json','["歲月雖遄邁，形容未苦癯。", "髮如新沐潤，顔似半酣朱。", "書讀常終卷，山行亦却扶。", "悠悠隨日過，不復嘆頭顱。"]'),
('46647831-239b-4691-937d-c3054a21ae35','晨起','陸游','宋','宋诗','song-poetry','','[]','客枕畏霜氣，曉窗收月痕。',48,'全唐诗/poet.song.134000.json','["客枕畏霜氣，曉窗收月痕。", "芸芸萬物作，皎皎一心存。", "老已忘開卷，貧猶力灌園。", "兒孫能繼此，亦足報君恩。"]'),
('80b39384-d6c8-41c0-bf17-72ef9b1cc55d','吾年過八十二首  其一','陸游','宋','宋诗','song-poetry','','[]','吾年過八十，久已棄朝簪。',48,'全唐诗/poet.song.134000.json','["吾年過八十，久已棄朝簪。", "化蝶有殘夢，焦桐無賞音。", "溪聲喧夜旦，野色變晴陰。", "欲講平生學，茫然不可尋。"]'),
('0b05f946-8c9e-4734-a952-2c5719ad4670','吾年過八十二首  其二','陸游','宋','宋诗','song-poetry','','[]','八十又過二，自言名放翁。',48,'全唐诗/poet.song.134000.json','["八十又過二，自言名放翁。", "斧斤遺壽櫟，雲海寄冥鴻。", "酒挂驢鞍側，詩投藥笈中。", "灞城逢薊叟，共語莫匆匆。"]'),
('50a18367-2d96-4a01-83ec-88c068ab5ea8','述志二首  其一','陸游','宋','宋诗','song-poetry','','[]','椎牛釃酒千人帳，破浪凌風萬斛船。',32,'全唐诗/poet.song.134000.json','["椎牛釃酒千人帳，破浪凌風萬斛船。", "常恨書生無此快，一生低首短檠前。"]'),
('11d5c9ee-651b-4a29-abc4-e6dfb8152a53','述志二首  其二','陸游','宋','宋诗','song-poetry','','[]','新豐買酒慰無聊，衝雪騎驢上灞橋。',32,'全唐诗/poet.song.134000.json','["新豐買酒慰無聊，衝雪騎驢上灞橋。", "羆老尚堪吞貈子，松風何至羨山苗。"]'),
('d21985d1-5e9e-4c26-9646-e36ce80ef219','排悶','陸游','宋','宋诗','song-poetry','','[]','吹盡梅花了不知，化工也誤老人期。',64,'全唐诗/poet.song.134000.json','["吹盡梅花了不知，化工也誤老人期。", "離離新草隨愁出，漠漠餘寒與睡宜。", "古錦一聯吟舊句，文楸數著理殘棋。", "波生澄澗君何怪，禪榻從來映鬢絲。"]'),
('0b78155c-0aca-43cb-8b79-c6150b3fed10','舟中作','陸游','宋','宋诗','song-poetry','','[]','林麓重重霧雨昏，扁舟晚過郡南門。',64,'全唐诗/poet.song.134000.json','["林麓重重霧雨昏，扁舟晚過郡南門。", "鑄金越相遺祠古，執玉塗山王氣存。", "官道蒼茫多水驛，客遊飄泊厭風餐。", "剡中此去無多地，會約支公聽斷猿。"]'),
('9188527d-ba83-4d5f-a894-dd887c12be5a','丙寅元日','陸游','宋','宋诗','song-poetry','','[]','縹緲初聞寺閣鐘，霏微零雨兆年豐。',64,'全唐诗/poet.song.134000.json','["縹緲初聞寺閣鐘，霏微零雨兆年豐。", "家家椒酒歡聲裏，戶戶桃符霽色中。", "春枕方濃從賣困，社醅雖美倦治聾。", "從今萬事俱拋擲，且作人間百歲翁。"]'),
('6a1d548b-a36d-4473-9465-8f017ee14269','新晴','陸游','宋','宋诗','song-poetry','','[]','夜雨空階滴到明，山雲忽斂作新晴。',64,'全唐诗/poet.song.134000.json','["夜雨空階滴到明，山雲忽斂作新晴。", "門前月淡有簷影，牆外泥乾無屐聲。", "與世日疏愁易遣，入春得暖疾差平。", "便當剩作滄洲趣，寄語沙鷗勿敗盟。"]'),
('441df84d-6ffa-495c-8e2f-b07450bccbf6','新歲','陸游','宋','宋诗','song-poetry','','[]','改歲鍾馗在，依然舊綠襦。',48,'全唐诗/poet.song.134000.json','["改歲鍾馗在，依然舊綠襦。", "老庖供餺飥，跣婢暖屠蘇。", "載糗送窮鬼，扶箕迎紫姑。", "兒童欺老聵，明燭聚呼盧。"]'),
('2294b595-5f42-4c05-9b25-a28ed33fbf54','簡邢德允','陸游','宋','宋诗','song-poetry','','[]','邢子襟靈舊絕塵，爾來句法更清新。',64,'全唐诗/poet.song.134000.json','["邢子襟靈舊絕塵，爾來句法更清新。", "淡交喜得山栖友，傑作疑非火食人。", "豈但僕奴看屈子，直須塗改到生民。", "與君兩世交情厚，剩欲燈前對角巾。"]'),
('1e7bf0f1-1fc2-4f71-b8b7-b34ea6f599a8','簡蘇邵叟','陸游','宋','宋诗','song-poetry','','[]','君家文獻歷十朝，魏公峨冕加金貂。',160,'全唐诗/poet.song.134000.json','["君家文獻歷十朝，魏公峨冕加金貂。", "孫支得君愈雋發，貴名突兀凌烟霄。", "居吳入蜀三十載，諸公孰能折簡招。", "澗松意氣極磊砢，天馬毛骨何超遥。", "鼎來行卷十九首，緱山明月聞吹簫。", "沉香亭畔未須說，想見風雪上灞橋。", "老夫誦之群玉府，學士如堵不敢驕。", "爾來一編愈妙絕，粲若新霽瞻斗杓。", "出爲龍首子何有，老穿豹尾我亦聊。", "湖邊酒樓無十步，胸次懣懣思同澆。"]'),
('26336ab0-2a1e-4175-8b56-46e16259d571','東村','陸游','宋','宋诗','song-poetry','','[]','信脚村墟路，歸來日未西。',48,'全唐诗/poet.song.134000.json','["信脚村墟路，歸來日未西。", "波清魚隊密，風小鵲巢低。", "白水初平岸，青蕪亦遍犁。", "市壚多美酒，飲具不須齎。"]'),
('8f562591-018b-4dec-aa0f-b702e50488d3','新曆嘆','陸游','宋','宋诗','song-poetry','','[]','新曆在手心怕開，日月聯翩相續來。',96,'全唐诗/poet.song.134000.json','["新曆在手心怕開，日月聯翩相續來。", "黄金散盡自一快，白髮不貸真可哀。", "無爲健羨廣成子，千二百年終有死。", "膠不可黏西去日，刀何由翦東流水。", "酒無醇醨但痛飲，市醞上尊俱醉耳。", "堂堂七尺死即休，不飽烏鳶飽螻蟻。"]'),
('0ad66bc8-af9b-4b5f-9bd7-135410669e7e','雪中二首  其一','陸游','宋','宋诗','song-poetry','','[]','忽忽悲窮處，悠悠感歲華。',48,'全唐诗/poet.song.134000.json','["忽忽悲窮處，悠悠感歲華。", "暮雲如潑墨，春雪不成花。", "眼澀燈生暈，詩成字半斜。", "殘尊已傾盡，試起問東家。"]'),
('888fea2e-66fb-4184-a956-77f1a4a36724','雪中二首  其二','陸游','宋','宋诗','song-poetry','','[]','春晝雪如簁，清羸病起時。',48,'全唐诗/poet.song.134000.json','["春晝雪如簁，清羸病起時。", "迹深驚虎過，烟絕閔僧饑。", "地凍萱芽短，林寒鳥哢遲。", "西窗斜日晚，呵手斂殘棋。"]'),
('45987d73-2530-4e92-8d18-f0d9ecade437','早春出遊二首  其一','陸游','宋','宋诗','song-poetry','','[]','微雲薄靄新晴後，小蓋輕輿古道遥。',64,'全唐诗/poet.song.134000.json','["微雲薄靄新晴後，小蓋輕輿古道遥。", "林杪幽禽初學囀，牆陰凍雪未全消。", "酒壚日暮收青旆，市步人歸擁畫橈。", "欹帽捫髯常半醉，逢人誰與話無憀。"]'),
('3c2b1a72-1fbc-42cb-964e-792e0efae5a3','早春出遊二首  其二','陸游','宋','宋诗','song-poetry','','[]','人生何適不艱難，賴是胸中萬斛寬。',64,'全唐诗/poet.song.134000.json','["人生何適不艱難，賴是胸中萬斛寬。", "尺宅常朱那待酒，上池頻飲自成丹。", "楚祠花發呼舟去，禹穴雲生倚杖看。", "更有新春堪喜事，一村簫鼓祭蠶官。"]'),
('4c1d7cca-039d-4e11-a730-7a6dec7ebce0','東籬三首  其一','陸游','宋','宋诗','song-poetry','','[]','東籬深僻懶衣裳，書卷縱橫雜藥囊。',64,'全唐诗/poet.song.134000.json','["東籬深僻懶衣裳，書卷縱橫雜藥囊。", "無吏徵租終日睡，得錢沽酒一春狂。", "新營茅舍軒窗靜，旋煮山蔬匕筯香。", "戲集句圖書素壁，本來無事却成忙。"]'),
('71575a64-b44e-4449-a6df-c603632dadd3','東籬三首  其二','陸游','宋','宋诗','song-poetry','','[]','漫道深居晝掩關，東籬栽接不曾閑。',64,'全唐诗/poet.song.134000.json','["漫道深居晝掩關，東籬栽接不曾閑。", "每因清夢遊敷水，自覺前身隱華山。", "花發時時携綠酒，客來往往羨朱顔。", "藥爐安著猶無地，擬展茅茨一兩間。"]'),
('758a0bd2-b599-4ade-bf2f-85119a9ac398','東籬三首  其三','陸游','宋','宋诗','song-poetry','','[]','東偏隙地作疏籬，遇興無非一笑時。',64,'全唐诗/poet.song.134000.json','["東偏隙地作疏籬，遇興無非一笑時。", "陪客投壺新罰酒，與兒鬭草又輸詩。", "山桃溪杏栽俱活，藥鑱漁竿動自隨。", "家事猶令罷關白，固應黜陟不曾知。"]'),
('eb9dbd73-88dd-46ff-952b-b8b31d3847b8','村市醉歸','陸游','宋','宋诗','song-poetry','','[]','明時乞得水雲身，白首扶衰又見春。',64,'全唐诗/poet.song.134000.json','["明時乞得水雲身，白首扶衰又見春。", "橫木門幽謝來客，獨轅車小避行人。", "湘湖水長蒓絲滑，蘭渚泥融箭茁新。", "處處酒壚皆可醉，不辭微雨墊吾巾。"]'),
('0d9caa16-f0f3-4f68-9985-92c7253a8de3','村夜','陸游','宋','宋诗','song-poetry','','[]','入春雨雪無休日，雨止猶陰未快晴。',64,'全唐诗/poet.song.134000.json','["入春雨雪無休日，雨止猶陰未快晴。", "萬竅怒號風不定，半輪斜照月微明。", "百年辛苦農桑業，五處睽離父子情。", "但得平安已爲幸，孤燈殘火過三更。"]'),
('bb7597f9-71b0-4e0e-a161-1f565487a6fd','旅思','陸游','宋','宋诗','song-poetry','','[]','百病集殘骸，閑遊且散懷。',48,'全唐诗/poet.song.134000.json','["百病集殘骸，閑遊且散懷。", "旅裝如遠役，蔬食似長齋。", "買藥停山步，求醫過縣街。", "春寒殊未已，閉戶夜燃䕸。"]'),
('78bb064c-ee84-4eb9-a323-065fd98e68a3','對酒作','陸游','宋','宋诗','song-poetry','','[]','憑閣風吹帽，穿林雨墊巾。',48,'全唐诗/poet.song.134000.json','["憑閣風吹帽，穿林雨墊巾。", "相呼十日飲，不負百年身。", "陌上金羈馬，墳前石琢麟。", "於吾竟何有，笑殺武陵人。"]'),
('07663414-0603-4f42-9ba4-792d70352c6e','遊東村','陸游','宋','宋诗','song-poetry','','[]','露草衡門曉，風松一塢幽。',48,'全唐诗/poet.song.134000.json','["露草衡門曉，風松一塢幽。", "新春有佳日，老子得閑遊。", "鷗爲忘機下，魚緣得計浮。", "歸途無遠近，一葉亂漁舟。"]'),
('2cb2c152-9a6e-4db1-912d-0241c268d1aa','晨起','陸游','宋','宋诗','song-poetry','','[]','老境真無事，深居每畏人。',48,'全唐诗/poet.song.134000.json','["老境真無事，深居每畏人。", "喔咿雞失旦，婭姹鳥鳴春。", "過擔餦餭白，擎盤粔籹新。", "出門還可喜，一笑語比鄰。"]'),
('30f7acdc-3dc1-41fd-b060-7d7e606b427a','夢中作','陸游','宋','宋诗','song-poetry','','[]','世事何由可控摶，故山歸卧有餘歡。',64,'全唐诗/poet.song.134000.json','["世事何由可控摶，故山歸卧有餘歡。", "澗泉見底藥根瘦，石室生雲丹竈寒。", "人遠忽聞清嘯起，山開頻得異書看。", "一朝出赴安期約，萬里烟霄駕紫鸞。"]'),
('4f596829-f0ec-4946-959b-20e485ff5f57','春雨四首  其一','陸游','宋','宋诗','song-poetry','','[]','片片紅梅落，纖纖綠草生。',24,'全唐诗/poet.song.134000.json','["片片紅梅落，纖纖綠草生。", "無端夜來雨，又礙出門行。"]'),
('27e2b40c-4fe4-4038-b26d-e5e2d9b28fb0','春雨四首  其二','陸游','宋','宋诗','song-poetry','','[]','春陰易成雨，客病不禁寒。',24,'全唐诗/poet.song.134000.json','["春陰易成雨，客病不禁寒。", "又與梅花別，無因一倚欄。"]'),
('a9a3f7a9-8755-4891-83ce-cb76a7ebc2c0','春雨四首  其三','陸游','宋','宋诗','song-poetry','','[]','胸懷阮步兵，詩句謝宣城。',24,'全唐诗/poet.song.134000.json','["胸懷阮步兵，詩句謝宣城。", "今夕俱參透，焚香聽雨聲。"]'),
('a8951af8-c9e0-4f46-b4d5-6bbb225f0f78','春雨四首  其四','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','疏點空階雨，長明古殿燈。',24,'全唐诗/poet.song.134000.json','["疏點空階雨，長明古殿燈。", "廬山岑寂夜，我是定中僧。"]'),
('e44b1fa2-bdf4-44c1-8853-1c8e45717ee2','村店','陸游','宋','宋诗','song-poetry','','[]','水汎輕摇檝，山行穩跨驢。',48,'全唐诗/poet.song.134000.json','["水汎輕摇檝，山行穩跨驢。", "朝晡半晴雨，閭里雜樵漁。", "野鶩浮寒浦，饑鴉集老樗。", "店家看壞壁，忽見昔年書。"]'),
('3da146d5-bbe1-403f-86ce-1df12ece42a8','久雨薪炭食飲俱不繼戲作','陸游','宋','宋诗','song-poetry','','[]','澤國春饒雨，書生老益貧。',48,'全唐诗/poet.song.134000.json','["澤國春饒雨，書生老益貧。", "固難誇練炭，亦豈擇勞薪。", "鹽盡纔供暮，醯微尚惱鄰。", "人嗤信書誤，癡絕望常珍。"]'),
('8b3684d8-fecd-4d67-b9a9-7d1fe677a788','溪上','陸游','宋','宋诗','song-poetry','','[]','偶就澄溪照幅巾，蘭亭遺韵想清真。',64,'全唐诗/poet.song.134000.json','["偶就澄溪照幅巾，蘭亭遺韵想清真。", "功名不入山林夢，詩酒猶關老病身。", "萬事只增思魯嘆，百年常愧避秦人。", "超然聊喜高情在，手挈長條貫細鱗。"]'),
('de67cf46-4089-494d-be0d-ceb9e858502a','謝君寄一犁春雨圖求詩爲作絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','說著功名我自羞，喜君解劍換吳牛。',32,'全唐诗/poet.song.134000.json','["說著功名我自羞，喜君解劍換吳牛。", "莫將江上一犁雨，輕博人間萬戶侯。"]'),
('9cce309c-8ebe-4cac-9763-48b5051cd7ef','謝君寄一犁春雨圖求詩爲作絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','老農雖瘠喜牛肥，回首紅塵萬事非。',32,'全唐诗/poet.song.134000.json','["老農雖瘠喜牛肥，回首紅塵萬事非。", "耕罷春蕪天欲暮，小舟衝雨載犁歸。"]'),
('d752c5fa-409d-4c4b-8680-b2d635a7cb15','二月一日夜夢','陸游','宋','宋诗','song-poetry','','[]','夢裏遇奇士，高樓酣且歌。',96,'全唐诗/poet.song.134000.json','["夢裏遇奇士，高樓酣且歌。", "霸圖輕管樂，王道探丘軻。", "大指如符券，微瑕互琢磨。", "相知殊恨晚，所得不勝多。", "勝算觀天定，精忠壓虜和。", "真當起莘渭，何止復關河。", "陣法參奇正，戎旃相蕩摩。", "覺來空雨泣，壯志已蹉跎。"]'),
('939c0b91-a9e0-4870-bad1-d51fc8d1114d','新晴二首  其一','陸游','宋','宋诗','song-poetry','','[]','寂寂房櫳鳥雀聲，熏籠茶竈正施行。',64,'全唐诗/poet.song.134000.json','["寂寂房櫳鳥雀聲，熏籠茶竈正施行。", "繁花滿樹春纔半，斜日穿雲雨乍晴。", "引睡書橫猶在架，圍棋客散但空枰。", "病懷莫道傷幽獨，小榼芳醪手自傾。"]'),
('7ed1dc8c-c8aa-4a3a-92f6-429c53387ee9','新晴二首  其二','陸游','宋','宋诗','song-poetry','','[]','挂冠湖上遂吾初，捫腹消摇適有餘。',64,'全唐诗/poet.song.134000.json','["挂冠湖上遂吾初，捫腹消摇適有餘。", "羹煮野蔬元足味，屋茨生草亦安居。", "市壚分熟通賒酒，鄰舍情深許借驢。", "更喜新晴滿窗日，籤題重整一牀書。"]'),
('5b44f6db-3b70-499e-999f-e860c808f3fd','望永思陵','陸游','宋','宋诗','song-poetry','','[]','高帝中興萬物春，青衫曾忝綴廷紳。',64,'全唐诗/poet.song.134000.json','["高帝中興萬物春，青衫曾忝綴廷紳。", "仕爲將相却常事，年及耄期能幾人。", "早幸執殳觀北伐，晚叨秉筆記東巡。", "歸耕况復蒼梧近，鬰鬰葱葱佳氣新。"]'),
('d477a863-19c3-4ba9-9ead-329746854550','燈下小酌','陸游','宋','宋诗','song-poetry','','[]','江湖雙鬢禿，宇宙一身窮。',48,'全唐诗/poet.song.134000.json','["江湖雙鬢禿，宇宙一身窮。", "酒浪摇輕碧，燈花落碎紅。", "交情元易見，春事半成空。", "尚覬身强健，烟畦擷芥菘。"]'),
('dd3d59b4-79e8-4af1-aee9-1d8fe0c0ab9b','春遊二首  其一','陸游','宋','宋诗','song-poetry','','[]','杏花天氣喜新晴，白首書生樂太平。',64,'全唐诗/poet.song.134000.json','["杏花天氣喜新晴，白首書生樂太平。", "小陌鞦韆雖隔世，名園祓禊尚關情。", "山林自古流觴地，絃管誰家送酒聲。", "蒓菜鮆魚初滿市，莫將羊酪敵南烹。"]'),
('e71f0cff-364e-456e-b341-f97c83afcb5c','春遊二首  其二','陸游','宋','宋诗','song-poetry','','[]','窮愁終日竟胡爲，老健人間自一奇。',64,'全唐诗/poet.song.134000.json','["窮愁終日竟胡爲，老健人間自一奇。", "每駕柴車遊古寺，間騎竹馬伴群兒。", "登臨蘭渚流觴地，蕭散狐泉冷餅時。", "綀布單衣白羽扇，路傍人總道相宜。"]'),
('98480655-2736-48b5-a45c-eb67b0d4cf09','春日雜賦五首  其一','陸游','宋','宋诗','song-poetry','','[]','羈懷病思正厭厭，詩卷漁竿信手拈。',64,'全唐诗/poet.song.134000.json','["羈懷病思正厭厭，詩卷漁竿信手拈。", "老境何嘗忘一笑，春風也解到窮閻。", "殘花滿地無餘萼，新筍掀泥已露尖。", "轉老轉窮君勿笑，熊蹯魚腹豈容兼。"]'),
('2a753442-35b2-41fe-ad59-c7517cf5593d','春日雜賦五首  其二','陸游','宋','宋诗','song-poetry','','[]','鬢毛八九已成霜，此際逢春只自傷。',64,'全唐诗/poet.song.134000.json','["鬢毛八九已成霜，此際逢春只自傷。", "苦雨不容花抵敵，餘寒猶賴酒禁當。", "退紅衣焙熏香冷，古錦詩囊覓句忙。", "堪笑散人閑事業，西窗容易又斜陽。"]'),
('f1800819-08a8-415d-aebf-ccc76aca08d6','春日雜賦五首  其三','陸游','宋','宋诗','song-poetry','','[]','江湖放浪水雲人，藥物枝梧夢幻身。',64,'全唐诗/poet.song.134000.json','["江湖放浪水雲人，藥物枝梧夢幻身。", "移竹南窗初試筍，掃花北陌旋成塵。", "窮忙自笑常終日，老健猶能不負春。", "未遂初心惟一事，乞薪賒米惱吾鄰。"]'),
('5e342c60-0fa4-47db-bf0e-51c453b245e8','春日雜賦五首  其四','陸游','宋','宋诗','song-poetry','','[]','乞得身歸剡曲邊，衡門茅舍共蕭然。',64,'全唐诗/poet.song.134000.json','["乞得身歸剡曲邊，衡門茅舍共蕭然。", "向來誤計守書冊，此日遣愁無酒錢。", "俗客妬閑來衮衮，流年欺老去翩翩。", "梨花楊柳清明過，且向江村剩放顛。"]'),
('516494de-4d3d-4a21-b86c-2feb3f4cb057','春日雜賦五首  其五','陸游','宋','宋诗','song-poetry','','[]','人生覓飯元多術，最下方爲祿代耕。',64,'全唐诗/poet.song.134000.json','["人生覓飯元多術，最下方爲祿代耕。", "脫却朝衫猶老健，快如苦雨得春晴。", "鳥聲頻喚五更夢，花氣頓醒三日酲。", "最喜晨興聞剝啄，吾兒書札到柴荆。"]'),
('65eebfec-c183-495a-8250-c8a0beb44879','悲歌行','陸游','宋','宋诗','song-poetry','','[]','讀書不能遂吾志，屬文不能盡吾才。',130,'全唐诗/poet.song.134000.json','["讀書不能遂吾志，屬文不能盡吾才。", "遠遊方樂歸太早，大藥未就老已催。", "結廬城南十里近，柴門正對湖山開。", "有時野行桑下宿，亦或慟哭中途回。", "檀公畫計三十六，不如一篇歸去來。", "紫駝之峰玄熊掌，不如飯豆羹芋魁。", "腰間纍纍六相印，不如高卧鼻息轟春雷。", "安得寶瑟五十弦，爲我寫盡無窮哀。"]'),
('a36a687c-2c2e-4ded-9710-3c86c053da85','梅市暮歸三山','陸游','宋','宋诗','song-poetry','','[]','日日蠻童佩一壺，壺乾時亦復村酤。',64,'全唐诗/poet.song.134000.json','["日日蠻童佩一壺，壺乾時亦復村酤。", "橫林露塔遠猶見，暮靄籠山淡欲無。", "綠浦例憑菰作界，畫橈常遣鷺前驅。", "此身元是滄浪客，敢學高人乞鏡湖。"]'),
('74fe6efd-8224-4858-a2be-a8584c6a9a7d','龜堂偶題二首  其一','陸游','宋','宋诗','song-poetry','','[]','文章何物求渠力，詩亦安能使汝窮。',32,'全唐诗/poet.song.134000.json','["文章何物求渠力，詩亦安能使汝窮。", "春水一池花百本，此生未易報天公。"]'),
('9b3aaf6e-ce1d-44e3-8354-d9f229962952','龜堂偶題二首  其二','陸游','宋','宋诗','song-poetry','','[]','細肋卧沙來左輔，巨螯斫雪出東吳。',32,'全唐诗/poet.song.134000.json','["細肋卧沙來左輔，巨螯斫雪出東吳。", "不知一飽摩便腹，得似茅簷薺糝無。"]'),
('58d43850-5ce8-4b2c-b7f0-e8e2ab9f311a','泛湖','陸游','宋','宋诗','song-poetry','','[]','白鷺雙飛導我前，自疑身是水中仙。',64,'全唐诗/poet.song.134000.json','["白鷺雙飛導我前，自疑身是水中仙。", "放舟漢客樵風裏，擲釣秦皇酒甕邊。", "山寺雲間傳講鼓，漁家浦口起炊烟。", "箇中得意君知否，買盡烟波不用錢。"]'),
('f004b67d-7c6a-4d53-8b40-e29b4858ccb0','園中作','陸游','宋','宋诗','song-poetry','','[]','疏籬圍中庭，野水赴方塘。',96,'全唐诗/poet.song.134000.json','["疏籬圍中庭，野水赴方塘。", "春雨路易乾，徐步蹋夕陽。", "艷艷紅杏梢，忽已占年光。", "我老來日短，乃復不自量。", "接花待其成，鄰里共笑狂。", "萬事孰能料，社櫟老不僵。", "磊磊盤中果，安知不獲嘗。", "作詩遣閑愁，一笑無留觴。"]'),
('1b1c28b9-d528-4c34-9e39-4b597e33dd9e','寄題求志堂','陸游','宋','宋诗','song-poetry','','[]','古人不輕出，出則堯舜其君民。',140,'全唐诗/poet.song.134000.json','["古人不輕出，出則堯舜其君民。", "古人不輕隱，隱則坐使風俗淳。", "孰知後世乃不然，唐虞日遠如飛烟。", "異端欲出六籍上，裔夷直居中夏先。", "窮居求志達行道，儻不塞責真負天。", "士固不可苟富貴，顧亦豈可徒貧賤。", "如其一念有愧心，寧不終身戴慚面。", "老夫少年鐵鑄硯，欲窺聖門終未見。", "祝君勿恃來日長，八九十年如掣電。"]'),
('918c9c48-0e4d-4459-a359-bcc8eb5cef2f','贈過門道人','陸游','宋','宋诗','song-poetry','','[]','賣藥人間兩屨輕，飄然雲水不論程。',32,'全唐诗/poet.song.134000.json','["賣藥人間兩屨輕，飄然雲水不論程。", "曉經浦口亂流渡，夜宿山家乘月行。"]'),
('69d2706b-8597-4dad-927b-951df1209359','春晚二首  其一','陸游','宋','宋诗','song-poetry','','[]','門巷蕭條老病侵，春晴方快又春陰。',64,'全唐诗/poet.song.134000.json','["門巷蕭條老病侵，春晴方快又春陰。", "啄吞自笑如孤鶴，導引何妨效五禽。", "雨洗杏花紅欲盡，日烘楊柳綠初深。", "雛鶯寧有平生舊，也傍茆簷送好音。"]'),
('868a9158-9028-4a3a-bcae-95ea051fa591','春晚二首  其二','陸游','宋','宋诗','song-poetry','','[]','村巷泥深晝掩門，倚闌搔首一消魂。',64,'全唐诗/poet.song.134000.json','["村巷泥深晝掩門，倚闌搔首一消魂。", "花經風雨人方惜，士在江湖道更尊。", "擘浪忽看魚對躍，入雲時見鶴孤鶱。", "向來莘渭今安在，嘆息誰能起九原。"]'),
('99fcf4d2-020e-46b4-a90c-d2bac0471e9c','梨花三首  其一','陸游','宋','宋诗','song-poetry','','[]','開向春殘不恨遲，綠楊窣地最相宜。',32,'全唐诗/poet.song.134000.json','["開向春殘不恨遲，綠楊窣地最相宜。", "征西幕府煎茶地，一幅邊鸞畫折枝。"]'),
('26b918ab-1bf5-457d-a519-68072fc252af','梨花三首  其二','陸游','宋','宋诗','song-poetry','','[]','粉淡香清自一家，未容桃李占年華。',32,'全唐诗/poet.song.134000.json','["粉淡香清自一家，未容桃李占年華。", "常思南鄭清明路，醉袖迎風雪一杈。"]'),
('3acb620b-ebbd-41f7-b358-d44fc11b1fb3','梨花三首  其三','陸游','宋','宋诗','song-poetry','','[]','嘉陵江色嫩如藍，鳳集山光照馬銜。',32,'全唐诗/poet.song.134000.json','["嘉陵江色嫩如藍，鳳集山光照馬銜。", "楊柳梨花迎客處，至今時夢到城南。"]'),
('dea9f109-7235-46e2-adc2-268df2e9a996','農桑四首  其一','陸游','宋','宋诗','song-poetry','','[]','農事初興未苦忙，且支漏屋補頹牆。',32,'全唐诗/poet.song.134000.json','["農事初興未苦忙，且支漏屋補頹牆。", "山歌高下皆成調，野水縱橫自入塘。"]'),
('18bf4d6a-4001-404c-85ba-4abe9d3947c6','農桑四首  其二','陸游','宋','宋诗','song-poetry','','[]','水長人家浸稻秧，蠶生女手摘桑黄。',32,'全唐诗/poet.song.134000.json','["水長人家浸稻秧，蠶生女手摘桑黄。", "差科未起身無事，鄰曲相過日正長。"]'),
('1a0ae57e-e122-4b3a-bec0-8659a7940fab','農桑四首  其三','陸游','宋','宋诗','song-poetry','','[]','采桑蠶婦念蠶饑，陌上匆匆負籠歸。',32,'全唐诗/poet.song.134000.json','["采桑蠶婦念蠶饑，陌上匆匆負籠歸。", "却羨鄰家下湖早，畫船青繖去如飛。"]'),
('9c30e3f0-2b1d-4468-9aee-1bf71e7a6c2b','農桑四首  其四','陸游','宋','宋诗','song-poetry','','[]','蠶如黑蟻稻青鍼，夫婦耕桑各苦心。',32,'全唐诗/poet.song.134000.json','["蠶如黑蟻稻青鍼，夫婦耕桑各苦心。", "但得老親供養足，不羞布袂與蒿簪。"]'),
('ac6a6cab-e77e-4508-ae21-72f078749d3d','自嘲','陸游','宋','宋诗','song-poetry','','[]','野叟身常雜傭保，茀圃荒庭自鋤掃。',96,'全唐诗/poet.song.134000.json','["野叟身常雜傭保，茀圃荒庭自鋤掃。", "小兒耕養堇堇足，大兒游宦垂垂老。", "朝餐未破百甕齏，晚餉猶存兩囷棗。", "舂粳但備翁作糜，儲帛纔堪孫裂褓。", "賢愚元自一王尊，癡鈍寧論萬馮道。", "可憐對客猶自矜，談道能令君絕倒。"]'),
('752f4093-a805-4785-8e37-1a8c7667091d','春晚二首  其一','陸游','宋','宋诗','song-poetry','','[]','寂寞又過桃李時，東園微雨草離離。',64,'全唐诗/poet.song.134000.json','["寂寞又過桃李時，東園微雨草離離。", "破囷食外有餘粟，殘髮白中生黑絲。", "小疾已能忘藥石，餘年寧復問蓍龜。", "飾巾待盡從來事，閉戶燒香更不疑。"]'),
('4d19cae2-a7bb-4f4a-a881-ea76410ae986','春晚二首  其二','陸游','宋','宋诗','song-poetry','','[]','正見山陂草木芽，狂風忽掃萬枝花。',64,'全唐诗/poet.song.134000.json','["正見山陂草木芽，狂風忽掃萬枝花。", "病懷久已忘春事，老眼猶能惜物華。", "枕上有詩頻自改，尊中無酒不妨賒。", "昔人漫道傷幽獨，野鶴分巢即是家。"]'),
('c6d418f3-2895-4bcb-a76c-051fb06f7b98','閉戶','陸游','宋','宋诗','song-poetry','','[]','乞身林下養衰殘，閉戶寧容外物干。',64,'全唐诗/poet.song.134000.json','["乞身林下養衰殘，閉戶寧容外物干。", "正使有爲終淡泊，未能無疾已輕安。", "寸陰息念如年永，丈室端居抵海寬。", "老子爾來深達此，却嫌兒女話團欒。"]'),
('9c6ffba1-8aa4-4e1a-9ec5-77a20c7d48fc','晨起','陸游','宋','宋诗','song-poetry','','[]','初聽高枝鵯鵊鳴，旋聞深井轆轤聲。',64,'全唐诗/poet.song.134000.json','["初聽高枝鵯鵊鳴，旋聞深井轆轤聲。", "烟籠小閣猶疑雨，日射東窗頓作晴。", "古洗注湯供頮濯，春畦摘菜助炰烹。", "老人頹惰雖堪笑，終勝胸中懷不平。"]'),
('2796423f-b78f-4ad1-8452-47db127eabf3','出遊四首  其一','陸游','宋','宋诗','song-poetry','','[]','九日陰薶一日晴，此行處處是丹青。',64,'全唐诗/poet.song.134000.json','["九日陰薶一日晴，此行處處是丹青。", "斷雲零落江郊路，壽木輪囷古驛亭。", "饁婦微行望耕壟，漁歌相和起烟汀。", "拔山意氣今何在，猶有遺祠可乞靈。"]'),
('0737d7a7-c4a8-4287-b764-53ce640a8a58','出遊四首  其二','陸游','宋','宋诗','song-poetry','','[]','近過父老遠尋僧，病起經行力漸增。',64,'全唐诗/poet.song.134000.json','["近過父老遠尋僧，病起經行力漸增。", "織室蹋機鳴軋軋，稻陂潴水筑登登。", "淺深村落時分徑，高下川原自作層。", "薄暮到家還熟睡，隔林鐘鼓報晨興。"]'),
('7b80c69e-1dd1-441b-9572-eab77fc8d87d','出遊四首  其三','陸游','宋','宋诗','song-poetry','','[]','吳地清明未減寒，梨花初動杏花殘。',64,'全唐诗/poet.song.134000.json','["吳地清明未減寒，梨花初動杏花殘。", "平沙漫漫人爭渡，微雨蕭蕭客跨鞍。", "野寺吹螺作春會，山郵糴米具朝餐。", "已開九帙吾何覬，時說金丹强自寬。"]'),
('b8085e1f-9c76-41b3-85f2-958cc263f9f5','出遊四首  其四','陸游','宋','宋诗','song-poetry','','[]','東阡南陌適逢晴，小蹇輕裝短作程。',64,'全唐诗/poet.song.134000.json','["東阡南陌適逢晴，小蹇輕裝短作程。", "白水滿陂秧馬躍，綠陰繞舍緯車鳴。", "過村小婦憑牆看，入寺高人攬裓迎。", "剩倩東風吹柳絮，放翁詩到此時成。"]'),
('132bd286-47d0-4384-8312-4e33e280194a','曳杖','陸游','宋','宋诗','song-poetry','','[]','曳杖寄彷徉，徐行轉曲廊。',48,'全唐诗/poet.song.134000.json','["曳杖寄彷徉，徐行轉曲廊。", "病知貪酒害，老悔愛花狂。", "庭樹雲收影，簾旌雨浥香。", "悠然有佳處，物我兩相忘。"]'),
('b9a0f4f5-8a65-4089-a48a-307c3db28d65','自詠','陸游','宋','宋诗','song-poetry','','[]','曾著杞菊賦，自名桑苧翁。',48,'全唐诗/poet.song.134000.json','["曾著杞菊賦，自名桑苧翁。", "常開羅爵網，不下釣魚筒。", "租稅先期畢，陂塘與眾同。", "士章八十字，世世寫屏風。"]'),
('bae23840-4a54-4997-8ee1-de36f36fdfd8','雜興五首  其一','陸游','宋','宋诗','song-poetry','','[]','謀生在衣食，不仕當作農。',72,'全唐诗/poet.song.134000.json','["謀生在衣食，不仕當作農。", "識字讀農書，豈不賢雕蟲。", "婦當娶農家，養蠶事炊舂。", "晨耕候春扈，夜織驚秋蛩。", "畦蔬勝肉羹，社酒如粥醲。", "毋爲慕朝幘，諂笑求見容。"]'),
('1e8b4279-1085-48de-8ed0-d73832f0ab43','雜興五首  其二','陸游','宋','宋诗','song-poetry','','[]','家世本臞儒，自奉至儉薄。',72,'全唐诗/poet.song.134000.json','["家世本臞儒，自奉至儉薄。", "肉食固難期，間亦闕鹽酪。", "賓朋飯芋豆，時節羹藜藿。", "偶然設雞豚，變色相與作。", "家居常守此，自計豈不樂。", "蔬園畏蹴蹋，切勿思大嚼。"]'),
('8392b0a6-06b9-44c6-9948-62ee021b26a8','雜興五首  其三','陸游','宋','宋诗','song-poetry','','[]','家本徙壽春，遭亂建炎初。',72,'全唐诗/poet.song.134000.json','["家本徙壽春，遭亂建炎初。", "南來避狂寇，乃復遇强胡。", "于時髧兩髦，幾不保頭顱。", "亂定不敢歸，三載東陽居。", "人事固難料，今乃八十餘。", "努力未死間，讀我先人書。"]'),
('8e97e8e7-55ef-4ef9-9dac-800b62554d44','雜興五首  其四','陸游','宋','宋诗','song-poetry','','[]','讀詩讀七月，治書治無逸。',72,'全唐诗/poet.song.134000.json','["讀詩讀七月，治書治無逸。", "王業與農功，事異理則一。", "此外復何爲，齊民有遺術。", "一飽不啻足，切勿爲利訹。", "大屋起道傍，百鬼闞其室。", "曷不觀陸翁，食菜開九秩。"]'),
('c89b16ad-e1da-48fa-b7e7-c84c775834da','雜興五首  其五','陸游','宋','宋诗','song-poetry','','[]','三吳氣候異，開歲固多雨。',72,'全唐诗/poet.song.134000.json','["三吳氣候異，開歲固多雨。", "今年已暮春，霽日僅可數。", "寒氣薄腠理，沉痛結心膂。", "遣奴買藥物，日夜事炮煮。", "端居情懷惡，欲出泥淖阻。", "安得平生歡，駕言問良苦。"]'),
('b623bb4e-849e-4c7e-879d-4454074bed05','雜感六首  其一','陸游','宋','宋诗','song-poetry','','[]','病卧踐衰境，躬耕歸故園。',48,'全唐诗/poet.song.134000.json','["病卧踐衰境，躬耕歸故園。", "怒蛙號廢沼，妖鵩嘯荒村。", "里巷魚餐薄，坊場黍酒渾。", "相逢欲話舊，意極轉忘言。"]'),
('9c62f9bf-4bbb-41fc-90c8-b4a6f956d586','雜感六首  其二','陸游','宋','宋诗','song-poetry','','[]','道進身垂老，方靈病已侵。',48,'全唐诗/poet.song.134000.json','["道進身垂老，方靈病已侵。", "知難逃死籍，猶得遂歸心。", "星斗開孤劍，塵埃拂素琴。", "妄庸常衮衮，誰與論幽深。"]'),
('6066de0b-fcdd-4e4e-bad2-02e37f98e454','雜感六首  其三','陸游','宋','宋诗','song-poetry','','[]','雨霽花無幾，愁多酒不支。',48,'全唐诗/poet.song.134000.json','["雨霽花無幾，愁多酒不支。", "凄凉數聲笛，零亂一枰棋。", "蹈海言猶在，移山志未衰。", "何人知壯士，擊筑有餘悲。"]'),
('78ba5075-c496-4d89-95aa-d68c374ee14d','雜感六首  其四','陸游','宋','宋诗','song-poetry','','[]','草徑纔容步，茅廬僅庇床。',48,'全唐诗/poet.song.134000.json','["草徑纔容步，茅廬僅庇床。", "原貧道尊顯，回夭死芬芳。", "弦誦喧清曉，鉏耰滿夕陽。", "此風能不墜，韋布亦何傷。"]'),
('b6727cac-cc8b-45a3-829d-016b82e29439','雜感六首  其五','陸游','宋','宋诗','song-poetry','','[]','早仕讒銷骨，遲歸悔噬臍。',48,'全唐诗/poet.song.134000.json','["早仕讒銷骨，遲歸悔噬臍。", "短衣猶掩脛，窮巷固多泥。", "婢喜蠶三幼，奴貪雨一犁。", "衡茅明我眼，刮膜謝金篦。"]'),
('d6a04ee7-42e1-4fa6-9dc5-d08066da80e8','雜感六首  其六','陸游','宋','宋诗','song-poetry','','[]','春晚晴還雨，村深醉復醒。',48,'全唐诗/poet.song.134000.json','["春晚晴還雨，村深醉復醒。", "溪添半篙綠，山可一窗青。", "藥品隨長鑱，花名記小屏。", "閑身幸無事，吟嘯送餘齡。"]'),
('4fb03c6d-605e-486c-a11e-5f6a6b090b8a','兩麞','陸游','宋','宋诗','song-poetry','','[]','吾園畜兩麞，善驚未易馴。',72,'全唐诗/poet.song.134000.json','["吾園畜兩麞，善驚未易馴。", "及今纔幾時，弭耳常依人。", "饑食園中草，渴飲溝澗濱。", "時時輟餘糧，亦未耗吾囷。", "吏或無佳政，盜賊起齊民。", "孰能撫以德，坐還三代醇。"]'),
('ba5e616b-8268-4b05-803c-7a14d85ee91e','書感','陸游','宋','宋诗','song-poetry','','[]','疋馬曾爲塞上遊，東歸幾見剡川秋。',64,'全唐诗/poet.song.134000.json','["疋馬曾爲塞上遊，東歸幾見剡川秋。", "故城廢市古今嘆，斷角殘鐘朝暮愁。", "尺寸無功真碌碌，耄期未死轉悠悠。", "阿奴尚喜强人意，三日於菟氣食牛。"]'),
('695e5d3e-a021-45a7-b3fc-4642fbfea7be','書意','陸游','宋','宋诗','song-poetry','','[]','萬事馬牛風，蕭然破屋中。',48,'全唐诗/poet.song.134000.json','["萬事馬牛風，蕭然破屋中。", "忍貧增力量，耐辱見神通。", "道進天魔散，心安客疾空。", "微言施魚鳥，一一脫池籠。"]'),
('092fb48c-f4e1-4d68-9f2b-0c162bd2f4cb','讀唐書','陸游','宋','宋诗','song-poetry','','[]','力行可使金如土，篤好能徠馬若龍。',32,'全唐诗/poet.song.134000.json','["力行可使金如土，篤好能徠馬若龍。", "斗米三錢本常事，風雲千載自難逢。"]'),
('fae3e8bd-e8a8-45b2-ae53-79f84fa2340d','雜題四首  其一','陸游','宋','宋诗','song-poetry','','[]','貧中得味如餐蔗，語下明心似到鄉。',32,'全唐诗/poet.song.134000.json','["貧中得味如餐蔗，語下明心似到鄉。", "對客欲談渾忘却，笑呼童子替燒香。"]'),
('cd179b53-f676-43bc-9435-a9d9ebd63c77','雜題四首  其二','陸游','宋','宋诗','song-poetry','','[]','半飽半饑窮境界，知晴知雨病形骸。',32,'全唐诗/poet.song.134000.json','["半飽半饑窮境界，知晴知雨病形骸。", "軒昂似鶴那求料，枯槁如僧不赴齋。"]'),
('6e34c7e6-679d-446e-a8d6-7c1e33ca01d3','雜題四首  其三','陸游','宋','宋诗','song-poetry','','[]','傳家只要存書種，學道當知養聖胎。',32,'全唐诗/poet.song.134000.json','["傳家只要存書種，學道當知養聖胎。", "寧使終身遷比景，莫令一物汙靈臺。"]'),
('21a5e2bb-87b7-4d59-bc8b-e837d14858f0','雜題四首  其四','陸游','宋','宋诗','song-poetry','','[]','大兒都門久栖栖，小兒調官今復西。',32,'全唐诗/poet.song.134000.json','["大兒都門久栖栖，小兒調官今復西。", "鄰家父子我所羨，泥水沒膝扶耕犁。"]'),
('64bf6371-d411-406c-ad87-3fa790e7e82c','栽牡丹','陸游','宋','宋诗','song-poetry','','[]','携鋤庭下斸蒼苔，墨紫鞓紅手自栽。',32,'全唐诗/poet.song.134000.json','["携鋤庭下斸蒼苔，墨紫鞓紅手自栽。", "老子龍鍾逾八十，死前猶見幾回開。"]'),
('4585b9d4-454c-4625-a97b-6b9f5de9c7c7','夜聞姑惡','陸游','宋','宋诗','song-poetry','','[]','學道當於萬事輕，可憐力淺未忘情。',32,'全唐诗/poet.song.134000.json','["學道當於萬事輕，可憐力淺未忘情。", "孤愁忽起不可耐，風雨溪頭姑惡聲。"]'),
('6b85a54c-125f-4128-a2de-270a229f1b8d','哭開孫','陸游','宋','宋诗','song-poetry','','[]','學步漸扶床，乘車已駕羊。',48,'全唐诗/poet.song.134000.json','["學步漸扶床，乘車已駕羊。", "虛稱砌臺使，不遇玉函方。", "杳杳天難問，茫茫夜正長。", "寂寥誰伴汝，蕭寺閉空房。"]'),
('b8ae6983-eda4-4e90-ad33-dd9ee7f85fb9','晚春東園作二首  其一','陸游','宋','宋诗','song-poetry','','[]','雨餘木葉綠成陰，一日身閑直萬金。',32,'全唐诗/poet.song.134000.json','["雨餘木葉綠成陰，一日身閑直萬金。", "習氣自嫌除未盡，鳥啼花落尚關心。"]'),
('94bb2976-33d7-472c-9be7-74f45536406c','晚春東園作二首  其二','陸游','宋','宋诗','song-poetry','','[]','女郎花開春事闌，王孫草長思婦嘆。',32,'全唐诗/poet.song.134000.json','["女郎花開春事闌，王孫草長思婦嘆。", "蜂釀蜜脾猶未熟，雨催梅頰已微丹。"]'),
('b7fb489f-f06c-4197-86be-26dc5969b9b3','禽聲','陸游','宋','宋诗','song-poetry','','[]','布穀布穀天未明，架犁架犁人起耕。',32,'全唐诗/poet.song.134000.json','["布穀布穀天未明，架犁架犁人起耕。", "宦途不似農家樂，東作西成過此生。"]'),
('c8e00b77-d836-4770-925b-06019f964bc7','秦皇酒甕下垂釣偶賦','陸游','宋','宋诗','song-poetry','','[]','酒甕山邊古釣磯，沙鷗與我共斜暉。',64,'全唐诗/poet.song.134000.json','["酒甕山邊古釣磯，沙鷗與我共斜暉。", "目前雖有小得喪，天下豈無公是非。", "滄海橫流何日定，古人復起欲誰歸。", "道邊醉倒君奚憾，豈失風塵一布衣。"]');
